{
  "name": "GasPro Field Dashboard",
  "description": "A TV-optimized gas production monitoring dashboard and admin portal for real-time field-wise analytics and data management."
}

export interface ProductionRecord {
  id: string;
  field: string;
  amount: number; // in MCF (Million Cubic Feet)
  date: string;
}

export interface FieldInfo {
  id: string;
  name: string;
  location: string;
  status: 'Active' | 'Maintenance' | 'Standby';
}

export type ViewType = 'dashboard' | 'admin';

import { GoogleGenAI } from "@google/genai";
import { ProductionRecord } from "../types";

export const getAIInsights = async (data: ProductionRecord[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const dataSummary = data.map(r => `${r.date}: ${r.field} produced ${r.amount} MCF`).join('\n');

  const prompt = `
    Analyze this gas production data for our MD:
    ${dataSummary}

    Provide a concise executive summary for display on a Google TV.
    Include:
    1. Overall trend.
    2. Best performing field.
    3. Any anomalies or maintenance alerts.
    Keep it professional and readable on a large screen.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Unable to generate insights at this time.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error connecting to AI analyst.";
  }
};

import React from 'react';
import { ProductionRecord } from '../types';

interface Props {
  data: ProductionRecord[];
}

const ProductionTable: React.FC<Props> = ({ data }) => {
  // Sort by date descending
  const sortedData = [...data].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  return (
    <div className="overflow-x-auto rounded-xl border border-slate-700 bg-slate-900/50">
      <table className="w-full text-left border-collapse">
        <thead>
          <tr className="bg-slate-800/80 text-slate-400 text-xs uppercase tracking-wider">
            <th className="px-6 py-4 font-semibold">Date</th>
            <th className="px-6 py-4 font-semibold">Field Name</th>
            <th className="px-6 py-4 font-semibold text-right">Production (MCF)</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-800">
          {sortedData.map((record) => (
            <tr key={record.id} className="hover:bg-slate-800/40 transition-colors">
              <td className="px-6 py-4 font-medium text-slate-300">{record.date}</td>
              <td className="px-6 py-4 text-slate-100">{record.field}</td>
              <td className="px-6 py-4 text-right font-mono text-emerald-400 font-bold">
                {record.amount.toLocaleString()}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ProductionTable;

import React from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend, LineChart, Line, AreaChart, Area
} from 'recharts';
import { ProductionRecord } from '../types';

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

interface ChartProps {
  data: ProductionRecord[];
}

export const FieldDistributionChart: React.FC<ChartProps> = ({ data }) => {
  // Aggregating latest production by field
  const latestDate = [...new Set(data.map(d => d.date))].sort().pop();
  const latestData = data.filter(d => d.date === latestDate);

  const chartData = latestData.map(d => ({
    name: d.field,
    value: d.amount
  }));

  return (
    <div className="h-[400px] w-full">
      <h3 className="text-xl font-bold mb-4 text-slate-100">Today's Distribution</h3>
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={chartData}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={120}
            paddingAngle={5}
            dataKey="value"
            label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
          >
            {chartData.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
            ))}
          </Pie>
          <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }} />
          <Legend />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

export const HistoricalTrendChart: React.FC<ChartProps> = ({ data }) => {
  // Pivot data for line chart
  const dates = [...new Set(data.map(d => d.date))].sort();
  const fields = [...new Set(data.map(d => d.field))];

  const chartData = dates.map(date => {
    const entry: any = { date };
    fields.forEach(field => {
      const record = data.find(r => r.date === date && r.field === field);
      entry[field] = record ? record.amount : 0;
    });
    return entry;
  });

  return (
    <div className="h-[400px] w-full">
      <h3 className="text-xl font-bold mb-4 text-slate-100">Production Trend (Last 7 Days)</h3>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={chartData}>
          <defs>
            {fields.map((f, i) => (
              <linearGradient key={`grad-${f}`} id={`color-${i}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={COLORS[i % COLORS.length]} stopOpacity={0.3}/>
                <stop offset="95%" stopColor={COLORS[i % COLORS.length]} stopOpacity={0}/>
              </linearGradient>
            ))}
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
          <XAxis dataKey="date" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
          <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(v) => `${v} MCF`} />
          <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }} />
          <Legend verticalAlign="top" height={36}/>
          {fields.map((field, index) => (
            <Area
              key={field}
              type="monotone"
              dataKey={field}
              stroke={COLORS[index % COLORS.length]}
              fillOpacity={1}
              fill={`url(#color-${index})`}
              strokeWidth={3}
            />
          ))}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export const FieldComparisonBar: React.FC<ChartProps> = ({ data }) => {
  const latestDate = [...new Set(data.map(d => d.date))].sort().pop();
  const latestData = data.filter(d => d.date === latestDate);

  return (
    <div className="h-[400px] w-full">
      <h3 className="text-xl font-bold mb-4 text-slate-100">Production vs Target</h3>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={latestData}>
          <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
          <XAxis dataKey="field" stroke="#94a3b8" fontSize={12} />
          <YAxis stroke="#94a3b8" fontSize={12} />
          <Tooltip 
            cursor={{ fill: '#334155', opacity: 0.4 }}
            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }} 
          />
          <Bar dataKey="amount" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState } from 'react';
import { FIELDS } from '../constants';
import { ProductionRecord } from '../types';
import { PlusCircle, Trash2, Database, AlertCircle } from 'lucide-react';

interface Props {
  data: ProductionRecord[];
  onAdd: (record: ProductionRecord) => void;
  onDelete: (id: string) => void;
}

const AdminPanel: React.FC<Props> = ({ data, onAdd, onDelete }) => {
  const [field, setField] = useState(FIELDS[0].name);
  const [amount, setAmount] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || isNaN(Number(amount))) return;

    const newRecord: ProductionRecord = {
      id: Math.random().toString(36).substr(2, 9),
      field,
      amount: Number(amount),
      date,
    };

    onAdd(newRecord);
    setAmount('');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Entry Form */}
      <div className="lg:col-span-1">
        <div className="bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-700">
          <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
            <Database className="text-blue-500" /> New Entry
          </h2>
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-2">Gas Field</label>
              <select 
                value={field}
                onChange={(e) => setField(e.target.value)}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {FIELDS.map(f => <option key={f.id} value={f.name}>{f.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-2">Production Amount (MCF)</label>
              <input 
                type="number"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                placeholder="e.g. 500"
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-blue-500 outline-none"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-2">Production Date</label>
              <input 
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-blue-500 outline-none"
                required
              />
            </div>
            <button 
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-lg transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-900/20"
            >
              <PlusCircle size={20} /> Add Record
            </button>
          </form>
        </div>
      </div>

      {/* Recent Records List */}
      <div className="lg:col-span-2">
        <div className="bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-700 h-full overflow-hidden flex flex-col">
          <h2 className="text-2xl font-bold mb-6">Database Records</h2>
          <div className="overflow-y-auto flex-1 pr-2">
            <div className="space-y-3">
              {[...data].reverse().map(record => (
                <div key={record.id} className="flex items-center justify-between p-4 bg-slate-900 rounded-xl border border-slate-700/50 group">
                  <div>
                    <div className="font-bold text-slate-100">{record.field}</div>
                    <div className="text-sm text-slate-400 flex items-center gap-3">
                      <span>{record.date}</span>
                      <span className="w-1 h-1 bg-slate-600 rounded-full"></span>
                      <span className="text-emerald-400 font-mono">{record.amount} MCF</span>
                    </div>
                  </div>
                  <button 
                    onClick={() => onDelete(record.id)}
                    className="p-2 text-slate-500 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              ))}
              {data.length === 0 && (
                <div className="text-center py-20 text-slate-500 flex flex-col items-center gap-4">
                  <AlertCircle size={48} className="opacity-20" />
                  <p>No records found in database</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { ProductionRecord } from '../types';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts';
import ProductionTable from './ProductionTable';
import { getAIInsights } from '../services/geminiService';
import { Sparkles, TrendingUp, Activity, BarChart3, Clock } from 'lucide-react';

interface Props {
  data: ProductionRecord[];
}

const Dashboard: React.FC<Props> = ({ data }) => {
  const [insights, setInsights] = useState<string>('Generating AI executive summary...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  useEffect(() => {
    const fetchInsights = async () => {
      setLoadingInsights(true);
      const text = await getAIInsights(data);
      setInsights(text);
      setLoadingInsights(false);
    };
    fetchInsights();
  }, [data]);

  const totalProduction = data
    .filter(d => d.date === [...new Set(data.map(r => r.date))].sort().pop())
    .reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="space-y-8 pb-12">
      {/* Top Stats - High Impact for TV */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-slate-800/80 p-6 rounded-3xl border border-slate-700 shadow-xl backdrop-blur-sm">
          <div className="flex items-center gap-4 mb-2">
            <div className="p-3 bg-blue-500/20 rounded-2xl">
              <Activity className="text-blue-500" />
            </div>
            <span className="text-slate-400 font-medium">Daily Production</span>
          </div>
          <div className="text-5xl font-extrabold text-white">
            {totalProduction.toLocaleString()} <span className="text-xl text-slate-500 font-medium uppercase">MCF</span>
          </div>
          <div className="mt-2 text-emerald-400 text-sm flex items-center gap-1 font-semibold">
            <TrendingUp size={16} /> +4.2% from yesterday
          </div>
        </div>

        <div className="bg-slate-800/80 p-6 rounded-3xl border border-slate-700 shadow-xl backdrop-blur-sm lg:col-span-3 overflow-hidden relative">
          <div className="flex items-center gap-4 mb-2">
            <div className="p-3 bg-purple-500/20 rounded-2xl">
              <Sparkles className="text-purple-500" />
            </div>
            <span className="text-slate-400 font-medium">AI Executive Summary</span>
          </div>
          <div className={`text-lg text-slate-200 leading-relaxed max-w-4xl transition-opacity duration-500 ${loadingInsights ? 'opacity-50' : 'opacity-100'}`}>
            {insights}
          </div>
          <div className="absolute top-0 right-0 p-8 opacity-10">
            <Sparkles size={120} />
          </div>
        </div>
      </div>

      {/* Main Charts Row */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
        <div className="bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <HistoricalTrendChart data={data} />
        </div>
        <div className="bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <FieldComparisonBar data={data} />
        </div>
      </div>

      {/* Bottom Row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
         <div className="lg:col-span-1 bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <FieldDistributionChart data={data} />
        </div>
        <div className="lg:col-span-2 bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-2xl font-bold text-white flex items-center gap-3">
              <Clock className="text-slate-400" /> Historical Log
            </h3>
            <span className="bg-slate-700 px-4 py-1 rounded-full text-xs font-bold text-slate-300">MCF Metrics</span>
          </div>
          <ProductionTable data={data} />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { ProductionRecord, ViewType } from './types';
import { INITIAL_MOCK_DATA } from './constants';
import Dashboard from './components/Dashboard';
import AdminPanel from './components/AdminPanel';
import { Monitor, Settings, LayoutDashboard, Database, Fuel } from 'lucide-react';

const App: React.FC = () => {
  const [data, setData] = useState<ProductionRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');

  useEffect(() => {
    const saved = localStorage.getItem('gaspro_production_data');
    if (saved) {
      setData(JSON.parse(saved));
    } else {
      setData(INITIAL_MOCK_DATA);
    }
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      localStorage.setItem('gaspro_production_data', JSON.stringify(data));
    }
  }, [data]);

  const handleAddRecord = (record: ProductionRecord) => {
    setData(prev => [...prev, record]);
  };

  const handleDeleteRecord = (id: string) => {
    setData(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Dynamic Header */}
      <header className="sticky top-0 z-50 bg-slate-900/80 border-b border-slate-800 backdrop-blur-md px-8 py-5 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2 rounded-xl shadow-lg shadow-emerald-900/30">
            <Fuel className="text-white" size={32} />
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tight text-white uppercase">GasPro <span className="text-emerald-500">Analytics</span></h1>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">MD Dashboard Suite v3.4</p>
          </div>
        </div>

        <nav className="flex items-center bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
          <button 
            onClick={() => setView('dashboard')}
            className={`px-8 py-3 rounded-xl flex items-center gap-3 font-bold transition-all ${view === 'dashboard' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
          >
            <LayoutDashboard size={20} /> Dashboard
          </button>
          <button 
            onClick={() => setView('admin')}
            className={`px-8 py-3 rounded-xl flex items-center gap-3 font-bold transition-all ${view === 'admin' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
          >
            <Database size={20} /> Admin Panel
          </button>
        </nav>

        <div className="hidden lg:flex items-center gap-4">
          <div className="text-right">
            <div className="text-sm font-bold text-slate-100">Regional HQ</div>
            <div className="text-xs text-emerald-500 animate-pulse flex items-center gap-1 justify-end">
              <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span> Live Updates
            </div>
          </div>
          <button className="p-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-400 transition-colors">
            <Settings size={24} />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 px-8 py-10 max-w-[2000px] mx-auto w-full">
        {view === 'dashboard' ? (
          <Dashboard data={data} />
        ) : (
          <AdminPanel data={data} onAdd={handleAddRecord} onDelete={handleDeleteRecord} />
        )}
      </main>

      {/* Footer / Status Bar - Google TV style */}
      <footer className="bg-slate-900 border-t border-slate-800 p-6 flex justify-between items-center text-slate-500 text-sm font-medium">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <Monitor size={16} /> Google TV Optimization Active
          </div>
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 bg-emerald-500 rounded-full"></div> All Systems Operational
          </div>
        </div>
        <div>
          &copy; {new Date().getFullYear()} Gas Production Ltd. Digital Twin Services
        </div>
      </footer>
    </div>
  );
};

export default App;

