import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ProductionRecord } from "../types";

export const getAIInsights = async (data: ProductionRecord[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Provide only the most recent context to keep prompt efficient
  const dataSummary = data.map(r => `${r.date}: ${r.field} produced ${r.amount} MCF`).join('\n');

  const prompt = `
    Analyze this gas production data for our Managing Director (MD):
    ${dataSummary}

    Context: This will be displayed on a Google TV in the MD's office.
    There is ALREADY a table showing the latest numbers right next to this text, so DO NOT list the raw numbers for every field unless they are critical for context.

    Focus your summary on:
    1. Overall growth or decline trend.
    2. Strategic insights (e.g., 'Alpha West is carrying the load while Charlie Deep is in maintenance').
    3. Forward-looking observation (one sentence).

    Keep it high-level, executive, and readable (max 3 short paragraphs). Avoid excessive jargon.
  `;

  try {
    // Fix: Explicitly type the response as GenerateContentResponse
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    // Fix: Use .text getter property directly
    return response.text || "Insight generation paused. Please check telemetry.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Intelligence offline. Manual review of the production logs is recommended.";
  }
};

