import React, { useState, useEffect } from 'react';
import { ProductionRecord } from '../types';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts';
import ProductionTable from './ProductionTable';
import { getAIInsights } from '../services/geminiService';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList } from 'lucide-react';

interface Props {
  data: ProductionRecord[];
}

const Dashboard: React.FC<Props> = ({ data }) => {
  const [insights, setInsights] = useState<string>('Analyzing production trends...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  // Fix: Explicitly type the Set to string to avoid unknown inference
  const latestDate = Array.from(new Set<string>(data.map(r => r.date))).sort().pop();
  const latestRecords = data.filter(d => d.date === latestDate);
  const totalProduction = latestRecords.reduce((acc, curr) => acc + curr.amount, 0);

  useEffect(() => {
    const fetchInsights = async () => {
      if (data.length === 0) return;
      setLoadingInsights(true);
      const text = await getAIInsights(data);
      setInsights(text);
      setLoadingInsights(false);
    };
    fetchInsights();
  }, [data]);

  return (
    <div className="space-y-8 pb-12">
      {/* Top Section: Daily Total & Executive AI Insight with Table */}
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Left: Headline Metric */}
        <div className="bg-slate-800/80 p-8 rounded-3xl border border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-center">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-blue-500/20 rounded-2xl text-blue-400">
              <Activity size={28} />
            </div>
            <span className="text-slate-400 font-bold uppercase tracking-wider text-sm">Today's Output</span>
          </div>
          <div className="text-6xl font-black text-white mb-2 tracking-tighter">
            {totalProduction.toLocaleString()}
          </div>
          <div className="text-xl text-slate-500 font-bold uppercase mb-4">Million Cubic Feet</div>
          <div className="mt-auto pt-4 border-t border-slate-700/50 text-emerald-400 text-lg flex items-center gap-2 font-bold">
            <TrendingUp size={20} /> +4.2% VS PREV
          </div>
        </div>

        {/* Right: AI Executive Summary with Integrated Latest Data Table */}
        <div className="bg-slate-800/80 rounded-3xl border border-slate-700 shadow-xl backdrop-blur-sm lg:col-span-3 flex flex-col lg:flex-row overflow-hidden">
          {/* Narrative Analysis */}
          <div className="flex-1 p-8 relative border-b lg:border-b-0 lg:border-r border-slate-700/50">
            <div className="flex items-center gap-4 mb-6">
              <div className="p-2.5 bg-purple-500/20 rounded-xl text-purple-400">
                <Sparkles size={24} />
              </div>
              <h2 className="text-xl font-bold text-white uppercase tracking-tight">AI Executive Summary</h2>
            </div>
            <div className={`text-xl text-slate-200 leading-relaxed font-medium transition-opacity duration-700 ${loadingInsights ? 'opacity-40 animate-pulse' : 'opacity-100'}`}>
              {insights}
            </div>
            <div className="absolute -bottom-10 -right-10 opacity-5 text-purple-200">
              <Sparkles size={180} />
            </div>
          </div>

          {/* Compact Latest Data Table for MD */}
          <div className="w-full lg:w-96 bg-slate-900/40 p-8">
            <div className="flex items-center gap-3 mb-6">
              <LayoutList size={20} className="text-emerald-500" />
              <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Live Status - {latestDate}</h3>
            </div>
            <div className="space-y-4">
              {latestRecords.map((record) => (
                <div key={record.field} className="flex items-center justify-between group">
                  <div className="text-slate-300 font-bold text-lg group-hover:text-white transition-colors">{record.field}</div>
                  <div className="text-right">
                    <div className="text-emerald-400 font-black text-xl font-mono leading-none">
                      {record.amount}
                    </div>
                    <div className="text-[10px] text-slate-500 font-bold uppercase">MCF / Day</div>
                  </div>
                </div>
              ))}
              {latestRecords.length === 0 && (
                <div className="text-slate-500 italic text-center py-4">No data for today.</div>
              )}
            </div>
            <div className="mt-8 pt-6 border-t border-slate-700/50">
              <div className="flex justify-between items-center text-xs font-bold uppercase tracking-widest text-slate-500">
                <span>Field Efficiency</span>
                <span className="text-emerald-500">98.2%</span>
              </div>
              <div className="w-full h-1.5 bg-slate-700 rounded-full mt-2 overflow-hidden">
                <div className="h-full bg-emerald-500 w-[98%] shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Primary Analytics Grid */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
        <div className="bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <HistoricalTrendChart data={data} />
        </div>
        <div className="bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <FieldComparisonBar data={data} />
        </div>
      </div>

      {/* Detail Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
         <div className="lg:col-span-1 bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <FieldDistributionChart data={data} />
