export const HistoricalTrendChart: React.FC<ChartProps> = ({ data }) => {
  // Pivot data for line chart
  // Fix: Explicitly type dates and fields as string arrays using Array.from and Set<string> to avoid 'unknown' inference which causes errors on lines 55 and 56
  const dates: string[] = Array.from(new Set<string>(data.map(d => d.date))).sort();
  const fields: string[] = Array.from(new Set<string>(data.map(d => d.field)));

  const chartData = dates.map(date => {
    const entry: any = { date };
    fields.forEach(field => {
      const record = data.find(r => r.date === date && r.field === field);
      entry[field] = record ? record.amount : 0;
    });
    return entry;
  });

  return (
    <div className="h-[400px] w-full">
      <h3 className="text-xl font-bold mb-4 text-slate-100">Production Trend (Last 7 Days)</h3>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={chartData}>
          <defs>
            {fields.map((f, i) => (
              <linearGradient key={`grad-${f}`} id={`color-${i}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={COLORS[i % COLORS.length]} stopOpacity={0.3}/>
                <stop offset="95%" stopColor={COLORS[i % COLORS.length]} stopOpacity={0}/>
              </linearGradient>
            ))}
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
          <XAxis dataKey="date" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
          <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(v) => `${v} MCF`} />
          <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }} />
          <Legend verticalAlign="top" height={36}/>
          {fields.map((field, index) => (
            <Area
              key={field}
              type="monotone"
              dataKey={field}
              stroke={COLORS[index % COLORS.length]}
              fillOpacity={1}
              fill={`url(#color-${index})`}
              strokeWidth={3}
            />
          ))}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

