import React, { useState, useEffect } from 'react';
import { ProductionRecord, ViewType } from './types';
import { INITIAL_MOCK_DATA, ALLOWED_ADMIN_IPS } from './constants';
import Dashboard from './components/Dashboard';
import AdminPanel from './components/AdminPanel';
import { Monitor, Settings, LayoutDashboard, Database, Fuel, ShieldCheck, ShieldAlert, Lock } from 'lucide-react';

const App: React.FC = () => {
  const [data, setData] = useState<ProductionRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');
  const [userIp, setUserIp] = useState<string | null>(null);
  const [isIpChecking, setIsIpChecking] = useState(true);
  const [isAdminAllowed, setIsAdminAllowed] = useState(false);

  useEffect(() => {
    // 1. Fetch Production Data
    const saved = localStorage.getItem('gaspro_production_data');
    if (saved) {
      setData(JSON.parse(saved));
    } else {
      setData(INITIAL_MOCK_DATA);
    }

    // 2. IP Detection Logic
    const checkIpAccess = async () => {
      setIsIpChecking(true);
      try {
        const response = await fetch('https://api.ipify.org?format=json');
        const result = await response.json();
        const currentIp = result.ip;
        setUserIp(currentIp);

        // In local development or if user is on allowed list
        const isAllowed = ALLOWED_ADMIN_IPS.includes(currentIp) || 
                          window.location.hostname === 'localhost' || 
                          window.location.hostname === '127.0.0.1';

        setIsAdminAllowed(isAllowed);
      } catch (error) {
        console.error("IP Check Failed:", error);
        // Default to restricted if check fails
        setIsAdminAllowed(false);
      } finally {
        setIsIpChecking(false);
      }
    };

    checkIpAccess();
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      localStorage.setItem('gaspro_production_data', JSON.stringify(data));
    }
  }, [data]);

  const handleAddRecord = (record: ProductionRecord) => {
    setData(prev => [...prev, record]);
  };

  const handleDeleteRecord = (id: string) => {
    setData(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Dynamic Header */}
      <header className="sticky top-0 z-50 bg-slate-900/80 border-b border-slate-800 backdrop-blur-md px-8 py-5 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2 rounded-xl shadow-lg shadow-emerald-900/30">
            <Fuel className="text-white" size={32} />
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tight text-white uppercase">GasPro <span className="text-emerald-500">Analytics</span></h1>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">MD Dashboard Suite v3.4</p>
          </div>
        </div>

        <nav className="flex items-center bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
          <button 
            onClick={() => setView('dashboard')}
            className={`px-8 py-3 rounded-xl flex items-center gap-3 font-bold transition-all ${view === 'dashboard' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
          >
            <LayoutDashboard size={20} /> Dashboard
          </button>

          {/* Conditional Admin Tab based on IP Check */}
          {isAdminAllowed && (
            <button 
              onClick={() => setView('admin')}
              className={`px-8 py-3 rounded-xl flex items-center gap-3 font-bold transition-all ${view === 'admin' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              <Database size={20} /> Admin Panel
            </button>
          )}

          {isIpChecking && (
            <div className="px-8 py-3 text-slate-500 flex items-center gap-2 animate-pulse">
              <div className="w-2 h-2 bg-slate-600 rounded-full"></div>
              <span className="text-xs font-bold uppercase">Verifying...</span>
            </div>
          )}
        </nav>

        <div className="hidden lg:flex items-center gap-6">
          <div className="flex flex-col items-end">
            <div className="flex items-center gap-2">
              <span className="text-sm font-bold text-slate-100">Regional HQ</span>
              {isAdminAllowed ? (
                <ShieldCheck size={16} className="text-emerald-500" title="Secure Link Verified" />
              ) : (
                <ShieldAlert size={16} className="text-amber-500" title="Public View Access" />
              )}
            </div>
            <div className="text-[10px] text-slate-500 font-mono tracking-tight">
              IP: {userIp || '0.0.0.0'}
            </div>
          </div>
          <button className="p-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-400 transition-colors">
            <Settings size={24} />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 px-8 py-10 max-w-[2000px] mx-auto w-full">
        {view === 'dashboard' ? (
          <Dashboard data={data} />
        ) : isAdminAllowed ? (
          <AdminPanel data={data} onAdd={handleAddRecord} onDelete={handleDeleteRecord} />
        ) : (
          <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-6">
            <div className="p-8 bg-slate-800/50 rounded-full border border-slate-700/50 shadow-2xl">
              <Lock size={120} className="text-slate-600" />
            </div>
            <div className="max-w-md">
              <h2 className="text-3xl font-black text-white mb-4">RESTRICTED AREA</h2>
              <p className="text-slate-400 font-medium">
                Your current network location is not authorized for administrative access. Please contact the MD Office IT team for IP whitelisting.
              </p>
              <button 
                onClick={() => setView('dashboard')}
                className="mt-8 px-10 py-4 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700 transition-colors"
              >
                Return to Dashboard
              </button>
            </div>
          </div>
        )}
      </main>

      {/* Footer / Status Bar - Google TV style */}
      <footer className="bg-slate-900 border-t border-slate-800 p-6 flex justify-between items-center text-slate-500 text-sm font-medium">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <Monitor size={16} /> Google TV Optimization Active
          </div>
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 bg-emerald-500 rounded-full"></div> All Systems Operational
          </div>
          {isAdminAllowed && (
            <div className="flex items-center gap-2 text-emerald-500/80 font-bold uppercase text-[10px] tracking-widest border border-emerald-500/20 px-2 py-0.5 rounded">
              Verified Office Link
            </div>
          )}
        </div>
        <div>
          &copy; {new Date().getFullYear()} Gas Production Ltd. Digital Twin Services
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ProductionRecord } from '../types';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts';
import ProductionTable from './ProductionTable';
import { getAIInsights } from '../services/geminiService';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList } from 'lucide-react';

interface Props {
  data: ProductionRecord[];
}

const Dashboard: React.FC<Props> = ({ data }) => {
  const [insights, setInsights] = useState<string>('Analyzing production trends...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  // Fix: Explicitly type the Set to string to avoid unknown inference
  const latestDate = Array.from(new Set<string>(data.map(r => r.date))).sort().pop();
  const latestRecords = data.filter(d => d.date === latestDate);
  const totalProduction = latestRecords.reduce((acc, curr) => acc + curr.amount, 0);

  useEffect(() => {
    const fetchInsights = async () => {
      if (data.length === 0) return;
      setLoadingInsights(true);
      const text = await getAIInsights(data);
      setInsights(text);
      setLoadingInsights(false);
    };
    fetchInsights();
  }, [data]);

  return (
    <div className="space-y-8 pb-12">
      {/* Top Section: Daily Total & Today's Distribution (Swapped) */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Left: Headline Metric */}
        <div className="bg-slate-800/80 p-8 rounded-3xl border border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-center h-full">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-blue-500/20 rounded-2xl text-blue-400">
              <Activity size={28} />
            </div>
            <span className="text-slate-400 font-bold uppercase tracking-wider text-sm">Today's Output</span>
          </div>
          <div className="text-7xl font-black text-white mb-2 tracking-tighter">
            {totalProduction.toLocaleString()}
          </div>
          <div className="text-xl text-slate-500 font-bold uppercase mb-4">Million Cubic Feet</div>
          <div className="mt-auto pt-6 border-t border-slate-700/50 text-emerald-400 text-lg flex items-center gap-2 font-bold">
            <TrendingUp size={24} /> +4.2% VS PREV
          </div>
        </div>

        {/* Right: Today's Distribution (Now at the top) */}
        <div className="bg-slate-800/80 p-8 rounded-3xl border border-slate-700 shadow-xl backdrop-blur-sm h-full">
          <FieldDistributionChart data={data} />
        </div>
      </div>

      {/* Primary Analytics Grid: Trend & Comparison (Remains in middle) */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
        <div className="bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <HistoricalTrendChart data={data} />
        </div>
        <div className="bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-lg">
          <FieldComparisonBar data={data} />
        </div>
      </div>

      {/* Detail Grid: AI Executive Summary & History (Swapped) */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: AI Executive Summary with Integrated Latest Data Table (Now at the bottom) */}
        <div className="bg-slate-800/80 rounded-3xl border border-slate-700 shadow-xl backdrop-blur-sm lg:col-span-2 flex flex-col lg:flex-row overflow-hidden">
          {/* Narrative Analysis */}
          <div className="flex-1 p-8 relative border-b lg:border-b-0 lg:border-r border-slate-700/50">
            <div className="flex items-center gap-4 mb-6">
              <div className="p-2.5 bg-purple-500/20 rounded-xl text-purple-400">
                <Sparkles size={24} />
              </div>
              <h2 className="text-xl font-bold text-white uppercase tracking-tight">AI Executive Summary</h2>
            </div>
            <div className={`text-xl text-slate-200 leading-relaxed font-medium transition-opacity duration-700 ${loadingInsights ? 'opacity-40 animate-pulse' : 'opacity-100'}`}>
