import React, { useState, useEffect } from 'react';
import { ProductionRecord, ViewType } from './types';
import { INITIAL_MOCK_DATA, ALLOWED_ADMIN_IPS } from './constants';
import Dashboard from './components/Dashboard';
import AdminPanel from './components/AdminPanel';
import { Monitor, Settings, LayoutDashboard, Database, Fuel, ShieldCheck, ShieldAlert, Lock } from 'lucide-react';

const App: React.FC = () => {
  const [data, setData] = useState<ProductionRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');
  const [userIp, setUserIp] = useState<string | null>(null);
  const [isIpChecking, setIsIpChecking] = useState(true);
  const [isAdminAllowed, setIsAdminAllowed] = useState(false);

  useEffect(() => {
    // 1. Fetch Production Data
    const saved = localStorage.getItem('gaspro_production_data');
    if (saved) {
      setData(JSON.parse(saved));
    } else {
      setData(INITIAL_MOCK_DATA);
    }

    // 2. IP Detection Logic
    const checkIpAccess = async () => {
      setIsIpChecking(true);
      try {
        const response = await fetch('https://api.ipify.org?format=json');
        const result = await response.json();
        const currentIp = result.ip;
        setUserIp(currentIp);

        // In local development or if user is on allowed list
        const isAllowed = ALLOWED_ADMIN_IPS.includes(currentIp) || 
                          window.location.hostname === 'localhost' || 
                          window.location.hostname === '127.0.0.1';

        setIsAdminAllowed(isAllowed);
      } catch (error) {
        console.error("IP Check Failed:", error);
        // Default to restricted if check fails
        setIsAdminAllowed(false);
      } finally {
        setIsIpChecking(false);
      }
    };

    checkIpAccess();
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      localStorage.setItem('gaspro_production_data', JSON.stringify(data));
    }
  }, [data]);

  const handleAddRecord = (record: ProductionRecord) => {
    setData(prev => [...prev, record]);
  };

  const handleDeleteRecord = (id: string) => {
    setData(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Dynamic Header */}
      <header className="sticky top-0 z-50 bg-slate-900/80 border-b border-slate-800 backdrop-blur-md px-8 py-5 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2 rounded-xl shadow-lg shadow-emerald-900/30">
            <Fuel className="text-white" size={32} />
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tight text-white uppercase">GasPro <span className="text-emerald-500">Analytics</span></h1>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">MD Dashboard Suite v3.4</p>
          </div>
        </div>

        <nav className="flex items-center bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
          <button 
            onClick={() => setView('dashboard')}
            className={`px-8 py-3 rounded-xl flex items-center gap-3 font-bold transition-all ${view === 'dashboard' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
          >
            <LayoutDashboard size={20} /> Dashboard
          </button>

          {/* Conditional Admin Tab based on IP Check */}
          {isAdminAllowed && (
            <button 
              onClick={() => setView('admin')}
              className={`px-8 py-3 rounded-xl flex items-center gap-3 font-bold transition-all ${view === 'admin' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              <Database size={20} /> Admin Panel
            </button>
          )}

          {isIpChecking && (
            <div className="px-8 py-3 text-slate-500 flex items-center gap-2 animate-pulse">
              <div className="w-2 h-2 bg-slate-600 rounded-full"></div>
              <span className="text-xs font-bold uppercase">Verifying...</span>
            </div>
          )}
        </nav>

        <div className="hidden lg:flex items-center gap-6">
          <div className="flex flex-col items-end">
            <div className="flex items-center gap-2">
              <span className="text-sm font-bold text-slate-100">Regional HQ</span>
              {/* Fix: Wrap icons in span to provide title tooltip via the native title attribute, resolving TS errors on lines 111 and 113 */}
              {isAdminAllowed ? (
                <span title="Secure Link Verified">
                  <ShieldCheck size={16} className="text-emerald-500" />
                </span>
              ) : (
                <span title="Public View Access">
                  <ShieldAlert size={16} className="text-amber-500" />
                </span>
              )}
            </div>
            <div className="text-[10px] text-slate-500 font-mono tracking-tight">
              IP: {userIp || '0.0.0.0'}
            </div>
          </div>
          <button className="p-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-400 transition-colors">
            <Settings size={24} />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 px-8 py-10 max-w-[2000px] mx-auto w-full">
        {view === 'dashboard' ? (
          <Dashboard data={data} />
        ) : isAdminAllowed ? (
          <AdminPanel data={data} onAdd={handleAddRecord} onDelete={handleDeleteRecord} />
        ) : (
          <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-6">
            <div className="p-8 bg-slate-800/50 rounded-full border border-slate-700/50 shadow-2xl">
