interface Props {
  data: ProductionRecord[];
  onAdd: (record: Omit<ProductionRecord, 'id'>) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
}

const AdminPanel: React.FC<Props> = ({ data, onAdd, onDelete }) => {
  const [field, setField] = useState(FIELDS[0].name);
  const [amount, setAmount] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [validationError, setValidationError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setValidationError(null);

    if (!amount || isNaN(Number(amount))) {
      setValidationError("Please enter a valid numeric amount.");
      return;
    }

    // Duplicate Validation: Check if a record for this field and date already exists
    const isDuplicate = data.some(
      (record) => record.field === field && record.date === date
    );

    if (isDuplicate) {
      setValidationError(`Data for "${field}" on ${date} already exists. Please edit or delete the existing record first.`);
      return;
    }

    setIsSubmitting(true);
    try {
      await onAdd({
        field,
        amount: Number(amount),
        date,
      });
      setAmount('');
    } catch (err) {
      setValidationError("Failed to save data. Please check your connection.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    setDeletingId(id);
    try {
      await onDelete(id);
    } finally {
      setDeletingId(null);
    }
  };

