      <div className="lg:col-span-2">
        <div className="bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-700 h-full overflow-hidden flex flex-col">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-2xl font-bold">PostgreSQL Archive</h2>
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest bg-slate-900 px-3 py-1 rounded-full border border-slate-700">
              {data.length} Records found
            </span>
          </div>
          <div className="overflow-y-auto flex-1 pr-2">
            <div className="space-y-3">
              {[...data].sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(record => (
                <div key={record.id} className="flex items-center justify-between p-4 bg-slate-900 rounded-xl border border-slate-700/50 group transition-all hover:border-blue-500/30">
                  <div>
