   * Adds a new production record to PostgreSQL
   */
  async addRecord(record: Omit<ProductionRecord, 'id'>): Promise<ProductionRecord | null> {
    if (!supabase) return null;

    const { data, error } = await supabase
      .from('production_records')
      .insert([record])
      .select()
      .single();

    if (error) {
      console.error('PostgreSQL Insert Error:', error.message);
      return null;
    }
    return data;
  },

  /**
   * Updates an existing production record in PostgreSQL
   */
  async updateRecord(id: string, record: Omit<ProductionRecord, 'id'>): Promise<ProductionRecord | null> {
    if (!supabase) return null;

    const { data, error } = await supabase
      .from('production_records')
      .update(record)
      .eq('id', id)
      .select()
      .single();

    if (error) {
      console.error('PostgreSQL Update Error:', error.message);
      return null;
    }
    return data;
  },

  /**
   * Deletes a production record from PostgreSQL
   */
  async deleteRecord(id: string): Promise<boolean> {
    if (!supabase) return false;

    const { error } = await supabase
      .from('production_records')
      .delete()
      .eq('id', id);

    if (error) {
      console.error('PostgreSQL Delete Error:', error.message);
      return false;
    }
    return true;
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ProductionRecord, ViewType } from './types';
import { INITIAL_MOCK_DATA, ALLOWED_ADMIN_IPS } from './constants';
import Dashboard from './components/Dashboard';
import AdminPanel from './components/AdminPanel';
import { dbService } from './services/dbService';
import { 
  Monitor, Settings, LayoutDashboard, Database, Fuel, 
  ShieldCheck, ShieldAlert, Lock, ChevronLeft, ChevronRight, 
  Calendar, RefreshCw, Server, AlertTriangle
} from 'lucide-react';

const App: React.FC = () => {
  const [data, setData] = useState<ProductionRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');
  const [isAdminAllowed, setIsAdminAllowed] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'online' | 'offline' | 'mock'>('mock');
  const isInitialLoad = useRef(true);

  // Derived date info
  const availableDates = useMemo(() => 
    Array.from(new Set<string>(data.map(r => r.date))).sort(), 
    [data]
  );

  const latestDateInSystem = useMemo(() => 
    availableDates.length > 0 ? availableDates[availableDates.length - 1] : new Date().toISOString().split('T')[0],
    [availableDates]
  );

  const [selectedDate, setSelectedDate] = useState<string>(latestDateInSystem);

  useEffect(() => {
    const initializeData = async () => {
      setIsLoading(true);

      if (!dbService.isConfigured()) {
        console.info("Supabase not configured. Loading mock data.");
        const saved = localStorage.getItem('gaspro_production_data');
        setData(saved ? JSON.parse(saved) : INITIAL_MOCK_DATA);
        setDbStatus('mock');
        setIsLoading(false);
        return;
      }

      try {
        const records = await dbService.getRecords();
        if (records && records.length > 0) {
          setData(records);
          setDbStatus('online');
        } else {
          // If DB is connected but empty, offer mock data as starting point
          const saved = localStorage.getItem('gaspro_production_data');
          setData(saved ? JSON.parse(saved) : INITIAL_MOCK_DATA);
          setDbStatus('online'); // It's online, just empty (or using local cache)
        }
      } catch (err) {
        console.error("DB Connection failed:", err);
        setDbStatus('offline');
        const saved = localStorage.getItem('gaspro_production_data');
        setData(saved ? JSON.parse(saved) : INITIAL_MOCK_DATA);
      } finally {
        setIsLoading(false);
      }
    };

    const checkIpAccess = async () => {
      try {
        const response = await fetch('https://api.ipify.org?format=json');
        const result = await response.json();
        const currentIp = result.ip;

        const isAllowed = ALLOWED_ADMIN_IPS.includes(currentIp) || 
                          window.location.hostname === 'localhost' || 
                          window.location.hostname === '127.0.0.1';

        setIsAdminAllowed(isAllowed);
      } catch (error) {
        // Fallback for dev environments
        if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
            setIsAdminAllowed(true);
        } else {
            setIsAdminAllowed(false);
        }
      }
    };

    initializeData();
    checkIpAccess();
  }, []);

  // Robust default-to-latest logic
  useEffect(() => {
    if (availableDates.length > 0) {
      if (isInitialLoad.current || !availableDates.includes(selectedDate)) {
        setSelectedDate(latestDateInSystem);
        isInitialLoad.current = false;
      }
    }
  }, [availableDates, latestDateInSystem, selectedDate]);

  // Persistence for mock mode
  useEffect(() => {
    if (dbStatus === 'mock' && data.length > 0) {
      localStorage.setItem('gaspro_production_data', JSON.stringify(data));
    }
  }, [data, dbStatus]);

  const handleAddRecord = async (record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      const newRecord = await dbService.addRecord(record);
      if (newRecord) {
        setData(prev => [newRecord, ...prev]);
        return;
      }
    }

    // Fallback/Mock mode
    const mockRecord = { ...record, id: Math.random().toString(36).substr(2, 9) };
    setData(prev => [mockRecord, ...prev]);
  };

  const handleUpdateRecord = async (id: string, record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      const updatedRecord = await dbService.updateRecord(id, record);
      if (updatedRecord) {
        setData(prev => prev.map(r => r.id === id ? updatedRecord : r));
        return;
      }
    }

    // Fallback/Mock mode
    setData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
  };

  const handleDeleteRecord = async (id: string) => {
    if (dbStatus === 'online') {
      const success = await dbService.deleteRecord(id);
      if (success) {
        setData(prev => prev.filter(r => r.id !== id));
        return;
      }
    }

    // Fallback/Mock mode
    setData(prev => prev.filter(r => r.id !== id));
  };

  const handlePrevDay = () => {
    const idx = availableDates.indexOf(selectedDate);
    if (idx > 0) setSelectedDate(availableDates[idx - 1]);
  };

  const handleNextDay = () => {
    const idx = availableDates.indexOf(selectedDate);
    if (idx < availableDates.length - 1) setSelectedDate(availableDates[idx + 1]);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <header className="sticky top-0 z-50 bg-slate-900/90 border-b border-slate-800 backdrop-blur-md px-8 py-4 flex items-center justify-between shadow-2xl">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2 rounded-xl shadow-lg shadow-emerald-900/30">
            <Fuel className="text-white" size={28} />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-xl font-black tracking-tight text-white uppercase leading-none">GasPro <span className="text-emerald-500">Analytics</span></h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">
              {dbStatus === 'online' ? 'Cloud SQL Synchronized' : 'Local Sandbox Mode'}
            </p>
          </div>
        </div>

        <nav className="flex items-center bg-slate-900/50 p-1 rounded-2xl border border-slate-700/50 shadow-inner">
          <button 
            onClick={() => setView('dashboard')}
            className={`px-6 py-2.5 rounded-xl flex items-center gap-2 font-bold transition-all ${view === 'dashboard' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <LayoutDashboard size={18} /> <span className="hidden md:inline">Dashboard</span>
          </button>

          {view === 'dashboard' && (
            <div className="mx-2 flex items-center gap-1 bg-slate-800/80 px-2 py-1 rounded-lg border border-slate-700">
              <button 
                onClick={handlePrevDay}
                disabled={availableDates.indexOf(selectedDate) <= 0}
                className="p-1.5 text-slate-400 hover:text-white disabled:opacity-10 transition-colors"
                aria-label="Previous day"
              >
                <ChevronLeft size={20} />
              </button>

              <div className="flex items-center gap-2 px-2 text-white font-black text-sm border-x border-slate-700">
                <Calendar size={14} className="text-emerald-500" />
                <input 
                  type="date" 
                  value={selectedDate}
                  onChange={(e) => setSelectedDate(e.target.value)}
                  className="bg-transparent border-none focus:ring-0 outline-none text-center cursor-pointer p-0 w-32"
                />
              </div>

              <button 
                onClick={handleNextDay}
                disabled={availableDates.indexOf(selectedDate) >= availableDates.length - 1}
                className="p-1.5 text-slate-400 hover:text-white disabled:opacity-10 transition-colors"
                aria-label="Next day"
              >
                <ChevronRight size={20} />
              </button>
            </div>
          )}

          {isAdminAllowed && (
            <button 
              onClick={() => setView('admin')}
              className={`px-6 py-2.5 rounded-xl flex items-center gap-2 font-bold transition-all ${view === 'admin' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <Database size={18} /> <span className="hidden md:inline">Admin</span>
            </button>
          )}
        </nav>

        <div className="hidden lg:flex items-center gap-6">
          <div className="flex flex-col items-end">
            <div className="flex items-center gap-2">
              <span className="text-xs font-bold text-slate-300 uppercase tracking-tighter">Server Status</span>
              {dbStatus === 'online' ? (
                <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-500/10 text-emerald-500 rounded-full border border-emerald-500/20">
                  <Server size={10} />
                  <span className="text-[10px] font-black">PostgreSQL LIVE</span>
                </div>
              ) : dbStatus === 'mock' ? (
                <div className="flex items-center gap-1.5 px-2 py-0.5 bg-blue-500/10 text-blue-400 rounded-full border border-blue-500/20">
                  <Database size={10} />
                  <span className="text-[10px] font-black uppercase">Demo Data</span>
                </div>
              ) : (
                <div className="flex items-center gap-1.5 px-2 py-0.5 bg-amber-500/10 text-amber-500 rounded-full border border-amber-500/20">
                  <AlertTriangle size={10} />
                  <span className="text-[10px] font-black uppercase">Offline</span>
                </div>
              )}
            </div>
          </div>
          <button className="p-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-400 transition-colors border border-slate-700/50">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <main className="flex-1 px-8 py-8 max-w-[2000px] mx-auto w-full">
        {isLoading ? (
          <div className="h-[60vh] flex flex-col items-center justify-center space-y-4">
            <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-slate-400 font-bold uppercase tracking-[0.2em] animate-pulse">Initializing Interface...</p>
          </div>
        ) : view === 'dashboard' ? (
          <Dashboard data={data} selectedDate={selectedDate} latestDateInSystem={latestDateInSystem} />
        ) : isAdminAllowed ? (
          <AdminPanel 
            data={data} 
            onAdd={handleAddRecord} 
            onUpdate={handleUpdateRecord}
            onDelete={handleDeleteRecord} 
          />
        ) : (
          <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-6">
            <div className="p-8 bg-slate-800/50 rounded-full border border-slate-700/50 shadow-2xl">
              <Lock size={120} className="text-slate-600" />
            </div>
            <div className="max-w-md">
              <h2 className="text-3xl font-black text-white mb-4">RESTRICTED AREA</h2>
              <p className="text-slate-400 font-medium">
                Authorization failed. Please access from the corporate network or contact IT.
              </p>
              <button 
                onClick={() => setView('dashboard')}
                className="mt-8 px-10 py-4 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700 transition-colors"
              >
                Return to Dashboard
              </button>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-slate-900 border-t border-slate-800 p-6 flex justify-between items-center text-slate-500 text-xs font-medium">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <Monitor size={14} /> TV Optimization v3.5
          </div>
          <div className="flex items-center gap-2">
            <div className={`w-1.5 h-1.5 rounded-full ${dbStatus === 'online' ? 'bg-emerald-500' : dbStatus === 'mock' ? 'bg-blue-500' : 'bg-amber-500 animate-pulse'}`}></div>
            {dbStatus === 'online' ? 'PostgreSQL Connected' : dbStatus === 'mock' ? 'Mock Mode (LocalStorage)' : 'Connection Interrupted'}
          </div>
        </div>
        <div>
          &copy; {new Date().getFullYear()} Gas Production Ltd. Cloud Intelligence Suite.
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { FIELDS } from '../constants';
import { ProductionRecord } from '../types';
import { 
  PlusCircle, Trash2, Database, AlertCircle, Loader2, XCircle, 
  Edit3, ChevronLeft, ChevronRight, Save, X
} from 'lucide-react';

interface Props {
  data: ProductionRecord[];
  onAdd: (record: Omit<ProductionRecord, 'id'>) => Promise<void>;
  onUpdate: (id: string, record: Omit<ProductionRecord, 'id'>) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
}

const RECORDS_PER_PAGE = 10;

const AdminPanel: React.FC<Props> = ({ data, onAdd, onUpdate, onDelete }) => {
  // Form State
  const [field, setField] = useState(FIELDS[0].name);
  const [amount, setAmount] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [editingId, setEditingId] = useState<string | null>(null);

  // UI State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [validationError, setValidationError] = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState(1);

  // Pagination Logic
  const sortedData = useMemo(() => 
    [...data].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()), 
    [data]
  );

  const totalPages = Math.ceil(sortedData.length / RECORDS_PER_PAGE);
  const currentRecords = useMemo(() => {
    const start = (currentPage - 1) * RECORDS_PER_PAGE;
    return sortedData.slice(start, start + RECORDS_PER_PAGE);
  }, [sortedData, currentPage]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setValidationError(null);

    const numAmount = Number(amount);
    if (!amount || isNaN(numAmount)) {
      setValidationError("Please enter a valid numeric amount.");
      return;
    }

    // Duplicate Validation: Check if a record for this field and date already exists (excluding the one being edited)
    const isDuplicate = data.some(
      (record) => record.field === field && record.date === date && record.id !== editingId
    );

    if (isDuplicate) {
      setValidationError(`Data for "${field}" on ${date} already exists. Please edit that record or use a different date.`);
      return;
    }

    setIsSubmitting(true);
    try {
      if (editingId) {
        await onUpdate(editingId, { field, amount: numAmount, date });
        setEditingId(null);
      } else {
        await onAdd({ field, amount: numAmount, date });
      }
      setAmount('');
      // Reset form to default date after success if adding
      if (!editingId) setDate(new Date().toISOString().split('T')[0]);
    } catch (err) {
      setValidationError("An error occurred while saving. Please check your connection.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const startEdit = (record: ProductionRecord) => {
    setField(record.field);
    setAmount(record.amount.toString());
    setDate(record.date);
    setEditingId(record.id);
    setValidationError(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const cancelEdit = () => {
    setEditingId(null);
    setAmount('');
    setField(FIELDS[0].name);
    setDate(new Date().toISOString().split('T')[0]);
    setValidationError(null);
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Are you sure you want to delete this record?")) return;
    setDeletingId(id);
    try {
      await onDelete(id);
      // Adjust page if we deleted the last item on a page
      if (currentRecords.length === 1 && currentPage > 1) {
        setCurrentPage(prev => prev - 1);
      }
    } finally {
      setDeletingId(null);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Entry / Edit Form */}
      <div className="lg:col-span-1">
        <div className={`bg-slate-800 p-8 rounded-2xl shadow-xl border transition-all duration-300 ${editingId ? 'border-amber-500/50 ring-1 ring-amber-500/20' : 'border-slate-700'}`}>
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-2xl font-bold flex items-center gap-2">
              {editingId ? (
                <>
                  <Edit3 className="text-amber-500" /> Edit Record
                </>
              ) : (
                <>
                  <Database className="text-blue-500" /> Cloud Write
                </>
              )}
            </h2>
            {editingId && (
              <button 
                onClick={cancelEdit}
                className="text-slate-400 hover:text-white p-1"
                title="Cancel Edit"
              >
                <X size={20} />
              </button>
            )}
          </div>

          {validationError && (
            <div className="mb-6 p-4 bg-red-500/10 border border-red-500/50 rounded-xl flex items-start gap-3 text-red-400 text-sm animate-in fade-in slide-in-from-top-2">
              <XCircle className="shrink-0 mt-0.5" size={18} />
              <p className="font-medium">{validationError}</p>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-2">Gas Field</label>
              <select 
                value={field}
                onChange={(e) => {
                  setField(e.target.value);
                  setValidationError(null);
                }}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {FIELDS.map(f => <option key={f.id} value={f.name}>{f.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-2">Production Amount (MCF)</label>
              <input 
                type="number"
                value={amount}
                onChange={(e) => {
                  setAmount(e.target.value);
                  setValidationError(null);
                }}
                placeholder="e.g. 500"
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-blue-500 outline-none font-mono"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-2">Production Date</label>
              <input 
                type="date"
                value={date}
                onChange={(e) => {
                  setDate(e.target.value);
                  setValidationError(null);
                }}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-blue-500 outline-none"
                required
              />
            </div>
            <div className="flex flex-col gap-3">
              <button 
                type="submit"
                disabled={isSubmitting}
                className={`w-full font-bold py-4 rounded-lg transition-all flex items-center justify-center gap-2 shadow-lg ${
                  editingId 
                    ? 'bg-amber-600 hover:bg-amber-500 shadow-amber-900/20 text-white' 
                    : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20 text-white'
                } disabled:opacity-50 disabled:cursor-not-allowed`}
              >
                {isSubmitting ? (
                  <>
                    <Loader2 size={20} className="animate-spin" /> {editingId ? 'Updating...' : 'Committing...'}
                  </>
                ) : (
                  <>
                    {editingId ? <Save size={20} /> : <PlusCircle size={20} />}
                    {editingId ? 'Update PostgreSQL Record' : 'Push to PostgreSQL'}
                  </>
                )}
              </button>
              {editingId && (
                <button 
                  type="button"
                  onClick={cancelEdit}
                  className="w-full bg-slate-700 hover:bg-slate-600 text-slate-200 font-bold py-3 rounded-lg transition-all"
                >
                  Cancel Edit
                </button>
              )}
            </div>
          </form>
        </div>
      </div>

      {/* Recent Records List with Pagination */}
      <div className="lg:col-span-2">
        <div className="bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-700 h-full flex flex-col min-h-[600px]">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-2xl font-bold">PostgreSQL Archive</h2>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                Displaying {currentRecords.length} of {data.length} Total Records
              </p>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-[10px] font-black text-slate-400 bg-slate-900 px-3 py-1 rounded-full border border-slate-700">
                Page {currentPage} / {totalPages || 1}
              </span>
            </div>
          </div>

          <div className="flex-1 space-y-3">
            {currentRecords.map(record => (
              <div 
                key={record.id} 
                className={`flex items-center justify-between p-4 bg-slate-900 rounded-xl border group transition-all duration-200 ${
                  editingId === record.id 
                    ? 'border-amber-500/50 bg-amber-500/5 shadow-lg shadow-amber-900/10' 
                    : 'border-slate-700/50 hover:border-blue-500/30'
                }`}
              >
                <div className="flex-1">
                  <div className="flex items-center gap-3">
                    <div className={`font-bold ${editingId === record.id ? 'text-amber-400' : 'text-slate-100'}`}>
                      {record.field}
                    </div>
                    {editingId === record.id && (
                      <span className="text-[8px] bg-amber-500/20 text-amber-500 px-1.5 py-0.5 rounded font-black uppercase tracking-tighter">
                        Active Edit
                      </span>
                    )}
                  </div>
                  <div className="text-sm text-slate-400 flex items-center gap-3 mt-0.5">
                    <span className="flex items-center gap-1"><ChevronRight size={12} className="text-slate-600" /> {record.date}</span>
                    <span className="w-1 h-1 bg-slate-600 rounded-full"></span>
                    <span className="text-emerald-400 font-mono font-bold">{record.amount.toLocaleString()} MCF</span>
                  </div>
                </div>

                <div className="flex items-center gap-2">
                  <button 
                    onClick={() => startEdit(record)}
                    disabled={isSubmitting}
                    className="p-2.5 text-slate-500 hover:text-amber-400 hover:bg-amber-400/10 rounded-lg transition-all opacity-0 group-hover:opacity-100 disabled:opacity-0"
                    title="Edit Record"
                  >
                    <Edit3 size={18} />
                  </button>
                  <button 
                    onClick={() => handleDelete(record.id)}
                    disabled={deletingId === record.id || isSubmitting}
                    className="p-2.5 text-slate-500 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all opacity-0 group-hover:opacity-100 disabled:opacity-50"
                    title="Delete Record"
                  >
                    {deletingId === record.id ? (
                      <Loader2 size={18} className="animate-spin text-red-400" />
                    ) : (
                      <Trash2 size={18} />
                    )}
                  </button>
                </div>
              </div>
            ))}

            {data.length === 0 && (
              <div className="text-center py-20 text-slate-500 flex flex-col items-center gap-4">
                <AlertCircle size={48} className="opacity-20" />
                <p className="font-bold uppercase tracking-widest text-sm">PostgreSQL Table Empty</p>
                <p className="text-xs text-slate-600">Please seed the database using the entry form.</p>
              </div>
            )}
          </div>

          {/* Pagination Controls */}
          {totalPages > 1 && (
            <div className="mt-8 flex items-center justify-between pt-6 border-t border-slate-700/50">
              <button 
                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                disabled={currentPage === 1}
                className="flex items-center gap-2 px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg text-slate-400 hover:text-white hover:border-slate-500 disabled:opacity-30 disabled:cursor-not-allowed transition-all font-bold text-sm"
              >
                <ChevronLeft size={16} /> Previous
              </button>

              <div className="flex items-center gap-1.5">
                {Array.from({ length: totalPages }, (_, i) => i + 1).map(page => (
                  <button
                    key={page}
                    onClick={() => setCurrentPage(page)}
                    className={`w-10 h-10 rounded-lg border font-bold text-sm transition-all ${
                      currentPage === page 
                        ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-900/20 scale-110' 
                        : 'bg-slate-900 border-slate-700 text-slate-500 hover:text-slate-300'
                    }`}
                  >
                    {page}
                  </button>
                ))}
              </div>

              <button 
                onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                disabled={currentPage === totalPages}
                className="flex items-center gap-2 px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg text-slate-400 hover:text-white hover:border-slate-500 disabled:opacity-30 disabled:cursor-not-allowed transition-all font-bold text-sm"
              >
                Next <ChevronRight size={16} />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

