import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { ProductionRecord, PersonnelRecord } from '../types';

const supabaseUrl = process.env.SUPABASE_URL;
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY;

const supabase: SupabaseClient | null = (supabaseUrl && supabaseAnonKey) 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

export const dbService = {
  isConfigured(): boolean {
    return !!supabase;
  },

  // Production Records
  async getRecords(): Promise<ProductionRecord[]> {
    if (!supabase) return [];
    const { data, error } = await supabase.from('production_records').select('*').order('date', { ascending: false });
    if (error) return [];
    return data || [];
  },

  async addRecord(record: Omit<ProductionRecord, 'id'>): Promise<ProductionRecord | null> {
    if (!supabase) return null;
    const { data, error } = await supabase.from('production_records').insert([record]).select().single();
    return error ? null : data;
  },

  async updateRecord(id: string, record: Omit<ProductionRecord, 'id'>): Promise<ProductionRecord | null> {
    if (!supabase) return null;
    const { data, error } = await supabase.from('production_records').update(record).eq('id', id).select().single();
    return error ? null : data;
  },

  async deleteRecord(id: string): Promise<boolean> {
    if (!supabase) return false;
    const { error } = await supabase.from('production_records').delete().eq('id', id);
    return !error;
  },

  // Personnel Records
  async getPersonnelRecords(): Promise<PersonnelRecord[]> {
    if (!supabase) return [];
    const { data, error } = await supabase.from('personnel_records').select('*').order('date', { ascending: false });
    if (error) return [];
    return data || [];
  },

  async addPersonnelRecord(record: Omit<PersonnelRecord, 'id'>): Promise<PersonnelRecord | null> {
    if (!supabase) return null;
    const { data, error } = await supabase.from('personnel_records').insert([record]).select().single();
    return error ? null : data;
  },

  async updatePersonnelRecord(id: string, record: Omit<PersonnelRecord, 'id'>): Promise<PersonnelRecord | null> {
    if (!supabase) return null;
    const { data, error } = await supabase.from('personnel_records').update(record).eq('id', id).select().single();
    return error ? null : data;
  },

  async deletePersonnelRecord(id: string): Promise<boolean> {
    if (!supabase) return false;
    const { error } = await supabase.from('personnel_records').delete().eq('id', id);
    return !error;
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ProductionRecord, PersonnelRecord, ViewType } from './types';
import { INITIAL_MOCK_DATA, INITIAL_PERSONNEL_DATA, ALLOWED_ADMIN_IPS } from './constants';
import Dashboard from './components/Dashboard';
import AdminPanel from './components/AdminPanel';
import { dbService } from './services/dbService';
import { 
  Monitor, Settings, LayoutDashboard, Database, Fuel, 
  Lock, ChevronLeft, ChevronRight, 
  Calendar, Server, AlertTriangle
} from 'lucide-react';

const App: React.FC = () => {
  const [productionData, setProductionData] = useState<ProductionRecord[]>([]);
  const [personnelData, setPersonnelData] = useState<PersonnelRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');
  const [isAdminAllowed, setIsAdminAllowed] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'online' | 'offline' | 'mock'>('mock');
  const isInitialLoad = useRef(true);

  const availableDates = useMemo(() => {
    const dates = new Set<string>();
    productionData.forEach(r => dates.add(r.date));
    personnelData.forEach(r => dates.add(r.date));
    return Array.from(dates).sort();
  }, [productionData, personnelData]);

  const latestDateInSystem = useMemo(() => 
    availableDates.length > 0 ? availableDates[availableDates.length - 1] : new Date().toISOString().split('T')[0],
    [availableDates]
  );

  const [selectedDate, setSelectedDate] = useState<string>(latestDateInSystem);

  useEffect(() => {
    const initializeData = async () => {
      setIsLoading(true);
      if (!dbService.isConfigured()) {
        const savedProd = localStorage.getItem('gaspro_production_data');
        const savedPers = localStorage.getItem('gaspro_personnel_data');
        setProductionData(savedProd ? JSON.parse(savedProd) : INITIAL_MOCK_DATA);
        setPersonnelData(savedPers ? JSON.parse(savedPers) : INITIAL_PERSONNEL_DATA);
        setDbStatus('mock');
        setIsLoading(false);
        return;
      }
      try {
        const [records, personnel] = await Promise.all([
          dbService.getRecords(),
          dbService.getPersonnelRecords()
        ]);
        setProductionData(records.length ? records : INITIAL_MOCK_DATA);
        setPersonnelData(personnel.length ? personnel : INITIAL_PERSONNEL_DATA);
        setDbStatus('online');
      } catch (err) {
        setDbStatus('offline');
        const savedProd = localStorage.getItem('gaspro_production_data');
        setProductionData(savedProd ? JSON.parse(savedProd) : INITIAL_MOCK_DATA);
      } finally {
        setIsLoading(false);
      }
    };
    const checkIpAccess = async () => {
      try {
        const response = await fetch('https://api.ipify.org?format=json');
        const result = await response.json();
        setIsAdminAllowed(ALLOWED_ADMIN_IPS.includes(result.ip) || window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');
      } catch {
        setIsAdminAllowed(window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');
      }
    };
    initializeData();
    checkIpAccess();
  }, []);

  useEffect(() => {
    if (availableDates.length > 0 && (isInitialLoad.current || !availableDates.includes(selectedDate))) {
      setSelectedDate(latestDateInSystem);
      isInitialLoad.current = false;
    }
  }, [availableDates, latestDateInSystem]);

  useEffect(() => {
    if (dbStatus === 'mock') {
      localStorage.setItem('gaspro_production_data', JSON.stringify(productionData));
      localStorage.setItem('gaspro_personnel_data', JSON.stringify(personnelData));
    }
  }, [productionData, personnelData, dbStatus]);

  // Handlers for Production
  const handleAddProduction = async (record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      const newRecord = await dbService.addRecord(record);
      if (newRecord) { setProductionData(prev => [newRecord, ...prev]); return; }
    }
    setProductionData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
  };
  const handleUpdateProduction = async (id: string, record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      const updated = await dbService.updateRecord(id, record);
      if (updated) { setProductionData(prev => prev.map(r => r.id === id ? updated : r)); return; }
    }
    setProductionData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
  };
  const handleDeleteProduction = async (id: string) => {
    if (dbStatus === 'online' && await dbService.deleteRecord(id)) { setProductionData(prev => prev.filter(r => r.id !== id)); return; }
    setProductionData(prev => prev.filter(r => r.id !== id));
  };

  // Handlers for Personnel
  const handleAddPersonnel = async (record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') {
      const newRecord = await dbService.addPersonnelRecord(record);
      if (newRecord) { setPersonnelData(prev => [newRecord, ...prev]); return; }
    }
    setPersonnelData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
  };
  const handleUpdatePersonnel = async (id: string, record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') {
      const updated = await dbService.updatePersonnelRecord(id, record);
      if (updated) { setPersonnelData(prev => prev.map(r => r.id === id ? updated : r)); return; }
    }
    setPersonnelData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
  };
  const handleDeletePersonnel = async (id: string) => {
    if (dbStatus === 'online' && await dbService.deletePersonnelRecord(id)) { setPersonnelData(prev => prev.filter(r => r.id !== id)); return; }
    setPersonnelData(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0f172a]">
      <header className="sticky top-0 z-50 bg-slate-900/90 border-b border-slate-800 backdrop-blur-md px-8 py-4 flex items-center justify-between shadow-2xl">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2 rounded-xl shadow-lg shadow-emerald-900/30"><Fuel className="text-white" size={28} /></div>
          <div className="hidden sm:block">
            <h1 className="text-xl font-black tracking-tight text-white uppercase leading-none">GasPro <span className="text-emerald-500">Analytics</span></h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">{dbStatus === 'online' ? 'PostgreSQL Active' : 'Offline Mode'}</p>
          </div>
        </div>
        <nav className="flex items-center bg-slate-900/50 p-1 rounded-2xl border border-slate-700/50 shadow-inner">
          <button onClick={() => setView('dashboard')} className={`px-6 py-2.5 rounded-xl flex items-center gap-2 font-bold transition-all ${view === 'dashboard' ? 'bg-slate-700 text-white' : 'text-slate-500 hover:text-slate-300'}`}>
            <LayoutDashboard size={18} /> <span className="hidden md:inline">Dashboard</span>
          </button>
          {view === 'dashboard' && (
            <div className="mx-2 flex items-center gap-1 bg-slate-800/80 px-2 py-1 rounded-lg border border-slate-700">
              <button onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx > 0) setSelectedDate(availableDates[idx - 1]); }} disabled={availableDates.indexOf(selectedDate) <= 0} className="p-1.5 text-slate-400 hover:text-white disabled:opacity-10"><ChevronLeft size={20} /></button>
              <div className="flex items-center gap-2 px-2 text-white font-black text-sm border-x border-slate-700"><Calendar size={14} className="text-emerald-500" /><input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} className="bg-transparent border-none focus:ring-0 outline-none p-0 w-32" /></div>
              <button onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx < availableDates.length - 1) setSelectedDate(availableDates[idx + 1]); }} disabled={availableDates.indexOf(selectedDate) >= availableDates.length - 1} className="p-1.5 text-slate-400 hover:text-white disabled:opacity-10"><ChevronRight size={20} /></button>
            </div>
          )}
          {isAdminAllowed && (
            <button onClick={() => setView('admin')} className={`px-6 py-2.5 rounded-xl flex items-center gap-2 font-bold transition-all ${view === 'admin' ? 'bg-slate-700 text-white' : 'text-slate-500 hover:text-slate-300'}`}>
              <Database size={18} /> <span className="hidden md:inline">Admin</span>
            </button>
          )}
        </nav>
        <div className="hidden lg:flex items-center gap-4">
           {dbStatus === 'online' ? (
              <div className="flex items-center gap-1.5 px-3 py-1 bg-emerald-500/10 text-emerald-500 rounded-full border border-emerald-500/20 text-[10px] font-black uppercase"><Server size={10} /> Cloud Link</div>
           ) : (
              <div className="flex items-center gap-1.5 px-3 py-1 bg-amber-500/10 text-amber-500 rounded-full border border-amber-500/20 text-[10px] font-black uppercase"><AlertTriangle size={10} /> Local Cache</div>
           )}
           <button className="p-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-400 border border-slate-700/50"><Settings size={20} /></button>
        </div>
      </header>
      <main className="flex-1 px-8 py-8 max-w-[2000px] mx-auto w-full">
        {isLoading ? (
          <div className="h-[60vh] flex flex-col items-center justify-center space-y-4 text-slate-500"><div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div><p className="font-bold uppercase tracking-widest text-sm">System Initializing...</p></div>
        ) : view === 'dashboard' ? (
          <Dashboard productionData={productionData} personnelData={personnelData} selectedDate={selectedDate} latestDateInSystem={latestDateInSystem} />
        ) : (
          <AdminPanel 
            productionData={productionData} 
            personnelData={personnelData}
            onAddProduction={handleAddProduction} 
            onUpdateProduction={handleUpdateProduction}
            onDeleteProduction={handleDeleteProduction}
            onAddPersonnel={handleAddPersonnel}
            onUpdatePersonnel={handleUpdatePersonnel}
            onDeletePersonnel={handleDeletePersonnel}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { ProductionRecord, PersonnelRecord } from '../types';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts';
import ProductionTable from './ProductionTable';
import { getAIInsights } from '../services/geminiService';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList, History, Zap, Users, Briefcase } from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  selectedDate: string;
  latestDateInSystem: string;
}

const Dashboard: React.FC<Props> = ({ productionData, personnelData, selectedDate, latestDateInSystem }) => {
  const [insights, setInsights] = useState<string>('Analyzing operational metrics...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  const dayRecords = useMemo(() => productionData.filter(d => d.date === selectedDate), [productionData, selectedDate]);
  const dayPersonnel = useMemo(() => personnelData.find(p => p.date === selectedDate), [personnelData, selectedDate]);

  const totalProduction = useMemo(() => dayRecords.reduce((acc, curr) => acc + curr.amount, 0), [dayRecords]);
  const isHistorical = selectedDate !== latestDateInSystem;

  useEffect(() => {
    const fetchInsights = async () => {
      if (dayRecords.length === 0) return;
      setLoadingInsights(true);
      const text = await getAIInsights(productionData, selectedDate);
      setInsights(text);
      setLoadingInsights(false);
    };
    fetchInsights();
  }, [selectedDate, productionData]);

  return (
    <div className="space-y-8 pb-12">
      <div className={`flex items-center gap-4 px-6 py-3 rounded-2xl border ${isHistorical ? 'bg-amber-500/5 border-amber-500/20 text-amber-500' : 'bg-emerald-500/5 border-emerald-500/20 text-emerald-500'} transition-all`}>
        {isHistorical ? <History size={20} /> : <Zap size={20} className="animate-pulse" />}
        <span className="font-black uppercase tracking-widest text-sm text-slate-100">
          {isHistorical ? `Historical Window: ${selectedDate}` : `Real-Time Monitoring: ${selectedDate}`}
