import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ProductionRecord, PersonnelRecord, ViewType } from './types.ts';
import { INITIAL_MOCK_DATA, INITIAL_PERSONNEL_DATA, ALLOWED_ADMIN_IPS } from './constants.ts';
import Dashboard from './components/Dashboard.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import { dbService } from './services/dbService.ts';
import { 
  Monitor, Settings, LayoutDashboard, Database, Fuel, 
  Lock, ChevronLeft, ChevronRight, 
  Calendar, Server, AlertTriangle, Clock, RefreshCw, Wifi, Moon, Sun
} from 'lucide-react';

const CompanyLogo = () => (
  <svg className="w-8 h-8 drop-shadow-lg" viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg">
    <path d="M50 5 C30 5 15 35 15 60 C15 85 30 95 50 95 C70 95 85 85 85 60 C85 35 70 5 50 5 Z" fill="#FBBF24" />
    <path d="M42 45 L42 85 M42 45 Q55 45 55 55 Q55 65 42 65 M42 65 Q58 65 58 75 Q58 85 42 85" fill="none" stroke="#EF4444" stroke-width="8" stroke-linecap="round" stroke-linejoin="round" />
    <path d="M65 45 Q50 45 50 65 Q50 85 65 85 L65 75" fill="none" stroke="#10B981" stroke-width="8" stroke-linecap="round" />
  </svg>
);

const App: React.FC = () => {
  const [productionData, setProductionData] = useState<ProductionRecord[]>([]);
  const [personnelData, setPersonnelData] = useState<PersonnelRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');
  const [isAdminAllowed, setIsAdminAllowed] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'online' | 'offline' | 'mock'>('mock');
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);
  const [isDark, setIsDark] = useState(document.documentElement.classList.contains('dark'));
  const isInitialLoad = useRef(true);

  const toggleTheme = () => {
    if (isDark) {
      document.documentElement.classList.remove('dark');
      localStorage.theme = 'light';
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.theme = 'dark';
      setIsDark(true);
    }
  };

  // Derived unique sorted dates from both datasets
  const availableDates = useMemo(() => {
    const dates = new Set<string>();
    productionData.forEach(r => dates.add(r.date));
    return Array.from(dates).sort();
  }, [productionData]);

  const latestDateInSystem = useMemo(() => 
    availableDates.length > 0 ? availableDates[availableDates.length - 1] : new Date().toISOString().split('T')[0],
    [availableDates]
  );

  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const fetchData = async () => {
    if (!dbService.isConfigured()) {
      const savedProd = localStorage.getItem('gaspro_production_data');
      const savedPers = localStorage.getItem('gaspro_personnel_data');
      setProductionData(savedProd ? JSON.parse(savedProd) : INITIAL_MOCK_DATA);
      setPersonnelData(savedPers ? JSON.parse(savedPers) : INITIAL_PERSONNEL_DATA);
      setDbStatus('mock');
      return;
    }
    try {
      const [records, personnel] = await Promise.all([
        dbService.getRecords(),
        dbService.getPersonnelRecords()
      ]);
      setProductionData(records);
      setPersonnelData(personnel);
      setDbStatus('online');
      setLastUpdated(new Date());
    } catch (err) {
      console.error("Fetch error:", err);
      setDbStatus('offline');
    }
  };

  useEffect(() => {
    if (dbStatus !== 'online') return;

    const channel = dbService.subscribeToChanges((payload) => {
      setIsSyncing(true);
      const { type, eventType, new: newRecord, old: oldRecord } = payload;

      if (type === 'production') {
        setProductionData(prev => {
          if (eventType === 'INSERT') return [newRecord, ...prev];
          if (eventType === 'UPDATE') return prev.map(r => r.id === newRecord.id ? newRecord : r);
          if (eventType === 'DELETE') return prev.filter(r => r.id !== oldRecord.id);
          return prev;
        });
      } else if (type === 'personnel') {
        setPersonnelData(prev => {
          if (eventType === 'INSERT') return [newRecord, ...prev];
          if (eventType === 'UPDATE') return prev.map(r => r.id === newRecord.id ? newRecord : r);
          if (eventType === 'DELETE') return prev.filter(r => r.id !== oldRecord.id);
          return prev;
        });
      }

      setLastUpdated(new Date());
      setTimeout(() => setIsSyncing(false), 1500);
    });

    return () => {
      if (channel) channel.unsubscribe();
    };
  }, [dbStatus]);

  useEffect(() => {
    const initialize = async () => {
      setIsLoading(true);
      await fetchData();

      try {
        const response = await fetch('https://api.ipify.org?format=json');
        const result = await response.json();
        setIsAdminAllowed(ALLOWED_ADMIN_IPS.includes(result.ip) || window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');
      } catch {
        setIsAdminAllowed(window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');
      }
      setIsLoading(false);
    };
    initialize();
  }, []);

  useEffect(() => {
    if (!isLoading && availableDates.length > 0) {
      if (isInitialLoad.current || !availableDates.includes(selectedDate)) {
        setSelectedDate(latestDateInSystem);
        isInitialLoad.current = false;
      }
    }
  }, [availableDates, latestDateInSystem, isLoading, selectedDate]);

  useEffect(() => {
    if (dbStatus === 'mock') {
      localStorage.setItem('gaspro_production_data', JSON.stringify(productionData));
      localStorage.setItem('gaspro_personnel_data', JSON.stringify(personnelData));
      setLastUpdated(new Date());
    }
  }, [productionData, personnelData, dbStatus]);

  const handleAddProduction = async (record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.addRecord(record);
    } else {
      setProductionData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
    }
  };

  const handleUpdateProduction = async (id: string, record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.updateRecord(id, record);
    } else {
      setProductionData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
    }
  };

  const handleDeleteProduction = async (id: string) => {
    if (dbStatus === 'online') {
      await dbService.deleteRecord(id);
    } else {
      setProductionData(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleAddPersonnel = async (record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.addPersonnelRecord(record);
    } else {
      setPersonnelData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
    }
  };

  const handleUpdatePersonnel = async (id: string, record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.updatePersonnelRecord(id, record);
    } else {
      setPersonnelData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
    }
  };

  const handleDeletePersonnel = async (id: string) => {
    if (dbStatus === 'online') {
      await dbService.deletePersonnelRecord(id);
    } else {
      setPersonnelData(prev => prev.filter(r => r.id !== id));
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-[#0f172a] text-slate-900 dark:text-slate-100 transition-colors duration-300">
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-slate-900/90 border-b border-slate-200 dark:border-slate-800 backdrop-blur-md px-8 py-4 flex items-center justify-between shadow-sm dark:shadow-2xl">
        <div className="flex items-center gap-4">
          <div className="bg-slate-100 dark:bg-slate-800 p-1.5 rounded-xl shadow-inner border border-slate-200 dark:border-slate-700/50">
            <CompanyLogo />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-xl font-black tracking-tight uppercase leading-none text-slate-900 dark:text-white">BGFCL GasPro <span className="text-emerald-500">Analytics</span></h1>
            <div className="flex items-center gap-2 mt-1">
              <p className={`text-[10px] font-bold uppercase tracking-widest transition-colors duration-500 ${isSyncing ? 'text-emerald-500' : 'text-slate-400 dark:text-slate-500'}`}>
                {dbStatus === 'online' ? 'Supabase Cloud' : 'Offline Mode'}
              </p>
              <div className={`w-1 h-1 rounded-full transition-colors duration-500 ${isSyncing ? 'bg-emerald-400 animate-ping' : 'bg-slate-300 dark:bg-slate-700'}`}></div>
              <p className="text-[10px] text-slate-400 dark:text-slate-600 font-bold uppercase tracking-widest flex items-center gap-1">
                <RefreshCw size={10} className={`${isSyncing ? 'animate-spin' : 'animate-spin-slow'}`} /> Updated {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
              </p>
            </div>
          </div>
        </div>
        <nav className="flex items-center bg-slate-100 dark:bg-slate-900/50 p-1 rounded-2xl border border-slate-200 dark:border-slate-700/50 shadow-inner">
          <button onClick={() => setView('dashboard')} className={`px-6 py-2.5 rounded-xl flex items-center gap-2 font-bold transition-all ${view === 'dashboard' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-md dark:shadow-lg' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}>
            <LayoutDashboard size={18} /> <span className="hidden md:inline">Dashboard</span>
          </button>

          {view === 'dashboard' && (
            <div className="mx-2 flex items-center gap-1 bg-white/50 dark:bg-slate-800/80 px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-700">
              <button 
                onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx > 0) setSelectedDate(availableDates[idx - 1]); }} 
                disabled={availableDates.indexOf(selectedDate) <= 0} 
                className="p-1.5 text-slate-400 hover:text-slate-600 dark:hover:text-white disabled:opacity-10 transition-colors"
                title="Previous Available Date"
              >
                <ChevronLeft size={20} />
              </button>

              <div className="flex items-center gap-2 px-3 text-slate-700 dark:text-white font-black text-sm border-x border-slate-200 dark:border-slate-700 group">
                <Calendar size={14} className="text-emerald-500 group-hover:scale-110 transition-transform" />
                <input 
                  type="date" 
                  value={selectedDate} 
                  onChange={(e) => setSelectedDate(e.target.value)} 
                  className="bg-transparent border-none focus:ring-0 outline-none p-0 w-32 cursor-pointer dark:color-scheme-dark" 
                />
                {selectedDate === latestDateInSystem && (
                  <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">LATEST</span>
                )}
              </div>

              <button 
                onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx < availableDates.length - 1) setSelectedDate(availableDates[idx + 1]); }} 
                disabled={availableDates.indexOf(selectedDate) >= availableDates.length - 1} 
                className="p-1.5 text-slate-400 hover:text-slate-600 dark:hover:text-white disabled:opacity-10 transition-colors"
                title="Next Available Date"
              >
                <ChevronRight size={20} />
              </button>
            </div>
          )}

          {isAdminAllowed && (
            <button onClick={() => setView('admin')} className={`px-6 py-2.5 rounded-xl flex items-center gap-2 font-bold transition-all ${view === 'admin' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-md dark:shadow-lg' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}>
              <Database size={18} /> <span className="hidden md:inline">Admin</span>
            </button>
          )}
        </nav>
        <div className="hidden lg:flex items-center gap-4">
           {dbStatus === 'online' ? (
              <div className="flex items-center gap-1.5 px-3 py-1 bg-emerald-500/10 text-emerald-600 dark:text-emerald-500 rounded-full border border-emerald-500/20 text-[10px] font-black uppercase">
                <Wifi size={10} className="animate-pulse" /> Live Syncing
              </div>
           ) : (
              <div className="flex items-center gap-1.5 px-3 py-1 bg-amber-500/10 text-amber-600 dark:text-amber-500 rounded-full border border-amber-500/20 text-[10px] font-black uppercase"><AlertTriangle size={10} /> Local Cache</div>
           )}
           <button onClick={toggleTheme} className="p-2.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-xl text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700/50 transition-colors">
            {isDark ? <Sun size={20} /> : <Moon size={20} />}
           </button>
           <button className="p-2.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-xl text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700/50 transition-colors"><Settings size={20} /></button>
        </div>
      </header>
      <main className="flex-1 px-8 py-8 max-w-[2000px] mx-auto w-full">
        {isLoading ? (
          <div className="h-[60vh] flex flex-col items-center justify-center space-y-4 text-slate-400 dark:text-slate-500">
            <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold uppercase tracking-[0.3em] text-sm animate-pulse">Initializing Data Stream...</p>
          </div>
        ) : view === 'dashboard' ? (
          <Dashboard productionData={productionData} personnelData={personnelData} selectedDate={selectedDate} latestDateInSystem={latestDateInSystem} isDarkMode={isDark} />
        ) : (
          <AdminPanel 
            productionData={productionData} 
            personnelData={personnelData}
            onAddProduction={handleAddProduction} 
            onUpdateProduction={handleUpdateProduction}
            onDeleteProduction={handleDeleteProduction}
            onAddPersonnel={handleAddPersonnel}
            onUpdatePersonnel={handleUpdatePersonnel}
            onDeletePersonnel={handleDeletePersonnel}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { ProductionRecord, PersonnelRecord } from '../types.ts';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts.tsx';
import ProductionTable from './ProductionTable.tsx';
import { getAIInsights } from '../services/geminiService.ts';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList, History, Zap, Users, Briefcase, BarChart3 } from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  selectedDate: string;
  latestDateInSystem: string;
  isDarkMode: boolean;
}

const Dashboard: React.FC<Props> = ({ productionData, personnelData, selectedDate, latestDateInSystem, isDarkMode }) => {
  const [insights, setInsights] = useState<string>('Analyzing operational metrics...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  const dayRecords = useMemo(() => productionData.filter(d => d.date === selectedDate), [productionData, selectedDate]);

  const latestPersonnel = useMemo(() => {
    if (!personnelData.length) return null;
    return [...personnelData].sort((a, b) => b.date.localeCompare(a.date))[0];
  }, [personnelData]);

  const totalProduction = useMemo(() => dayRecords.reduce((acc, curr) => acc + curr.amount, 0), [dayRecords]);
  const isLatest = selectedDate === latestDateInSystem;

  const historicalMetrics = useMemo(() => {
    const dailyTotalsMap: Record<string, number> = {};
    productionData.forEach(record => {
      dailyTotalsMap[record.date] = (dailyTotalsMap[record.date] || 0) + record.amount;
    });

    const sortedDates = Object.keys(dailyTotalsMap).sort();
    const latestIdx = sortedDates.indexOf(latestDateInSystem);

    if (latestIdx === -1) return { avg7: 0, avg30: 0 };

    const last7Dates = sortedDates.slice(Math.max(0, latestIdx - 6), latestIdx + 1);
    const last30Dates = sortedDates.slice(Math.max(0, latestIdx - 29), latestIdx + 1);

    const sum7 = last7Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);
    const sum30 = last30Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);

    return {
      avg7: last7Dates.length ? Math.round(sum7 / last7Dates.length) : 0,
      avg30: last30Dates.length ? Math.round(sum30 / last30Dates.length) : 0,
    };
  }, [productionData, latestDateInSystem]);

  useEffect(() => {
    const fetchInsights = async () => {
      if (dayRecords.length === 0) {
        setInsights("No data available for AI analysis on this date.");
        setLoadingInsights(false);
        return;
      }
      setLoadingInsights(true);
      try {
        const text = await getAIInsights(productionData, selectedDate);
        setInsights(text);
      } catch (e) {
        setInsights("AI Insights currently unavailable.");
      } finally {
        setLoadingInsights(false);
      }
    };
    fetchInsights();
  }, [selectedDate, productionData]);

  return (
    <div className="space-y-8 pb-12">
      <div className={`flex items-center gap-4 px-6 py-4 rounded-3xl border shadow-sm transition-all ${!isLatest ? 'bg-amber-500/5 border-amber-500/20 text-amber-600 dark:text-amber-500' : 'bg-emerald-500/5 border-emerald-500/20 text-emerald-600 dark:text-emerald-500'}`}>
        {!isLatest ? (
          <>
            <History size={24} className="animate-in slide-in-from-left duration-300" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-sm">Historical Archive View</span>
              <span className="text-[10px] opacity-70 font-bold uppercase">Viewing finalized records for {selectedDate}</span>
            </div>
          </>
        ) : (
          <>
            <Zap size={24} className="animate-pulse text-emerald-500 dark:text-emerald-400" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-sm">System Status: Live / Latest</span>
              <span className="text-[10px] opacity-70 font-bold uppercase">Displaying the most recent entries in the production database</span>
            </div>
            <span className="ml-auto flex h-3 w-3 rounded-full bg-emerald-500 animate-ping"></span>
          </>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="bg-white dark:bg-slate-800/80 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-center lg:col-span-2 relative overflow-hidden group">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-blue-500/10 dark:bg-blue-500/20 rounded-2xl text-blue-600 dark:text-blue-400"><Activity size={28} /></div>
            <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-sm">Aggregate Daily Field Output ({selectedDate})</span>
          </div>

          <div className="flex flex-col md:flex-row md:items-end gap-6 mb-8">
            <div>
              <div className="text-8xl font-black text-slate-900 dark:text-white tracking-tighter drop-shadow-sm dark:drop-shadow-[0_0_15px_rgba(255,255,255,0.1)]">{totalProduction.toLocaleString()}</div>
              <div className="text-xl text-slate-400 dark:text-slate-500 font-bold uppercase mt-1">Million Cubic Feet (MCF)</div>
            </div>

            <div className="flex flex-col gap-3 pb-2 border-l border-slate-200 dark:border-slate-700 pl-6 mb-1">
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">7-Day Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-2xl font-black text-blue-600 dark:text-blue-400 font-mono">{historicalMetrics.avg7.toLocaleString()}</span>
                  <BarChart3 size={14} className="text-slate-300 dark:text-slate-600" />
                </div>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">30-Day Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-2xl font-black text-slate-700 dark:text-slate-300 font-mono">{historicalMetrics.avg30.toLocaleString()}</span>
                  <TrendingUp size={14} className="text-slate-300 dark:text-slate-600" />
                </div>
              </div>
            </div>
          </div>

          <div className={`mt-auto pt-6 border-t border-slate-100 dark:border-slate-700/50 text-lg flex items-center justify-between font-bold`}>
            <div className={`flex items-center gap-2 ${totalProduction >= historicalMetrics.avg7 ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-600 dark:text-amber-400'}`}>
               <TrendingUp size={24} className={totalProduction < historicalMetrics.avg7 ? 'rotate-180' : ''} /> 
               {totalProduction >= historicalMetrics.avg7 ? 'PERFORMING ABOVE 7D AVG' : 'BELOW 7D OPERATIONAL NORM'}
            </div>
            <div className="text-[10px] text-slate-300 dark:text-slate-600 uppercase font-black tracking-widest hidden sm:block">Real-time Telemetry Active</div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800/80 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-between relative overflow-hidden group">
          <div className="absolute top-4 right-4 flex flex-col items-end gap-1">
            <span className="text-[8px] bg-emerald-500 text-white px-2 py-0.5 rounded-full font-black animate-pulse">LATEST STATUS</span>
            <span className="text-[7px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-tighter italic">Ref: {latestPersonnel?.date || 'N/A'}</span>
          </div>

          <div>
            <div className="flex items-center gap-3 mb-8">
              <Users size={24} className="text-slate-400 dark:text-slate-500" />
              <h3 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest">Company Workforce</h3>
            </div>
            <div className="space-y-8">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-amber-500/10 dark:bg-amber-500/20 rounded-xl text-amber-600 dark:text-amber-400 group-hover:scale-110 transition-transform"><Briefcase size={24} /></div>
                  <span className="text-slate-600 dark:text-slate-300 font-bold text-lg uppercase">Officers</span>
                </div>
                <div className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">{latestPersonnel?.officers.toLocaleString() || "---"}</div>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-emerald-500/10 dark:bg-emerald-500/20 rounded-xl text-emerald-600 dark:text-emerald-400 group-hover:scale-110 transition-transform"><Users size={24} /></div>
                  <span className="text-slate-600 dark:text-slate-300 font-bold text-lg uppercase">Employees</span>
                </div>
                <div className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">{latestPersonnel?.employees.toLocaleString() || "---"}</div>
              </div>
            </div>
          </div>
          <div className="pt-8 border-t border-slate-100 dark:border-slate-700/50">
            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-[0.3em]">Current Personnel Distribution</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="bg-white dark:bg-slate-900/60 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm lg:col-span-2">
          <div className="flex items-center gap-3 mb-6">
            <LayoutList size={24} className="text-emerald-500" />
            <h3 className="text-lg font-black text-slate-900 dark:text-white uppercase tracking-widest">Field wise Daily Breakdown</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {dayRecords.map((record) => (
              <div key={record.field} className="p-6 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-slate-300 dark:hover:border-slate-700 transition-all flex items-center justify-between">
                <div className="text-slate-800 dark:text-slate-100 font-black text-xl uppercase tracking-tight">{record.field}</div>
                <div className="text-emerald-600 dark:text-emerald-400 font-black text-2xl font-mono">{record.amount.toLocaleString()} <span className="text-[10px] text-slate-400 dark:text-slate-600 uppercase font-sans">MCF</span></div>
              </div>
            ))}
          </div>
          {dayRecords.length === 0 && <div className="text-slate-400 dark:text-slate-500 text-center py-20 font-bold uppercase tracking-widest border border-dashed border-slate-200 dark:border-slate-800 rounded-3xl">No production logs found for this date.</div>}
        </div>
        <div className="bg-white dark:bg-slate-800/80 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm"><FieldDistributionChart data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} /></div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
        <div className="bg-white dark:bg-slate-800/50 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg"><HistoricalTrendChart data={productionData} centerDate={selectedDate} isDarkMode={isDarkMode} /></div>
        <div className="bg-white dark:bg-slate-800/50 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg"><FieldComparisonBar data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} /></div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="bg-white dark:bg-slate-800/80 p-10 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl lg:col-span-2 relative overflow-hidden">
          <div className="flex items-center gap-4 mb-8">
            <div className="p-3 bg-purple-500/10 dark:bg-purple-500/20 rounded-xl text-purple-600 dark:text-purple-400"><Sparkles size={28} /></div>
            <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Executive Intelligence</h2>
          </div>
          <div className={`text-2xl text-slate-700 dark:text-slate-200 leading-relaxed font-medium transition-opacity duration-700 max-w-4xl ${loadingInsights ? 'opacity-40 animate-pulse' : 'opacity-100'}`}>{insights}</div>
          <div className="absolute -bottom-20 -right-20 opacity-5 text-purple-200 dark:text-purple-200 pointer-events-none"><Sparkles size={300} /></div>
        </div>
        <div className="lg:col-span-1 bg-white dark:bg-slate-800/50 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg flex flex-col">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-3"><Clock className="text-slate-400 dark:text-slate-600" /> Activity Log</h3>
            <span className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Audit Trail</span>
          </div>
          <div className="flex-1 overflow-y-auto max-h-[400px]"><ProductionTable data={productionData} /></div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend, AreaChart, Area
} from 'recharts';
import { ProductionRecord } from '../types.ts';

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

interface BaseProps {
  data: ProductionRecord[];
  isDarkMode: boolean;
}

interface TargetedProps extends BaseProps {
  targetDate: string;
}

interface TrendProps extends BaseProps {
  centerDate: string;
}

const getTooltipStyle = (isDarkMode: boolean) => ({
  backgroundColor: isDarkMode ? '#1e293b' : '#ffffff',
  border: isDarkMode ? 'none' : '1px solid #e2e8f0',
  borderRadius: '8px',
  color: isDarkMode ? '#f8fafc' : '#0f172a',
  boxShadow: isDarkMode ? 'none' : '0 10px 15px -3px rgba(0, 0, 0, 0.1)',
});

const getGridColor = (isDarkMode: boolean) => (isDarkMode ? '#334155' : '#e2e8f0');
const getTextColor = (isDarkMode: boolean) => (isDarkMode ? '#94a3b8' : '#64748b');

export const FieldDistributionChart: React.FC<TargetedProps> = ({ data, targetDate, isDarkMode }) => {
  const chartData = useMemo(() => {
    return data
      .filter(d => d.date === targetDate)
      .map(d => ({
        name: d.field,
        value: d.amount
      }));
  }, [data, targetDate]);

  return (
    <div className="h-[280px] w-full flex flex-col">
      <div className="flex items-center justify-between mb-2">
        <h3 className="text-sm font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Daily Production Share %</h3>
        <span className="text-[10px] bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded text-slate-600 dark:text-slate-300 font-bold uppercase tracking-tighter">{targetDate}</span>
      </div>
      <div className="flex-1">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie
              data={chartData}
              cx="50%"
              cy="50%"
              innerRadius={55}
              outerRadius={80}
              paddingAngle={5}
              dataKey="value"
              label={({ percent }) => `${(percent * 100).toFixed(0)}%`}
              labelLine={false}
              stroke={isDarkMode ? '#1e293b' : '#ffffff'}
            >
              {chartData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
              ))}
            </Pie>
            <Tooltip contentStyle={getTooltipStyle(isDarkMode)} itemStyle={{ color: isDarkMode ? '#f8fafc' : '#0f172a' }} />
            <Legend 
              iconType="circle" 
              layout="horizontal" 
              verticalAlign="bottom" 
              align="center"
              wrapperStyle={{ fontSize: '10px', paddingTop: '10px', color: getTextColor(isDarkMode) }} 
            />
          </PieChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export const HistoricalTrendChart: React.FC<TrendProps> = ({ data, centerDate, isDarkMode }) => {
  const chartData = useMemo(() => {
    const dates: string[] = Array.from(new Set<string>(data.map(d => d.date))).sort();
    const fields: string[] = Array.from(new Set<string>(data.map(d => d.field)));

    const targetIdx = dates.indexOf(centerDate);
    const startIdx = Math.max(0, targetIdx - 6);
    const windowDates = dates.slice(startIdx, targetIdx + 1);

    return windowDates.map(date => {
      const entry: any = { date };
      fields.forEach(field => {
        const record = data.find(r => r.date === date && r.field === field);
        entry[field] = record ? record.amount : 0;
      });
      return entry;
    });
  }, [data, centerDate]);

  const fields = useMemo(() => Array.from(new Set<string>(data.map(d => d.field))), [data]);

  return (
    <div className="h-[400px] w-full">
      <h3 className="text-xl font-bold mb-4 text-slate-900 dark:text-slate-100 uppercase tracking-tight">Window Trend (7D Peak)</h3>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={chartData}>
          <defs>
            {fields.map((f, i) => (
              <linearGradient key={`grad-${f}`} id={`color-${i}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={COLORS[i % COLORS.length]} stopOpacity={0.3}/>
                <stop offset="95%" stopColor={COLORS[i % COLORS.length]} stopOpacity={0}/>
              </linearGradient>
            ))}
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke={getGridColor(isDarkMode)} vertical={false} />
          <XAxis dataKey="date" stroke={getTextColor(isDarkMode)} fontSize={10} tickLine={false} axisLine={false} />
          <YAxis stroke={getTextColor(isDarkMode)} fontSize={10} tickLine={false} axisLine={false} />
          <Tooltip contentStyle={getTooltipStyle(isDarkMode)} itemStyle={{ color: isDarkMode ? '#f8fafc' : '#0f172a' }} />
          <Legend verticalAlign="top" height={36} iconType="circle" wrapperStyle={{ fontSize: '12px', color: getTextColor(isDarkMode) }} />
          {fields.map((field, index) => (
            <Area
              key={field}
              type="monotone"
              dataKey={field}
              stroke={COLORS[index % COLORS.length]}
              fillOpacity={1}
              fill={`url(#color-${index})`}
              strokeWidth={3}
              activeDot={{ r: 8 }}
            />
          ))}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export const FieldComparisonBar: React.FC<TargetedProps> = ({ data, targetDate, isDarkMode }) => {
  const dayData = useMemo(() => data.filter(d => d.date === targetDate), [data, targetDate]);

  return (
    <div className="h-[400px] w-full">
      <h3 className="text-xl font-bold mb-4 text-slate-900 dark:text-slate-100 uppercase tracking-tight">Volume Benchmarking</h3>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={dayData}>
          <CartesianGrid strokeDasharray="3 3" stroke={getGridColor(isDarkMode)} vertical={false} />
          <XAxis dataKey="field" stroke={getTextColor(isDarkMode)} fontSize={10} />
          <YAxis stroke={getTextColor(isDarkMode)} fontSize={10} />
          <Tooltip 
            cursor={{ fill: isDarkMode ? '#334155' : '#f1f5f9', opacity: 0.4 }}
            contentStyle={getTooltipStyle(isDarkMode)} 
            itemStyle={{ color: isDarkMode ? '#f8fafc' : '#0f172a' }}
          />
          <Bar dataKey="amount" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40}>
            {dayData.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { FIELDS } from '../constants.ts';
import { ProductionRecord, PersonnelRecord } from '../types.ts';
import { 
  PlusCircle, Trash2, Database, AlertCircle, Loader2, XCircle, 
  Edit3, ChevronLeft, ChevronRight, Save, X, Users, Briefcase, LayoutGrid, UserCheck,
  Fuel, Calendar
} from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  onAddProduction: (record: Omit<ProductionRecord, 'id'>) => Promise<void>;
  onUpdateProduction: (id: string, record: Omit<ProductionRecord, 'id'>) => Promise<void>;
  onDeleteProduction: (id: string) => Promise<void>;
  onAddPersonnel: (record: Omit<PersonnelRecord, 'id'>) => Promise<void>;
  onUpdatePersonnel: (id: string, record: Omit<PersonnelRecord, 'id'>) => Promise<void>;
  onDeletePersonnel: (id: string) => Promise<void>;
}

const RECORDS_PER_PAGE = 8;

const AdminPanel: React.FC<Props> = ({ 
  productionData, personnelData,
  onAddProduction, onUpdateProduction, onDeleteProduction,
  onAddPersonnel, onUpdatePersonnel, onDeletePersonnel
}) => {
  const [activeTab, setActiveTab] = useState<'production' | 'personnel'>('production');

  // Production Form State
  const [field, setField] = useState(FIELDS[0].name);
  const [amount, setAmount] = useState<string>('');
  const [prodDate, setProdDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [editingProdId, setEditingProdId] = useState<string | null>(null);

  // Personnel Form State
  const [persDate, setPersDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [officers, setOfficers] = useState<string>('');
  const [employees, setEmployees] = useState<string>('');
  const [editingPersId, setEditingPersId] = useState<string | null>(null);

  // UI State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [loadingActionId, setLoadingActionId] = useState<string | null>(null);
  const [validationError, setValidationError] = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState(1);

  const handleProductionSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setValidationError(null);
    const numAmount = Number(amount);
    if (!amount || isNaN(numAmount)) { setValidationError("Enter numeric production amount."); return; }
    if (productionData.some(r => r.field === field && r.date === prodDate && r.id !== editingProdId)) {
      setValidationError(`Entry for ${field} on ${prodDate} already exists.`); return;
    }
    setIsSubmitting(true);
    try {
      if (editingProdId) await onUpdateProduction(editingProdId, { field, amount: numAmount, date: prodDate });
      else await onAddProduction({ field, amount: numAmount, date: prodDate });
      setAmount(''); setEditingProdId(null);
    } catch { setValidationError("Database error occurred."); } finally { setIsSubmitting(false); }
  };

  const handlePersonnelSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setValidationError(null);
    const numOff = Number(officers);
    const numEmp = Number(employees);
    if (isNaN(numOff) || isNaN(numEmp)) { setValidationError("Enter valid personnel counts."); return; }
    if (personnelData.some(p => p.date === persDate && p.id !== editingPersId)) {
       setValidationError(`Personnel data for ${persDate} already exists.`); return;
    }
    setIsSubmitting(true);
    try {
      if (editingPersId) await onUpdatePersonnel(editingPersId, { date: persDate, officers: numOff, employees: numEmp });
      else await onAddPersonnel({ date: persDate, officers: numOff, employees: numEmp });
      setOfficers(''); setEmployees(''); setEditingPersId(null);
    } catch { setValidationError("Personnel database update failed."); } finally { setIsSubmitting(false); }
  };

  const startEditProd = (record: ProductionRecord) => {
    setField(record.field); setAmount(record.amount.toString()); setProdDate(record.date);
    setEditingProdId(record.id); setValidationError(null); setActiveTab('production');
  };

  const startEditPers = (record: PersonnelRecord) => {
    setPersDate(record.date); setOfficers(record.officers.toString()); setEmployees(record.employees.toString());
    setEditingPersId(record.id); setValidationError(null); setActiveTab('personnel');
  };

  const sortedProduction = useMemo(() => [...productionData].sort((a,b) => b.date.localeCompare(a.date)), [productionData]);
  const sortedPersonnel = useMemo(() => [...personnelData].sort((a,b) => b.date.localeCompare(a.date)), [personnelData]);

  const pagedData = activeTab === 'production' 
    ? sortedProduction.slice((currentPage-1)*RECORDS_PER_PAGE, currentPage*RECORDS_PER_PAGE)
    : sortedPersonnel.slice((currentPage-1)*RECORDS_PER_PAGE, currentPage*RECORDS_PER_PAGE);

  const totalPages = Math.ceil((activeTab === 'production' ? productionData.length : personnelData.length) / RECORDS_PER_PAGE);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
      <div className="lg:col-span-1 space-y-8">
        <div className="flex bg-white dark:bg-slate-900 p-1.5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <button onClick={() => { setActiveTab('production'); setValidationError(null); }} className={`flex-1 py-3 px-4 rounded-xl flex items-center justify-center gap-2 font-bold text-sm transition-all ${activeTab === 'production' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}>
            <LayoutGrid size={18} /> Production
          </button>
          <button onClick={() => { setActiveTab('personnel'); setValidationError(null); }} className={`flex-1 py-3 px-4 rounded-xl flex items-center justify-center gap-2 font-bold text-sm transition-all ${activeTab === 'personnel' ? 'bg-amber-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}>
            <UserCheck size={18} /> Personnel
          </button>
        </div>

        <div className={`bg-white dark:bg-slate-800 p-8 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl transition-all duration-300 ${activeTab === 'personnel' ? 'ring-2 ring-amber-500/20' : 'ring-2 ring-emerald-500/20'}`}>
          <h2 className="text-2xl font-black mb-6 flex items-center gap-3 text-slate-900 dark:text-white">
            {activeTab === 'production' ? <><Database className="text-emerald-500" /> Field Logging</> : <><Users className="text-amber-500" /> Census Update</>}
          </h2>
          {validationError && <div className="mb-6 p-4 bg-red-500/10 border border-red-500/30 rounded-xl flex items-center gap-3 text-red-600 dark:text-red-400 text-sm font-bold"><XCircle size={18} /> {validationError}</div>}

          {activeTab === 'production' ? (
            <form onSubmit={handleProductionSubmit} className="space-y-6">
              <div><label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Field Selection</label><select value={field} onChange={(e) => setField(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl p-4 text-slate-900 dark:text-slate-100 font-bold outline-none focus:ring-2 focus:ring-emerald-500">{FIELDS.map(f => <option key={f.id} value={f.name}>{f.name}</option>)}</select></div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Volume (MCF)</label><input type="number" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl p-4 text-slate-900 dark:text-slate-100 font-mono font-bold outline-none focus:ring-2 focus:ring-emerald-500" required /></div>
                <div><label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Log Date</label><input type="date" value={prodDate} onChange={(e) => setProdDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl p-4 text-slate-900 dark:text-slate-100 font-bold outline-none focus:ring-2 focus:ring-emerald-500" required /></div>
              </div>
              <button type="submit" disabled={isSubmitting} className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-2xl text-white font-black uppercase tracking-widest shadow-xl shadow-emerald-900/20 flex items-center justify-center gap-3">{isSubmitting ? <Loader2 className="animate-spin" /> : editingProdId ? <Save /> : <PlusCircle />} {editingProdId ? "Apply Update" : "Push Production Log"}</button>
              {editingProdId && <button type="button" onClick={() => setEditingProdId(null)} className="w-full py-4 text-slate-500 dark:text-slate-400 font-bold uppercase text-xs tracking-widest border border-slate-200 dark:border-slate-700 rounded-2xl">Cancel Edit</button>}
            </form>
          ) : (
            <form onSubmit={handlePersonnelSubmit} className="space-y-6">
              <div><label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Census Date</label><input type="date" value={persDate} onChange={(e) => setPersDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl p-4 text-slate-900 dark:text-slate-100 font-bold outline-none focus:ring-2 focus:ring-amber-500" required /></div>
              <div className="grid grid-cols-2 gap-4">
                <div className="relative"><label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Officers</label><Briefcase size={16} className="absolute left-4 top-[54px] text-slate-400 dark:text-slate-600" /><input type="number" value={officers} onChange={(e) => setOfficers(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl p-4 pl-12 text-slate-900 dark:text-slate-100 font-mono font-bold outline-none focus:ring-2 focus:ring-amber-500" required /></div>
                <div className="relative"><label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Employees</label><Users size={16} className="absolute left-4 top-[54px] text-slate-400 dark:text-slate-600" /><input type="number" value={employees} onChange={(e) => setEmployees(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl p-4 pl-12 text-slate-900 dark:text-slate-100 font-mono font-bold outline-none focus:ring-2 focus:ring-amber-500" required /></div>
              </div>
              <button type="submit" disabled={isSubmitting} className="w-full bg-amber-600 hover:bg-amber-500 py-5 rounded-2xl text-white font-black uppercase tracking-widest shadow-xl shadow-amber-900/20 flex items-center justify-center gap-3">{isSubmitting ? <Loader2 className="animate-spin" /> : editingPersId ? <Save /> : <UserCheck />} {editingPersId ? "Update Census" : "Submit Global Census"}</button>
              {editingPersId && <button type="button" onClick={() => setEditingPersId(null)} className="w-full py-4 text-slate-500 dark:text-slate-400 font-bold uppercase text-xs tracking-widest border border-slate-200 dark:border-slate-700 rounded-2xl">Cancel Edit</button>}
            </form>
          )}
        </div>
      </div>

      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white dark:bg-slate-800 p-10 rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl h-full flex flex-col min-h-[700px]">
          <div className="flex items-center justify-between mb-8">
            <div><h2 className="text-3xl font-black text-slate-900 dark:text-white">{activeTab === 'production' ? "Production Archives" : "Personnel Archives"}</h2><p className="text-xs text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest mt-2">{activeTab === 'production' ? productionData.length : personnelData.length} records in system</p></div>
            <div className="bg-slate-50 dark:bg-slate-900 px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-700 text-[10px] font-black text-slate-400 dark:text-slate-500">PAGE {currentPage} / {totalPages || 1}</div>
          </div>

          <div className="flex-1 space-y-4">
            {activeTab === 'production' ? (
               (pagedData as ProductionRecord[]).map(record => (
                 <div key={record.id} className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-700/50 group hover:border-emerald-500/30 transition-all shadow-sm">
                    <div className="flex items-center gap-6">
                      <div className="bg-white dark:bg-slate-800 p-3 rounded-xl text-slate-400 dark:text-slate-500 shadow-sm border border-slate-100 dark:border-slate-700"><Fuel size={24} /></div>
                      <div><div className="font-black text-lg text-slate-800 dark:text-slate-100">{record.field}</div><div className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest mt-1 flex items-center gap-2"><Calendar size={12} /> {record.date}</div></div>
                    </div>
                    <div className="flex items-center gap-8">
                      <div className="text-right"><div className="text-2xl font-black text-emerald-600 dark:text-emerald-400 font-mono">{record.amount.toLocaleString()}</div><div className="text-[10px] font-black text-slate-400 dark:text-slate-600 uppercase">MCF Volume</div></div>
                      <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => startEditProd(record)} className="p-2.5 text-slate-400 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-emerald-400/10 rounded-lg"><Edit3 size={18} /></button>
                        <button onClick={async () => { if(confirm("Delete record?")) { setLoadingActionId(record.id); await onDeleteProduction(record.id); setLoadingActionId(null); } }} className="p-2.5 text-slate-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-400/10 rounded-lg">{loadingActionId === record.id ? <Loader2 className="animate-spin" size={18} /> : <Trash2 size={18} />}</button>
                      </div>
                    </div>
                 </div>
               ))
            ) : (
              (pagedData as PersonnelRecord[]).map(record => (
                <div key={record.id} className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-700/50 group hover:border-amber-500/30 transition-all shadow-sm">
                   <div className="flex items-center gap-6">
                     <div className="bg-white dark:bg-slate-800 p-3 rounded-xl text-slate-400 dark:text-slate-500 shadow-sm border border-slate-100 dark:border-slate-700"><UserCheck size={24} /></div>
                     <div><div className="font-black text-lg text-slate-800 dark:text-slate-100">Global Census</div><div className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest mt-1 flex items-center gap-2"><Calendar size={12} /> {record.date}</div></div>
                   </div>
                   <div className="flex items-center gap-10">
                     <div className="flex items-center gap-6">
                        <div className="text-right"><div className="text-xl font-black text-amber-600 dark:text-amber-500 font-mono">{record.officers}</div><div className="text-[10px] font-black text-slate-400 dark:text-slate-600 uppercase">Officers</div></div>
                        <div className="text-right"><div className="text-xl font-black text-emerald-600 dark:text-emerald-400 font-mono">{record.employees}</div><div className="text-[10px] font-black text-slate-400 dark:text-slate-600 uppercase">Employees</div></div>
                     </div>
                     <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                       <button onClick={() => startEditPers(record)} className="p-2.5 text-slate-400 hover:text-amber-600 dark:hover:text-amber-400 hover:bg-amber-400/10 rounded-lg"><Edit3 size={18} /></button>
                       <button onClick={async () => { if(confirm("Delete census record?")) { setLoadingActionId(record.id); await onDeletePersonnel(record.id); setLoadingActionId(null); } }} className="p-2.5 text-slate-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-400/10 rounded-lg">{loadingActionId === record.id ? <Loader2 className="animate-spin" size={18} /> : <Trash2 size={18} />}</button>
                     </div>
                   </div>
                </div>
              ))
            )}
            {pagedData.length === 0 && <div className="text-center py-40 text-slate-400 dark:text-slate-600 flex flex-col items-center gap-4"><AlertCircle size={48} className="opacity-10" /><p className="font-black uppercase tracking-widest">No matching records found.</p></div>}
          </div>

          {totalPages > 1 && (
            <div className="mt-auto pt-10 flex items-center justify-between border-t border-slate-100 dark:border-slate-700/50">
               <button onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage===1} className="flex items-center gap-2 px-6 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white disabled:opacity-20 font-black uppercase text-xs tracking-widest transition-all shadow-sm"><ChevronLeft size={16} /> Previous</button>
               <div className="flex gap-2">
                 {Array.from({length: totalPages}, (_,i) => i+1).map(p => (
                   <button key={p} onClick={() => setCurrentPage(p)} className={`w-12 h-12 rounded-xl border font-black text-sm transition-all ${currentPage===p ? 'bg-slate-900 dark:bg-slate-200 text-white dark:text-slate-900 border-slate-900 dark:border-white shadow-xl' : 'bg-white dark:bg-slate-900 text-slate-400 dark:text-slate-500 border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-500'}`}>{p}</button>
                 ))}
               </div>
               <button onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage===totalPages} className="flex items-center gap-2 px-6 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white disabled:opacity-20 font-black uppercase text-xs tracking-widest transition-all shadow-sm">Next <ChevronRight size={16} /></button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

