import AdminPanel from './components/AdminPanel.tsx';
import { dbService } from './services/dbService.ts';
import { 
  Monitor, Settings, LayoutDashboard, Database, Fuel, 
  Lock, ChevronLeft, ChevronRight, 
  Calendar, Server, AlertTriangle, Clock, RefreshCw, Wifi, Moon, Sun
} from 'lucide-react';

const CompanyLogo = () => (
  <svg className="w-6 h-6 md:w-8 md:h-8 drop-shadow-lg" viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg">
    <path d="M50 5 C30 5 15 35 15 60 C15 85 30 95 50 95 C70 95 85 85 85 60 C85 35 70 5 50 5 Z" fill="#FBBF24" />
    <path d="M42 45 L42 85 M42 45 Q55 45 55 55 Q55 65 42 65 M42 65 Q58 65 58 75 Q58 85 42 85" fill="none" stroke="#EF4444" stroke-width="8" stroke-linecap="round" stroke-linejoin="round" />
    <path d="M65 45 Q50 45 50 65 Q50 85 65 85 L65 75" fill="none" stroke="#10B981" stroke-width="8" stroke-linecap="round" />
  </svg>
);

const App: React.FC = () => {
  const [productionData, setProductionData] = useState<ProductionRecord[]>([]);
  const [personnelData, setPersonnelData] = useState<PersonnelRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');
  const [isAdminAllowed, setIsAdminAllowed] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'online' | 'offline' | 'mock'>('mock');
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);
  const [isDark, setIsDark] = useState(document.documentElement.classList.contains('dark'));
  const isInitialLoad = useRef(true);

  const toggleTheme = () => {
    if (isDark) {
      document.documentElement.classList.remove('dark');
      localStorage.theme = 'light';
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.theme = 'dark';
      setIsDark(true);
    }
  };

  const availableDates = useMemo(() => {
    const dates = new Set<string>();
    productionData.forEach(r => dates.add(r.date));
    return Array.from(dates).sort();
  }, [productionData]);

  const latestDateInSystem = useMemo(() => 
    availableDates.length > 0 ? availableDates[availableDates.length - 1] : new Date().toISOString().split('T')[0],
    [availableDates]
  );

  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const fetchData = async () => {
    if (!dbService.isConfigured()) {
      const savedProd = localStorage.getItem('gaspro_production_data');
      const savedPers = localStorage.getItem('gaspro_personnel_data');
      setProductionData(savedProd ? JSON.parse(savedProd) : INITIAL_MOCK_DATA);
      setPersonnelData(savedPers ? JSON.parse(savedPers) : INITIAL_PERSONNEL_DATA);
      setDbStatus('mock');
      return;
    }
    try {
      const [records, personnel] = await Promise.all([
        dbService.getRecords(),
        dbService.getPersonnelRecords()
      ]);
      setProductionData(records);
      setPersonnelData(personnel);
      setDbStatus('online');
      setLastUpdated(new Date());
    } catch (err) {
      console.error("Fetch error:", err);
      setDbStatus('offline');
    }
  };

  useEffect(() => {
    if (dbStatus !== 'online') return;

    const channel = dbService.subscribeToChanges((payload) => {
      setIsSyncing(true);
      const { type, eventType, new: newRecord, old: oldRecord } = payload;

      if (type === 'production') {
        setProductionData(prev => {
          if (eventType === 'INSERT') return [newRecord, ...prev];
          if (eventType === 'UPDATE') return prev.map(r => r.id === newRecord.id ? newRecord : r);
          if (eventType === 'DELETE') return prev.filter(r => r.id !== oldRecord.id);
          return prev;
        });
      } else if (type === 'personnel') {
        setPersonnelData(prev => {
          if (eventType === 'INSERT') return [newRecord, ...prev];
          if (eventType === 'UPDATE') return prev.map(r => r.id === newRecord.id ? newRecord : r);
          if (eventType === 'DELETE') return prev.filter(r => r.id !== oldRecord.id);
          return prev;
        });
      }

      setLastUpdated(new Date());
      setTimeout(() => setIsSyncing(false), 1500);
    });

    return () => {
      if (channel) channel.unsubscribe();
    };
  }, [dbStatus]);

  useEffect(() => {
    const initialize = async () => {
      setIsLoading(true);
      await fetchData();

      try {
        const response = await fetch('https://api.ipify.org?format=json');
        const result = await response.json();
        setIsAdminAllowed(ALLOWED_ADMIN_IPS.includes(result.ip) || window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');
      } catch {
        setIsAdminAllowed(window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');
      }
      setIsLoading(false);
    };
    initialize();
  }, []);

  useEffect(() => {
    if (!isLoading && availableDates.length > 0) {
      if (isInitialLoad.current || !availableDates.includes(selectedDate)) {
        setSelectedDate(latestDateInSystem);
        isInitialLoad.current = false;
      }
    }
  }, [availableDates, latestDateInSystem, isLoading, selectedDate]);

  useEffect(() => {
    if (dbStatus === 'mock') {
      localStorage.setItem('gaspro_production_data', JSON.stringify(productionData));
      localStorage.setItem('gaspro_personnel_data', JSON.stringify(personnelData));
      setLastUpdated(new Date());
    }
  }, [productionData, personnelData, dbStatus]);

  const handleAddProduction = async (record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.addRecord(record);
    } else {
      setProductionData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
    }
  };

  const handleUpdateProduction = async (id: string, record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.updateRecord(id, record);
    } else {
      setProductionData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
    }
  };

  const handleDeleteProduction = async (id: string) => {
    if (dbStatus === 'online') {
      await dbService.deleteRecord(id);
    } else {
      setProductionData(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleAddPersonnel = async (record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.addPersonnelRecord(record);
    } else {
      setPersonnelData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
    }
  };

  const handleUpdatePersonnel = async (id: string, record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') {
      await dbService.updatePersonnelRecord(id, record);
    } else {
      setPersonnelData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
    }
  };

  const handleDeletePersonnel = async (id: string) => {
    if (dbStatus === 'online') {
      await dbService.deletePersonnelRecord(id);
    } else {
      setPersonnelData(prev => prev.filter(r => r.id !== id));
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-[#0f172a] text-slate-900 dark:text-slate-100 transition-colors duration-300">
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-slate-900/90 border-b border-slate-200 dark:border-slate-800 backdrop-blur-md px-4 md:px-8 py-3 md:py-4 flex flex-col sm:flex-row items-center justify-between gap-4 shadow-sm dark:shadow-2xl">
        <div className="flex items-center justify-between w-full sm:w-auto gap-4">
          <div className="flex items-center gap-2 md:gap-4">
            <div className="bg-slate-100 dark:bg-slate-800 p-1 md:p-1.5 rounded-lg md:rounded-xl shadow-inner border border-slate-200 dark:border-slate-700/50">
              <CompanyLogo />
            </div>
            <div>
              <h1 className="text-sm md:text-xl font-black tracking-tight uppercase leading-none text-slate-900 dark:text-white">BGFCL GasPro <span className="text-emerald-500">Analytics</span></h1>
              <p className="text-[8px] md:text-[10px] text-slate-400 dark:text-slate-600 font-bold uppercase tracking-widest mt-0.5 md:mt-1 flex items-center gap-1">
                <RefreshCw size={8} className={`${isSyncing ? 'animate-spin' : 'animate-spin-slow'}`} /> Updated {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </p>
            </div>
          </div>
          <div className="sm:hidden flex items-center gap-2">
             <button onClick={toggleTheme} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-lg text-slate-500 dark:text-slate-400">
              {isDark ? <Sun size={18} /> : <Moon size={18} />}
             </button>
          </div>
        </div>

        <nav className="flex items-center bg-slate-100 dark:bg-slate-900/50 p-1 rounded-xl md:rounded-2xl border border-slate-200 dark:border-slate-700/50 shadow-inner w-full sm:w-auto justify-center overflow-x-auto">
          <button onClick={() => setView('dashboard')} className={`px-4 md:px-6 py-2 md:py-2.5 rounded-lg md:rounded-xl flex items-center gap-2 font-bold text-xs md:text-sm transition-all whitespace-nowrap ${view === 'dashboard' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>
            <LayoutDashboard size={16} /> Dashboard
          </button>

          {view === 'dashboard' && (
            <div className="mx-1 md:mx-2 flex items-center gap-1 bg-white/50 dark:bg-slate-800/80 px-1 md:px-2 py-0.5 md:py-1 rounded-lg border border-slate-200 dark:border-slate-700">
              <button 
                onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx > 0) setSelectedDate(availableDates[idx - 1]); }} 
                disabled={availableDates.indexOf(selectedDate) <= 0} 
                className="p-1 text-slate-400 hover:text-slate-600 dark:hover:text-white disabled:opacity-10"
              >
                <ChevronLeft size={18} />
              </button>

              <div className="flex items-center gap-1 md:gap-2 px-1 md:px-3 text-slate-700 dark:text-white font-black text-[10px] md:text-sm border-x border-slate-200 dark:border-slate-700 group">
                <input 
                  type="date" 
                  value={selectedDate} 
                  onChange={(e) => setSelectedDate(e.target.value)} 
                  className="bg-transparent border-none focus:ring-0 outline-none p-0 w-24 md:w-32 cursor-pointer dark:color-scheme-dark" 
                />
              </div>

              <button 
                onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx < availableDates.length - 1) setSelectedDate(availableDates[idx + 1]); }} 
                disabled={availableDates.indexOf(selectedDate) >= availableDates.length - 1} 
                className="p-1 text-slate-400 hover:text-slate-600 dark:hover:text-white disabled:opacity-10"
              >
                <ChevronRight size={18} />
              </button>
            </div>
          )}

          {isAdminAllowed && (
            <button onClick={() => setView('admin')} className={`px-4 md:px-6 py-2 md:py-2.5 rounded-lg md:rounded-xl flex items-center gap-2 font-bold text-xs md:text-sm transition-all whitespace-nowrap ${view === 'admin' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>
              <Database size={16} /> Admin
            </button>
          )}
        </nav>

        <div className="hidden sm:flex items-center gap-2 md:gap-4">
           {dbStatus === 'online' ? (
              <div className="flex items-center gap-1.5 px-3 py-1 bg-emerald-500/10 text-emerald-600 dark:text-emerald-500 rounded-full border border-emerald-500/20 text-[10px] font-black uppercase whitespace-nowrap">
                <Wifi size={10} className="animate-pulse" /> Live
              </div>
           ) : (
              <div className="flex items-center gap-1.5 px-3 py-1 bg-amber-500/10 text-amber-600 dark:text-amber-500 rounded-full border border-amber-500/20 text-[10px] font-black uppercase whitespace-nowrap"><AlertTriangle size={10} /> Local</div>
           )}
           <button onClick={toggleTheme} className="p-2 md:p-2.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 rounded-lg md:rounded-xl text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700/50 transition-colors">
            {isDark ? <Sun size={18} /> : <Moon size={18} />}
           </button>
           <button className="hidden md:block p-2.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 rounded-xl text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700/50"><Settings size={20} /></button>
        </div>
      </header>

      <main className="flex-1 px-4 md:px-8 py-6 md:py-8 max-w-[2000px] mx-auto w-full">
        {isLoading ? (
          <div className="h-[60vh] flex flex-col items-center justify-center space-y-4 text-slate-400 dark:text-slate-500">
            <div className="w-10 h-10 md:w-12 md:h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold uppercase tracking-[0.2em] md:tracking-[0.3em] text-xs md:text-sm animate-pulse">Initializing Data Stream...</p>
          </div>
        ) : view === 'dashboard' ? (
          <Dashboard productionData={productionData} personnelData={personnelData} selectedDate={selectedDate} latestDateInSystem={latestDateInSystem} isDarkMode={isDark} />
        ) : (
          <AdminPanel 
            productionData={productionData} 
            personnelData={personnelData}
            onAddProduction={handleAddProduction} 
            onUpdateProduction={handleUpdateProduction}
            onDeleteProduction={handleDeleteProduction}
            onAddPersonnel={handleAddPersonnel}
            onUpdatePersonnel={handleUpdatePersonnel}
            onDeletePersonnel={handleDeletePersonnel}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { ProductionRecord, PersonnelRecord } from '../types.ts';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts.tsx';
import ProductionTable from './ProductionTable.tsx';
import { getAIInsights } from '../services/geminiService.ts';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList, History, Zap, Users, Briefcase, BarChart3 } from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  selectedDate: string;
  latestDateInSystem: string;
  isDarkMode: boolean;
}

const Dashboard: React.FC<Props> = ({ productionData, personnelData, selectedDate, latestDateInSystem, isDarkMode }) => {
  const [insights, setInsights] = useState<string>('Analyzing operational metrics...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  const dayRecords = useMemo(() => productionData.filter(d => d.date === selectedDate), [productionData, selectedDate]);

  const latestPersonnel = useMemo(() => {
    if (!personnelData.length) return null;
    return [...personnelData].sort((a, b) => b.date.localeCompare(a.date))[0];
  }, [personnelData]);

  const totalProduction = useMemo(() => dayRecords.reduce((acc, curr) => acc + curr.amount, 0), [dayRecords]);
  const isLatest = selectedDate === latestDateInSystem;

  const historicalMetrics = useMemo(() => {
    const dailyTotalsMap: Record<string, number> = {};
    productionData.forEach(record => {
      dailyTotalsMap[record.date] = (dailyTotalsMap[record.date] || 0) + record.amount;
    });

    const sortedDates = Object.keys(dailyTotalsMap).sort();
    const latestIdx = sortedDates.indexOf(latestDateInSystem);

    if (latestIdx === -1) return { avg7: 0, avg30: 0 };

    const last7Dates = sortedDates.slice(Math.max(0, latestIdx - 6), latestIdx + 1);
    const last30Dates = sortedDates.slice(Math.max(0, latestIdx - 29), latestIdx + 1);

    const sum7 = last7Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);
    const sum30 = last30Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);

    return {
      avg7: last7Dates.length ? Math.round(sum7 / last7Dates.length) : 0,
      avg30: last30Dates.length ? Math.round(sum30 / last30Dates.length) : 0,
    };
  }, [productionData, latestDateInSystem]);

  useEffect(() => {
    const fetchInsights = async () => {
      if (dayRecords.length === 0) {
        setInsights("No data available for AI analysis on this date.");
        setLoadingInsights(false);
        return;
      }
      setLoadingInsights(true);
      try {
        const text = await getAIInsights(productionData, selectedDate);
        setInsights(text);
      } catch (e) {
        setInsights("AI Insights currently unavailable.");
      } finally {
        setLoadingInsights(false);
      }
    };
    fetchInsights();
  }, [selectedDate, productionData]);

  return (
    <div className="space-y-6 md:space-y-8 pb-12">
      <div className={`flex items-center gap-3 md:gap-4 px-4 md:px-6 py-3 md:py-4 rounded-2xl md:rounded-3xl border shadow-sm transition-all ${!isLatest ? 'bg-amber-500/5 border-amber-500/20 text-amber-600 dark:text-amber-500' : 'bg-emerald-500/5 border-emerald-500/20 text-emerald-600 dark:text-emerald-500'}`}>
        {!isLatest ? (
          <>
            <History size={20} className="md:size-6" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-[10px] md:text-sm">Historical Archive View</span>
              <span className="text-[8px] md:text-[10px] opacity-70 font-bold uppercase">{selectedDate} Records</span>
            </div>
          </>
        ) : (
          <>
            <Zap size={20} className="md:size-6 animate-pulse" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-[10px] md:text-sm">Live Operational Status</span>
              <span className="text-[8px] md:text-[10px] opacity-70 font-bold uppercase">Streaming Latest Logs</span>
            </div>
            <span className="ml-auto flex h-2 w-2 md:h-3 md:w-3 rounded-full bg-emerald-500 animate-ping"></span>
          </>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="bg-white dark:bg-slate-800/80 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-center lg:col-span-2 relative overflow-hidden group">
          <div className="flex items-center gap-3 md:gap-4 mb-4">
            <div className="p-2 md:p-3 bg-blue-500/10 dark:bg-blue-500/20 rounded-xl md:rounded-2xl text-blue-600 dark:text-blue-400"><Activity size={24} /></div>
            <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-[10px] md:text-sm">Aggregate Daily Production</span>
          </div>

          <div className="flex flex-col md:flex-row md:items-end gap-4 md:gap-6 mb-6 md:mb-8">
            <div>
              <div className="text-6xl md:text-8xl font-black text-slate-900 dark:text-white tracking-tighter">{totalProduction.toLocaleString()}</div>
              <div className="text-sm md:text-xl text-slate-400 dark:text-slate-500 font-bold uppercase mt-1">Million Cubic Feet (MCF)</div>
            </div>

            <div className="flex flex-row md:flex-col gap-6 md:gap-3 pb-2 border-l-0 md:border-l border-slate-200 dark:border-slate-700 pl-0 md:pl-6">
              <div className="flex flex-col">
                <span className="text-[8px] md:text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">7D Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-xl md:text-2xl font-black text-blue-600 dark:text-blue-400 font-mono">{historicalMetrics.avg7.toLocaleString()}</span>
                </div>
              </div>
              <div className="flex flex-col">
                <span className="text-[8px] md:text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">30D Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-xl md:text-2xl font-black text-slate-700 dark:text-slate-300 font-mono">{historicalMetrics.avg30.toLocaleString()}</span>
                </div>
              </div>
            </div>
          </div>

          <div className={`mt-auto pt-4 md:pt-6 border-t border-slate-100 dark:border-slate-700/50 text-xs md:text-lg flex items-center justify-between font-bold`}>
            <div className={`flex items-center gap-2 ${totalProduction >= historicalMetrics.avg7 ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-600 dark:text-amber-400'}`}>
               <TrendingUp size={16} className={`${totalProduction < historicalMetrics.avg7 ? 'rotate-180' : ''} md:size-6`} /> 
               {totalProduction >= historicalMetrics.avg7 ? 'ABOVE 7D AVG' : 'BELOW 7D NORM'}
            </div>
            <div className="text-[8px] md:text-[10px] text-slate-300 dark:text-slate-600 uppercase font-black tracking-widest">Telemetry Active</div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800/80 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-between relative overflow-hidden">
          <div className="absolute top-4 right-4 flex flex-col items-end gap-1">
            <span className="text-[7px] md:text-[8px] bg-emerald-500 text-white px-2 py-0.5 rounded-full font-black animate-pulse">LATEST</span>
          </div>

          <div>
            <div className="flex items-center gap-3 mb-6 md:mb-8">
              <Users size={20} className="text-slate-400 md:size-6" />
              <h3 className="text-xs md:text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest">Workforce Status</h3>
            </div>
            <div className="space-y-6 md:space-y-8">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3 md:gap-4">
                  <div className="p-2 md:p-3 bg-amber-500/10 dark:bg-amber-500/20 rounded-xl text-amber-600 dark:text-amber-400"><Briefcase size={20} className="md:size-6" /></div>
                  <span className="text-slate-600 dark:text-slate-300 font-bold text-sm md:text-lg uppercase">Officers</span>
                </div>
                <div className="text-3xl md:text-5xl font-black text-slate-900 dark:text-white tracking-tighter">{latestPersonnel?.officers.toLocaleString() || "---"}</div>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3 md:gap-4">
                  <div className="p-2 md:p-3 bg-emerald-500/10 dark:bg-emerald-500/20 rounded-xl text-emerald-600 dark:text-emerald-400"><Users size={20} className="md:size-6" /></div>
                  <span className="text-slate-600 dark:text-slate-300 font-bold text-sm md:text-lg uppercase">Employees</span>
                </div>
                <div className="text-3xl md:text-5xl font-black text-slate-900 dark:text-white tracking-tighter">{latestPersonnel?.employees.toLocaleString() || "---"}</div>
              </div>
            </div>
          </div>
          <div className="pt-6 md:pt-8 border-t border-slate-100 dark:border-slate-700/50 mt-4">
            <p className="text-[8px] md:text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest">Current Distribution</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="bg-white dark:bg-slate-900/60 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm lg:col-span-2">
          <div className="flex items-center gap-3 mb-6">
            <LayoutList size={20} className="text-emerald-500 md:size-6" />
            <h3 className="text-sm md:text-lg font-black text-slate-900 dark:text-white uppercase tracking-widest">Field Logs Breakdown</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3 md:gap-4">
            {dayRecords.map((record) => (
