import React, { useState, useEffect, useMemo } from 'react';
import { ProductionRecord, PersonnelRecord } from '../types.ts';
import { ORGANOGRAM } from '../constants.ts';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts.tsx';
import ProductionTable from './ProductionTable.tsx';
import { getAIInsights } from '../services/geminiService.ts';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList, History, Zap, Users, Briefcase, Droplets, FlaskConical, Target, AlertTriangle, CheckCircle2 } from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  selectedDate: string;
  latestDateInSystem: string;
  isDarkMode: boolean;
}

const Dashboard: React.FC<Props> = ({ productionData, personnelData, selectedDate, latestDateInSystem, isDarkMode }) => {
  const [insights, setInsights] = useState<string>('Analyzing operational metrics...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  const dayRecords = useMemo(() => productionData.filter(d => d.date === selectedDate), [productionData, selectedDate]);

  const latestPersonnel = useMemo(() => {
    if (!personnelData.length) return null;
    return [...personnelData].sort((a, b) => b.date.localeCompare(a.date))[0];
  }, [personnelData]);

  const stats = useMemo(() => {
    const officers = latestPersonnel?.officers || 0;
    const employees = latestPersonnel?.employees || 0;
    const total = officers + employees;
    const targetTotal = ORGANOGRAM.OFFICERS + ORGANOGRAM.EMPLOYEES;

    return {
      officers,
      employees,
      total,
      offDiff: officers - ORGANOGRAM.OFFICERS,
      empDiff: employees - ORGANOGRAM.EMPLOYEES,
      totalDiff: total - targetTotal,
      offPercent: (officers / ORGANOGRAM.OFFICERS) * 100,
      empPercent: (employees / ORGANOGRAM.EMPLOYEES) * 100
    };
  }, [latestPersonnel]);

  const totalProduction = useMemo(() => dayRecords.reduce((acc, curr) => acc + curr.amount, 0), [dayRecords]);
  const totalCondensate = useMemo(() => dayRecords.reduce((acc, curr) => acc + (curr.condensate || 0), 0), [dayRecords]);
  const totalWater = useMemo(() => dayRecords.reduce((acc, curr) => acc + (curr.water || 0), 0), [dayRecords]);

  const isLatest = selectedDate === latestDateInSystem;

  const historicalMetrics = useMemo(() => {
    const dailyTotalsMap: Record<string, number> = {};
    productionData.forEach(record => {
      dailyTotalsMap[record.date] = (dailyTotalsMap[record.date] || 0) + record.amount;
    });

    const sortedDates = Object.keys(dailyTotalsMap).sort();
    const latestIdx = sortedDates.indexOf(latestDateInSystem);

    if (latestIdx === -1) return { avg7: 0, avg30: 0 };

    const last7Dates = sortedDates.slice(Math.max(0, latestIdx - 6), latestIdx + 1);
    const last30Dates = sortedDates.slice(Math.max(0, latestIdx - 29), latestIdx + 1);

    const sum7 = last7Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);
    const sum30 = last30Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);

    return {
      avg7: last7Dates.length ? Math.round(sum7 / last7Dates.length) : 0,
      avg30: last30Dates.length ? Math.round(sum30 / last30Dates.length) : 0,
    };
  }, [productionData, latestDateInSystem]);

  useEffect(() => {
    const fetchInsights = async () => {
      if (dayRecords.length === 0) {
        setInsights("No data available for AI analysis on this date.");
        setLoadingInsights(false);
        return;
      }
      setLoadingInsights(true);
      try {
        const text = await getAIInsights(productionData, selectedDate);
        setInsights(text);
      } catch (e) {
        setInsights("AI Insights currently unavailable.");
      } finally {
        setLoadingInsights(false);
      }
    };
    fetchInsights();
  }, [selectedDate, productionData]);

  const renderWorkforceRow = (label: string, icon: React.ReactNode, actual: number, target: number, diff: number, color: string) => {
    const isShortage = diff < 0;
    const isSurplus = diff > 0;

    return (
      <div className="flex flex-col gap-1 p-2 md:p-3 bg-slate-50/50 dark:bg-slate-900/30 rounded-xl border border-slate-100 dark:border-slate-800">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className={`p-1.5 rounded-lg ${color}`}>{icon}</div>
            <span className="text-slate-600 dark:text-slate-400 font-bold text-[10px] md:text-xs uppercase tracking-tight">{label}</span>
          </div>
          <div className="flex items-center gap-1.5">
             <span className="text-lg md:text-xl font-black text-slate-900 dark:text-white">{actual.toLocaleString()}</span>
             <span className="text-[10px] font-bold text-slate-400">/ {target}</span>
          </div>
        </div>
        <div className="flex items-center justify-between text-[9px] md:text-[10px] font-black uppercase tracking-widest mt-1">
          <div className="text-slate-400">Organogram Gap</div>
          <div className={`flex items-center gap-1 ${isShortage ? 'text-rose-500' : isSurplus ? 'text-emerald-500' : 'text-slate-400'}`}>
            {isShortage ? <AlertTriangle size={10} /> : <CheckCircle2 size={10} />}
            {isShortage ? 'Shortage' : isSurplus ? 'Surplus' : 'Full'} ({isShortage ? '' : '+'}{diff})
          </div>
        </div>
        <div className="w-full h-1 bg-slate-200 dark:bg-slate-800 rounded-full mt-1 overflow-hidden">
          <div 
            className={`h-full transition-all duration-1000 ${isShortage ? 'bg-amber-500' : 'bg-emerald-500'}`} 
            style={{ width: `${Math.min(100, (actual/target)*100)}%` }}
          />
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-4 md:space-y-6 pb-12">
      <div className={`flex items-center gap-3 md:gap-4 px-4 md:px-6 py-2 md:py-3 rounded-2xl md:rounded-3xl border shadow-sm transition-all ${!isLatest ? 'bg-amber-500/5 border-amber-500/20 text-amber-600 dark:text-amber-500' : 'bg-emerald-500/5 border-emerald-500/20 text-emerald-600 dark:text-emerald-500'}`}>
        {!isLatest ? (
          <>
            <History size={16} className="md:w-5 md:h-5" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-[8px] md:text-xs">Historical Archive View</span>
              <span className="text-[7px] md:text-[9px] opacity-70 font-bold uppercase">{selectedDate} Records</span>
            </div>
          </>
        ) : (
          <>
            <Zap size={16} className="md:w-5 md:h-5 animate-pulse" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-[8px] md:text-xs">Live Operational Status</span>
              <span className="text-[7px] md:text-[9px] opacity-70 font-bold uppercase">Streaming Latest Logs</span>
            </div>
            <span className="ml-auto flex h-1.5 w-1.5 md:h-2 md:w-2 rounded-full bg-emerald-500 animate-ping"></span>
          </>
        )}
      </div>

      {/* Row 1: Primary Metrics */}
      <div className="grid grid-cols-1 xl:grid-cols-4 4k:grid-cols-4 gap-4 md:gap-6">
        {/* Aggregate Daily Production (Gas) */}
        <div className="bg-white dark:bg-slate-800/80 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-center xl:col-span-2 4k:col-span-2 relative overflow-hidden group">
          <div className="flex items-center gap-3 md:gap-4 mb-2">
            <div className="p-1.5 md:p-2 bg-blue-500/10 dark:bg-blue-500/20 rounded-xl text-blue-600 dark:text-blue-400"><Activity size={20} /></div>
            <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-xs">Aggregate Daily Gas Production</span>
          </div>

          <div className="flex flex-col 4k:flex-row 4k:items-end gap-4 4k:gap-10 mb-4 4k:mb-6">
            <div>
              <div className="text-4xl md:text-6xl 4k:text-7xl font-black text-slate-900 dark:text-white tracking-tighter leading-tight">{totalProduction.toLocaleString()}</div>
              <div className="text-[10px] md:text-xs 4k:text-sm text-slate-400 dark:text-slate-500 font-bold uppercase mt-0">Million Cubic Feet (MCF)</div>
            </div>

            <div className="grid grid-cols-2 md:flex md:flex-col gap-4 md:gap-2 pb-2 border-l-0 4k:border-l border-slate-200 dark:border-slate-700 pl-0 4k:pl-8">
              <div className="flex flex-col">
                <span className="text-[7px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">7D Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-base md:text-lg 4k:text-xl font-black text-blue-600 dark:text-blue-400 font-mono">{historicalMetrics.avg7.toLocaleString()}</span>
                </div>
              </div>
              <div className="flex flex-col">
                <span className="text-[7px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">30D Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-base md:text-lg 4k:text-xl font-black text-slate-700 dark:text-slate-300 font-mono">{historicalMetrics.avg30.toLocaleString()}</span>
                </div>
              </div>
            </div>
          </div>

          <div className={`mt-auto pt-3 md:pt-4 border-t border-slate-100 dark:border-slate-700/50 text-[10px] md:text-xs flex items-center justify-between font-bold`}>
            <div className={`flex items-center gap-1.5 ${totalProduction >= historicalMetrics.avg7 ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-600 dark:text-amber-400'}`}>
               <TrendingUp size={14} className={`${totalProduction < historicalMetrics.avg7 ? 'rotate-180' : ''} md:w-5 md:h-5`} /> 
               {totalProduction >= historicalMetrics.avg7 ? 'ABOVE 7D AVG' : 'BELOW 7D NORM'}
            </div>
          </div>
        </div>

        {/* Liquid Metrics (Condensate & Water) */}
        <div className="grid grid-rows-2 gap-4 md:gap-6 xl:col-span-1 4k:col-span-1">
          <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl flex flex-col justify-center relative overflow-hidden group">
            <div className="flex items-center gap-2 mb-2">
              <FlaskConical size={16} className="text-blue-500" />
              <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-xs">Condensate</span>
            </div>
            <div className="text-3xl md:text-4xl font-black text-slate-900 dark:text-white tracking-tighter">{totalCondensate.toLocaleString()} <span className="text-[10px] font-bold text-slate-400 uppercase">BBL</span></div>
          </div>
          <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl flex flex-col justify-center relative overflow-hidden group">
            <div className="flex items-center gap-2 mb-2">
              <Droplets size={16} className="text-amber-500" />
              <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-xs">Produced Water</span>
            </div>
            <div className="text-3xl md:text-4xl font-black text-slate-900 dark:text-white tracking-tighter">{totalWater.toLocaleString()} <span className="text-[10px] font-bold text-slate-400 uppercase">BBL</span></div>
          </div>
        </div>

        {/* Workforce Card - Benchmarked against Organogram */}
        <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-between relative overflow-hidden xl:col-span-1 4k:col-span-1">
          <div>
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2">
                <Users size={16} className="text-slate-400 md:w-5 md:h-5" />
                <h3 className="text-[10px] md:text-xs font-black text-slate-900 dark:text-white uppercase tracking-widest">Workforce Gap</h3>
              </div>
              <span className="text-[8px] bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">ORGANOGRAM</span>
            </div>

            <div className="space-y-3 md:space-y-4">
              {renderWorkforceRow('Officers', <Briefcase size={14} />, stats.officers, ORGANOGRAM.OFFICERS, stats.offDiff, 'bg-amber-500/10 text-amber-600 dark:text-amber-400')}
              {renderWorkforceRow('Staff', <Users size={14} />, stats.employees, ORGANOGRAM.EMPLOYEES, stats.empDiff, 'bg-blue-500/10 text-blue-600 dark:text-blue-400')}

              <div className="mt-4 pt-4 border-t border-slate-100 dark:border-slate-700/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 md:p-2 bg-emerald-500/10 rounded-lg text-emerald-600 dark:text-emerald-400"><Target size={14} /></div>
                  <span className="text-slate-800 dark:text-slate-200 font-black text-[10px] md:text-xs uppercase tracking-tighter">Total Strength</span>
                </div>
                <div className="flex flex-col items-end">
                  <div className="text-xl md:text-2xl font-black text-emerald-600 dark:text-emerald-400 tracking-tighter">{stats.total.toLocaleString()}</div>
                  <div className={`text-[8px] font-black uppercase ${stats.totalDiff < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                    Net Gap: {stats.totalDiff < 0 ? '' : '+'}{stats.totalDiff}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Row 2: Breakdown (Larger) */}
      <div className="grid grid-cols-1 xl:grid-cols-4 4k:grid-cols-6 gap-4 md:gap-6">
        <div className="bg-white dark:bg-slate-900/60 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm xl:col-span-3 4k:col-span-4">
          <div className="flex items-center gap-3 mb-4">
            <LayoutList size={18} className="text-emerald-500" />
            <h3 className="text-[10px] md:text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest">Field-wise Operational Summary</h3>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-3 4k:grid-cols-6 gap-2 md:gap-4">
            {dayRecords.map((record) => (
              <div key={record.field} className="p-4 bg-slate-50 dark:bg-slate-800/40 rounded-xl border border-slate-100 dark:border-slate-800 hover:border-emerald-500/30 transition-all flex flex-col">
                <div className="text-slate-400 dark:text-slate-500 font-black text-[12px] md:text-[14px] uppercase tracking-widest mb-2 truncate">{record.field}</div>
                <div className="space-y-1">
                  <div className="text-emerald-600 dark:text-emerald-400 font-black text-lg md:text-xl font-mono">{record.amount.toLocaleString()} <span className="text-[8px] text-slate-400 uppercase font-sans">MCF</span></div>
                  <div className="flex justify-between items-center text-[10px] md:text-[11px] font-bold">
                    <span className="text-blue-500 uppercase tracking-tighter">Cond:</span>
                    <span className="text-slate-700 dark:text-slate-300 font-mono">{record.condensate?.toLocaleString() || 0} BBL</span>
                  </div>
                  <div className="flex justify-between items-center text-[10px] md:text-[11px] font-bold">
                    <span className="text-amber-500 uppercase tracking-tighter">Water:</span>
                    <span className="text-slate-700 dark:text-slate-300 font-mono">{record.water?.toLocaleString() || 0} BBL</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
          {dayRecords.length === 0 && <div className="text-slate-400 dark:text-slate-500 text-center py-10 font-bold uppercase tracking-widest border border-dashed border-slate-200 dark:border-slate-800 rounded-2xl">No data found</div>}
        </div>

        <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl xl:col-span-1 4k:col-span-2">
          <FieldDistributionChart data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
      </div>

      {/* Row 3: Trend | Benchmarking | Activity */}
      <div className="grid grid-cols-1 xl:grid-cols-8 gap-4 md:gap-6">
        <div className="bg-white dark:bg-slate-800/50 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg xl:col-span-3">
           <HistoricalTrendChart data={productionData} centerDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
        <div className="bg-white dark:bg-slate-800/50 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg xl:col-span-3">
           <FieldComparisonBar data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
        <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl xl:col-span-2">
           <div className="flex items-center gap-2 mb-4">
              <Sparkles size={16} className="text-purple-500" />
              <h3 className="text-[10px] md:text-xs font-black text-slate-900 dark:text-white uppercase tracking-widest">Executive Intelligence</h3>
           </div>
           <div className={`text-xs md:text-sm 4k:text-base text-slate-700 dark:text-slate-200 leading-relaxed font-medium transition-opacity duration-700 ${loadingInsights ? 'opacity-40 animate-pulse' : 'opacity-100'}`}>{insights}</div>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800/50 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg flex flex-col">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-xs md:text-sm font-bold text-slate-900 dark:text-white flex items-center gap-2 uppercase tracking-widest"><Clock size={16} className="text-slate-400" /> Recent Field Activity</h3>
          </div>
          <div className="flex-1 overflow-y-auto max-h-[400px]"><ProductionTable data={productionData} /></div>
      </div>
    </div>
  );
};

export default Dashboard;

export interface ProductionRecord {
  id: string;
  field: string;
  amount: number; // in MCF (Million Cubic Feet)
  condensate: number; // in BBL (Barrels)
  water: number; // in BBL (Barrels)
  date: string;
}

export interface PersonnelRecord {
  id: string;
  date: string;
  officers: number;
  employees: number;
  approved_officers?: number; // Target from Organogram
  approved_employees?: number; // Target from Organogram
}

export interface FieldInfo {
  id: string;
  name: string;
  location: string;
  status: 'Active' | 'Maintenance' | 'Standby';
}

export type ViewType = 'dashboard' | 'admin';

import React, { useState, useMemo } from 'react';
import { FIELDS, ORGANOGRAM } from '../constants.ts';
import { ProductionRecord, PersonnelRecord } from '../types.ts';
import { 
  PlusCircle, Trash2, Database, AlertCircle, Loader2, XCircle, 
  Edit3, ChevronLeft, ChevronRight, Save, X, Users, Briefcase, LayoutGrid, UserCheck,
  Fuel, Calendar, Droplets, FlaskConical, Target
} from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  onAddProduction: (record: Omit<ProductionRecord, 'id'>) => Promise<void>;
  onUpdateProduction: (id: string, record: Omit<ProductionRecord, 'id'>) => Promise<void>;
  onDeleteProduction: (id: string) => Promise<void>;
  onAddPersonnel: (record: Omit<PersonnelRecord, 'id'>) => Promise<void>;
  onUpdatePersonnel: (id: string, record: Omit<PersonnelRecord, 'id'>) => Promise<void>;
  onDeletePersonnel: (id: string) => Promise<void>;
}

const RECORDS_PER_PAGE = 8;

const AdminPanel: React.FC<Props> = ({ 
  productionData, personnelData,
  onAddProduction, onUpdateProduction, onDeleteProduction,
  onAddPersonnel, onUpdatePersonnel, onDeletePersonnel
}) => {
  const [activeTab, setActiveTab] = useState<'production' | 'personnel'>('production');

  // Production Form State
  const [field, setField] = useState(FIELDS[0].name);
  const [amount, setAmount] = useState<string>('');
  const [condensate, setCondensate] = useState<string>('');
  const [water, setWater] = useState<string>('');
  const [prodDate, setProdDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [editingProdId, setEditingProdId] = useState<string | null>(null);

  // Personnel Form State
  const [persDate, setPersDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [officers, setOfficers] = useState<string>('');
  const [employees, setEmployees] = useState<string>('');
  const [appOfficers, setAppOfficers] = useState<string>(ORGANOGRAM.OFFICERS.toString());
  const [appEmployees, setAppEmployees] = useState<string>(ORGANOGRAM.EMPLOYEES.toString());
  const [editingPersId, setEditingPersId] = useState<string | null>(null);

  // UI State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [loadingActionId, setLoadingActionId] = useState<string | null>(null);
  const [validationError, setValidationError] = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState(1);

  const handleProductionSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setValidationError(null);
    const numAmount = Number(amount);
    const numCond = Number(condensate || 0);
    const numWater = Number(water || 0);

    if (!amount || isNaN(numAmount)) { setValidationError("Enter numeric gas production amount."); return; }
    if (isNaN(numCond) || isNaN(numWater)) { setValidationError("Enter numeric liquid production values."); return; }

    if (productionData.some(r => r.field === field && r.date === prodDate && r.id !== editingProdId)) {
      setValidationError(`Entry for ${field} on ${prodDate} already exists.`); return;
    }

    setIsSubmitting(true);
    try {
      const payload = { 
        field, 
        amount: numAmount, 
        condensate: numCond, 
        water: numWater, 
        date: prodDate 
      };
      if (editingProdId) await onUpdateProduction(editingProdId, payload);
      else await onAddProduction(payload);

      setAmount(''); setCondensate(''); setWater(''); 
      setEditingProdId(null);
    } catch { setValidationError("Database error occurred."); } finally { setIsSubmitting(false); }
  };

  const handlePersonnelSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setValidationError(null);
    const numOff = Number(officers);
    const numEmp = Number(employees);
    const numAppOff = Number(appOfficers);
    const numAppEmp = Number(appEmployees);

    if (isNaN(numOff) || isNaN(numEmp) || isNaN(numAppOff) || isNaN(numAppEmp)) { 
      setValidationError("Enter valid personnel counts."); return; 
    }

    if (personnelData.some(p => p.date === persDate && p.id !== editingPersId)) {
       setValidationError(`Personnel data for ${persDate} already exists.`); return;
    }

    setIsSubmitting(true);
    try {
      const payload = { 
        date: persDate, 
        officers: numOff, 
        employees: numEmp,
        approved_officers: numAppOff,
        approved_employees: numAppEmp
      };

      if (editingPersId) await onUpdatePersonnel(editingPersId, payload);
      else await onAddPersonnel(payload);

      setOfficers(''); setEmployees(''); 
      setEditingPersId(null);
    } catch { setValidationError("Personnel database update failed."); } finally { setIsSubmitting(false); }
  };

  const startEditProd = (record: ProductionRecord) => {
    setField(record.field); 
    setAmount(record.amount.toString()); 
    setCondensate(record.condensate?.toString() || '');
    setWater(record.water?.toString() || '');
    setProdDate(record.date);
    setEditingProdId(record.id); setValidationError(null); setActiveTab('production');
  };

  const startEditPers = (record: PersonnelRecord) => {
    setPersDate(record.date); 
    setOfficers(record.officers.toString()); 
    setEmployees(record.employees.toString());
    setAppOfficers((record.approved_officers || ORGANOGRAM.OFFICERS).toString());
    setAppEmployees((record.approved_employees || ORGANOGRAM.EMPLOYEES).toString());
    setEditingPersId(record.id); setValidationError(null); setActiveTab('personnel');
  };

  const sortedProduction = useMemo(() => [...productionData].sort((a,b) => b.date.localeCompare(a.date)), [productionData]);
  const sortedPersonnel = useMemo(() => [...personnelData].sort((a,b) => b.date.localeCompare(a.date)), [personnelData]);

  const pagedData = activeTab === 'production' 
    ? sortedProduction.slice((currentPage-1)*RECORDS_PER_PAGE, currentPage*RECORDS_PER_PAGE)
    : sortedPersonnel.slice((currentPage-1)*RECORDS_PER_PAGE, currentPage*RECORDS_PER_PAGE);

  const totalPages = Math.ceil((activeTab === 'production' ? productionData.length : personnelData.length) / RECORDS_PER_PAGE);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-10">
      <div className="lg:col-span-1 space-y-6 md:space-y-8">
        <div className="flex bg-white dark:bg-slate-900 p-1 md:p-1.5 rounded-xl md:rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <button onClick={() => { setActiveTab('production'); setValidationError(null); setCurrentPage(1); }} className={`flex-1 py-2 md:py-3 px-2 md:px-4 rounded-lg md:rounded-xl flex items-center justify-center gap-2 font-bold text-xs md:text-sm transition-all ${activeTab === 'production' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-700'}`}>
            <LayoutGrid size={16} /> Production
          </button>
          <button onClick={() => { setActiveTab('personnel'); setValidationError(null); setCurrentPage(1); }} className={`flex-1 py-2 md:py-3 px-2 md:px-4 rounded-lg md:rounded-xl flex items-center justify-center gap-2 font-bold text-xs md:text-sm transition-all ${activeTab === 'personnel' ? 'bg-amber-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-700'}`}>
            <UserCheck size={16} /> Personnel
          </button>
        </div>

        <div className={`bg-white dark:bg-slate-800 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl transition-all duration-300 ${activeTab === 'personnel' ? 'ring-2 ring-amber-500/20' : 'ring-2 ring-emerald-500/20'}`}>
          <h2 className="text-xl md:text-2xl font-black mb-6 flex items-center gap-2 md:gap-3 text-slate-900 dark:text-white">
            {activeTab === 'production' ? <><Database className="text-emerald-500" size={20} /> Field Logging</> : <><Users className="text-amber-500" size={20} /> Census Update</>}
          </h2>
          {validationError && <div className="mb-6 p-3 md:p-4 bg-red-500/10 border border-red-500/30 rounded-xl flex items-center gap-3 text-red-600 dark:text-red-400 text-[10px] md:text-sm font-bold"><XCircle size={16} /> {validationError}</div>}

          {activeTab === 'production' ? (
            <form onSubmit={handleProductionSubmit} className="space-y-5 md:space-y-6">
              <div>
                <label className="block text-[8px] md:text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Field Selection</label>
                <select value={field} onChange={(e) => setField(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg md:rounded-xl p-3 md:p-4 text-xs md:text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500">
                  {FIELDS.map(f => <option key={f.id} value={f.name}>{f.name}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[8px] md:text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Gas (MCF)</label>
                  <input type="number" step="0.01" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg md:rounded-xl p-3 md:p-4 text-xs md:text-sm font-mono font-bold outline-none focus:ring-2 focus:ring-emerald-500" required />
                </div>
                <div>
                  <label className="block text-[8px] md:text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Log Date</label>
                  <input type="date" value={prodDate} onChange={(e) => setProdDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg md:rounded-xl p-3 md:p-4 text-xs md:text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500" required />
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[8px] md:text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Condensate (BBL)</label>
                  <input type="number" step="0.01" value={condensate} onChange={(e) => setCondensate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg md:rounded-xl p-3 md:p-4 text-xs md:text-sm font-mono font-bold outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-[8px] md:text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Produced Water (BBL)</label>
                  <input type="number" step="0.01" value={water} onChange={(e) => setWater(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg md:rounded-xl p-3 md:p-4 text-xs md:text-sm font-mono font-bold outline-none focus:ring-2 focus:ring-amber-500" />
                </div>
              </div>
              <button type="submit" disabled={isSubmitting} className="w-full bg-emerald-600 hover:bg-emerald-500 py-4 md:py-5 rounded-xl md:rounded-2xl text-white font-black uppercase tracking-widest text-xs md:text-sm shadow-xl flex items-center justify-center gap-3">{isSubmitting ? <Loader2 className="animate-spin" size={16} /> : editingProdId ? <Save size={16} /> : <PlusCircle size={16} />} {editingProdId ? "Apply Update" : "Push Log"}</button>
              {editingProdId && <button type="button" onClick={() => setEditingProdId(null)} className="w-full py-3 text-slate-500 font-bold uppercase text-[10px] tracking-widest border border-slate-200 rounded-xl">Cancel</button>}
            </form>
          ) : (
            <form onSubmit={handlePersonnelSubmit} className="space-y-5 md:space-y-6">
              <div>
                <label className="block text-[8px] md:text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Census Date</label>
                <input type="date" value={persDate} onChange={(e) => setPersDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg md:rounded-xl p-3 md:p-4 text-xs md:text-sm font-bold outline-none focus:ring-2 focus:ring-amber-500" required />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-4">
                  <span className="block text-[8px] font-black text-emerald-500 uppercase tracking-widest">Present Strength</span>
                  <div>
                    <label className="block text-[8px] md:text-[10px] font-black text-slate-400 uppercase mb-1">Officers</label>
                    <input type="number" value={officers} onChange={(e) => setOfficers(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-3 text-xs md:text-sm font-mono font-bold outline-none focus:ring-2 focus:ring-amber-500" required />
                  </div>
                  <div>
                    <label className="block text-[8px] md:text-[10px] font-black text-slate-400 uppercase mb-1">Staff</label>
                    <input type="number" value={employees} onChange={(e) => setEmployees(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-3 text-xs md:text-sm font-mono font-bold outline-none focus:ring-2 focus:ring-amber-500" required />
                  </div>
                </div>

                <div className="space-y-4">
                  <span className="block text-[8px] font-black text-blue-500 uppercase tracking-widest">Approved (Organogram)</span>
                  <div>
                    <label className="block text-[8px] md:text-[10px] font-black text-slate-400 uppercase mb-1">Officers</label>
                    <input type="number" value={appOfficers} onChange={(e) => setAppOfficers(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-3 text-xs md:text-sm font-mono font-bold outline-none focus:ring-2 focus:ring-blue-500" required />
                  </div>
                  <div>
                    <label className="block text-[8px] md:text-[10px] font-black text-slate-400 uppercase mb-1">Staff</label>
                    <input type="number" value={appEmployees} onChange={(e) => setAppEmployees(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-3 text-xs md:text-sm font-mono font-bold outline-none focus:ring-2 focus:ring-blue-500" required />
                  </div>
                </div>
              </div>

              <button type="submit" disabled={isSubmitting} className="w-full bg-amber-600 hover:bg-amber-500 py-4 md:py-5 rounded-xl md:rounded-2xl text-white font-black uppercase tracking-widest text-xs md:text-sm shadow-xl flex items-center justify-center gap-3">{isSubmitting ? <Loader2 className="animate-spin" size={16} /> : editingPersId ? <Save size={16} /> : <UserCheck size={16} />} {editingPersId ? "Update Census" : "Submit Census"}</button>
              {editingPersId && <button type="button" onClick={() => setEditingPersId(null)} className="w-full py-3 text-slate-500 font-bold uppercase text-[10px] tracking-widest border border-slate-200 rounded-xl">Cancel</button>}
            </form>
          )}
        </div>
      </div>

      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white dark:bg-slate-800 p-6 md:p-10 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl h-full flex flex-col min-h-[500px] md:min-h-[700px]">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6 md:mb-8">
            <div><h2 className="text-xl md:text-3xl font-black text-slate-900 dark:text-white">{activeTab === 'production' ? "Production Logs" : "Personnel Logs"}</h2></div>
            <div className="bg-slate-50 dark:bg-slate-900 px-3 py-1.5 rounded-lg border border-slate-200 text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest self-start">PAGE {currentPage} / {totalPages || 1}</div>
          </div>

          <div className="flex-1 space-y-3 md:space-y-4">
            {activeTab === 'production' ? (
               (pagedData as ProductionRecord[]).map(record => (
                 <div key={record.id} className="flex items-center justify-between p-4 md:p-6 bg-slate-50 dark:bg-slate-900 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-700/50 hover:border-emerald-500/30 transition-all shadow-sm">
                    <div className="flex items-center gap-3 md:gap-6">
                      <div className="hidden sm:block bg-white dark:bg-slate-800 p-2 md:p-3 rounded-lg md:rounded-xl text-slate-400 dark:text-slate-500 shadow-sm border border-slate-100 dark:border-slate-700"><Fuel size={20} /></div>
                      <div>
                        <div className="font-black text-sm md:text-lg text-slate-800 dark:text-slate-100">{record.field}</div>
                        <div className="text-[8px] md:text-xs font-bold text-slate-400 dark:text-slate-500 uppercase flex items-center gap-1"><Calendar size={10} /> {record.date}</div>
                        <div className="flex gap-2 mt-1">
                          <span className="text-[7px] bg-blue-500/10 text-blue-500 px-1 rounded">C: {record.condensate || 0}</span>
                          <span className="text-[7px] bg-amber-500/10 text-amber-500 px-1 rounded">W: {record.water || 0}</span>
                        </div>
                      </div>
                    </div>
                    <div className="flex items-center gap-4 md:gap-8">
                      <div className="text-right">
                        <div className="text-lg md:text-2xl font-black text-emerald-600 dark:text-emerald-400 font-mono">{record.amount.toLocaleString()}</div>
                        <div className="text-[8px] md:text-[10px] font-black text-slate-400 dark:text-slate-600 uppercase tracking-widest">MCF</div>
                      </div>
                      <div className="flex items-center gap-1 md:gap-2">
                        <button onClick={() => startEditProd(record)} className="p-1.5 md:p-2.5 text-slate-400 hover:text-emerald-600 hover:bg-emerald-400/10 rounded-lg"><Edit3 size={16} /></button>
                        <button onClick={async () => { if(confirm("Delete record?")) { setLoadingActionId(record.id); await onDeleteProduction(record.id); setLoadingActionId(null); } }} className="p-1.5 md:p-2.5 text-slate-400 hover:text-red-600 hover:bg-red-400/10 rounded-lg">{loadingActionId === record.id ? <Loader2 className="animate-spin" size={16} /> : <Trash2 size={16} />}</button>
                      </div>
                    </div>
                 </div>
               ))
            ) : (
              (pagedData as PersonnelRecord[]).map(record => (
                <div key={record.id} className="flex items-center justify-between p-4 md:p-6 bg-slate-50 dark:bg-slate-900 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-700/50 hover:border-amber-500/30 transition-all shadow-sm">
                   <div className="flex items-center gap-3 md:gap-6">
                     <div className="hidden sm:block bg-white dark:bg-slate-800 p-2 md:p-3 rounded-lg md:rounded-xl text-slate-400 dark:text-slate-500 shadow-sm border border-slate-100 dark:border-slate-700"><UserCheck size={20} /></div>
                     <div><div className="font-black text-sm md:text-lg text-slate-800 dark:text-slate-100">Census</div><div className="text-[8px] md:text-xs font-bold text-slate-400 dark:text-slate-500 uppercase flex items-center gap-1"><Calendar size={10} /> {record.date}</div></div>
                   </div>
                   <div className="flex items-center gap-4 md:gap-10">
                     <div className="flex items-center gap-4 md:gap-6">
                        <div className="text-right">
                          <div className="text-base md:text-xl font-black text-amber-600 dark:text-amber-500 font-mono">{record.officers}</div>
                          <div className="text-[7px] md:text-[8px] font-black text-slate-400 dark:text-slate-600 uppercase tracking-tighter">OFF ({record.approved_officers || 'N/A'})</div>
                        </div>
                        <div className="text-right">
                          <div className="text-base md:text-xl font-black text-emerald-600 dark:text-emerald-400 font-mono">{record.employees}</div>
                          <div className="text-[7px] md:text-[8px] font-black text-slate-400 dark:text-slate-600 uppercase tracking-tighter">STAFF ({record.approved_employees || 'N/A'})</div>
                        </div>
                     </div>
                     <div className="flex items-center gap-1 md:gap-2">
                       <button onClick={() => startEditPers(record)} className="p-1.5 md:p-2.5 text-slate-400 hover:text-amber-600 hover:bg-amber-400/10 rounded-lg"><Edit3 size={16} /></button>
                       <button onClick={async () => { if(confirm("Delete census?")) { setLoadingActionId(record.id); await onDeletePersonnel(record.id); setLoadingActionId(null); } }} className="p-1.5 md:p-2.5 text-slate-400 hover:text-red-600 hover:bg-red-400/10 rounded-lg">{loadingActionId === record.id ? <Loader2 className="animate-spin" size={16} /> : <Trash2 size={16} />}</button>
                     </div>
                   </div>
                </div>
              ))
            )}
            {pagedData.length === 0 && <div className="text-center py-24 md:py-40 text-slate-400 dark:text-slate-600 flex flex-col items-center gap-4"><AlertCircle size={32} className="opacity-10 md:w-16 md:h-16" /><p className="font-black uppercase tracking-widest text-xs md:text-sm">Empty State</p></div>}
          </div>

          {totalPages > 1 && (
            <div className="mt-auto pt-6 md:pt-10 flex items-center justify-between border-t border-slate-100 dark:border-slate-700/50">
               <button onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage===1} className="flex items-center gap-1 md:gap-2 px-3 md:px-6 py-2 md:py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 rounded-lg md:rounded-xl text-slate-500 font-black uppercase text-[8px] md:text-xs tracking-widest disabled:opacity-20 transition-all"><ChevronLeft size={14} /> Prev</button>
               <div className="flex gap-1 md:gap-2">
                 <div className="text-[10px] md:text-sm font-black text-slate-400 px-2">Page {currentPage} of {totalPages}</div>
               </div>
               <button onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage===totalPages} className="flex items-center gap-1 md:gap-2 px-3 md:px-6 py-2 md:py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 rounded-lg md:rounded-xl text-slate-500 font-black uppercase text-[8px] md:text-xs tracking-widest disabled:opacity-20 transition-all">Next <ChevronRight size={14} /></button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { ProductionRecord, PersonnelRecord } from '../types.ts';
import { ORGANOGRAM } from '../constants.ts';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts.tsx';
import ProductionTable from './ProductionTable.tsx';
import { getAIInsights } from '../services/geminiService.ts';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList, History, Zap, Users, Briefcase, Droplets, FlaskConical, Target, AlertTriangle, CheckCircle2 } from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  selectedDate: string;
  latestDateInSystem: string;
  isDarkMode: boolean;
}

const Dashboard: React.FC<Props> = ({ productionData, personnelData, selectedDate, latestDateInSystem, isDarkMode }) => {
  const [insights, setInsights] = useState<string>('Analyzing operational metrics...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  const dayRecords = useMemo(() => productionData.filter(d => d.date === selectedDate), [productionData, selectedDate]);

  const latestPersonnel = useMemo(() => {
    if (!personnelData.length) return null;
    return [...personnelData].sort((a, b) => b.date.localeCompare(a.date))[0];
  }, [personnelData]);

  const stats = useMemo(() => {
    const officers = latestPersonnel?.officers || 0;
    const employees = latestPersonnel?.employees || 0;
    const total = officers + employees;

    // Use values from DB if available, otherwise fall back to global constants
    const targetOfficers = latestPersonnel?.approved_officers || ORGANOGRAM.OFFICERS;
    const targetEmployees = latestPersonnel?.approved_employees || ORGANOGRAM.EMPLOYEES;
    const targetTotal = targetOfficers + targetEmployees;

    return {
      officers,
      employees,
      total,
      targetOfficers,
      targetEmployees,
      targetTotal,
      offDiff: officers - targetOfficers,
      empDiff: employees - targetEmployees,
      totalDiff: total - targetTotal,
      offPercent: (officers / targetOfficers) * 100,
      empPercent: (employees / targetEmployees) * 100
    };
  }, [latestPersonnel]);

  const totalProduction = useMemo(() => dayRecords.reduce((acc, curr) => acc + curr.amount, 0), [dayRecords]);
  const totalCondensate = useMemo(() => dayRecords.reduce((acc, curr) => acc + (curr.condensate || 0), 0), [dayRecords]);
  const totalWater = useMemo(() => dayRecords.reduce((acc, curr) => acc + (curr.water || 0), 0), [dayRecords]);

  const isLatest = selectedDate === latestDateInSystem;

  const historicalMetrics = useMemo(() => {
    const dailyTotalsMap: Record<string, number> = {};
    productionData.forEach(record => {
      dailyTotalsMap[record.date] = (dailyTotalsMap[record.date] || 0) + record.amount;
    });

    const sortedDates = Object.keys(dailyTotalsMap).sort();
    const latestIdx = sortedDates.indexOf(latestDateInSystem);

    if (latestIdx === -1) return { avg7: 0, avg30: 0 };

    const last7Dates = sortedDates.slice(Math.max(0, latestIdx - 6), latestIdx + 1);
    const last30Dates = sortedDates.slice(Math.max(0, latestIdx - 29), latestIdx + 1);

    const sum7 = last7Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);
    const sum30 = last30Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);

    return {
      avg7: last7Dates.length ? Math.round(sum7 / last7Dates.length) : 0,
      avg30: last30Dates.length ? Math.round(sum30 / last30Dates.length) : 0,
    };
  }, [productionData, latestDateInSystem]);

  useEffect(() => {
    const fetchInsights = async () => {
      if (dayRecords.length === 0) {
        setInsights("No data available for AI analysis on this date.");
        setLoadingInsights(false);
        return;
      }
      setLoadingInsights(true);
      try {
        const text = await getAIInsights(productionData, selectedDate);
        setInsights(text);
      } catch (e) {
        setInsights("AI Insights currently unavailable.");
      } finally {
        setLoadingInsights(false);
      }
    };
    fetchInsights();
  }, [selectedDate, productionData]);

  const renderWorkforceRow = (label: string, icon: React.ReactNode, actual: number, target: number, diff: number, color: string) => {
    const isShortage = diff < 0;
    const isSurplus = diff > 0;

    return (
      <div className="flex flex-col gap-1 p-2 md:p-3 bg-slate-50/50 dark:bg-slate-900/30 rounded-xl border border-slate-100 dark:border-slate-800">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className={`p-1.5 rounded-lg ${color}`}>{icon}</div>
            <span className="text-slate-600 dark:text-slate-400 font-bold text-[10px] md:text-xs uppercase tracking-tight">{label}</span>
          </div>
          <div className="flex items-center gap-1.5">
             <span className="text-lg md:text-xl font-black text-slate-900 dark:text-white">{actual.toLocaleString()}</span>
             <span className="text-[10px] font-bold text-slate-400">/ {target}</span>
          </div>
        </div>
        <div className="flex items-center justify-between text-[9px] md:text-[10px] font-black uppercase tracking-widest mt-1">
          <div className="text-slate-400">Organogram Status</div>
          <div className={`flex items-center gap-1 ${isShortage ? 'text-rose-500' : isSurplus ? 'text-emerald-500' : 'text-slate-400'}`}>
            {isShortage ? <AlertTriangle size={10} /> : <CheckCircle2 size={10} />}
            {isShortage ? 'Shortage' : isSurplus ? 'Surplus' : 'Optimal'} ({isShortage ? '' : '+'}{diff})
          </div>
        </div>
        <div className="w-full h-1 bg-slate-200 dark:bg-slate-800 rounded-full mt-1 overflow-hidden">
          <div 
            className={`h-full transition-all duration-1000 ${isShortage ? 'bg-amber-500' : 'bg-emerald-500'}`} 
            style={{ width: `${Math.min(100, (actual/target)*100)}%` }}
          />
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-4 md:space-y-6 pb-12">
      <div className={`flex items-center gap-3 md:gap-4 px-4 md:px-6 py-2 md:py-3 rounded-2xl md:rounded-3xl border shadow-sm transition-all ${!isLatest ? 'bg-amber-500/5 border-amber-500/20 text-amber-600 dark:text-amber-500' : 'bg-emerald-500/5 border-emerald-500/20 text-emerald-600 dark:text-emerald-500'}`}>
        {!isLatest ? (
          <>
            <History size={16} className="md:w-5 md:h-5" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-[8px] md:text-xs">Historical Archive View</span>
              <span className="text-[7px] md:text-[9px] opacity-70 font-bold uppercase">{selectedDate} Records</span>
            </div>
          </>
        ) : (
          <>
            <Zap size={16} className="md:w-5 md:h-5 animate-pulse" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-[8px] md:text-xs">Live Operational Status</span>
              <span className="text-[7px] md:text-[9px] opacity-70 font-bold uppercase">Streaming Latest Logs</span>
            </div>
            <span className="ml-auto flex h-1.5 w-1.5 md:h-2 md:w-2 rounded-full bg-emerald-500 animate-ping"></span>
          </>
        )}
      </div>

      {/* Row 1: Primary Metrics */}
      <div className="grid grid-cols-1 xl:grid-cols-4 4k:grid-cols-4 gap-4 md:gap-6">
        {/* Aggregate Daily Production (Gas) */}
        <div className="bg-white dark:bg-slate-800/80 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-center xl:col-span-2 4k:col-span-2 relative overflow-hidden group">
          <div className="flex items-center gap-3 md:gap-4 mb-2">
            <div className="p-1.5 md:p-2 bg-blue-500/10 dark:bg-blue-500/20 rounded-xl text-blue-600 dark:text-blue-400"><Activity size={20} /></div>
            <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-xs">Aggregate Daily Gas Production</span>
          </div>

          <div className="flex flex-col 4k:flex-row 4k:items-end gap-4 4k:gap-10 mb-4 4k:mb-6">
            <div>
              <div className="text-4xl md:text-6xl 4k:text-7xl font-black text-slate-900 dark:text-white tracking-tighter leading-tight">{totalProduction.toLocaleString()}</div>
              <div className="text-[10px] md:text-xs 4k:text-sm text-slate-400 dark:text-slate-500 font-bold uppercase mt-0">Million Cubic Feet (MCF)</div>
            </div>

            <div className="grid grid-cols-2 md:flex md:flex-col gap-4 md:gap-2 pb-2 border-l-0 4k:border-l border-slate-200 dark:border-slate-700 pl-0 4k:pl-8">
              <div className="flex flex-col">
                <span className="text-[7px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">7D Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-base md:text-lg 4k:text-xl font-black text-blue-600 dark:text-blue-400 font-mono">{historicalMetrics.avg7.toLocaleString()}</span>
                </div>
              </div>
              <div className="flex flex-col">
                <span className="text-[7px] md:text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">30D Mean</span>
                <div className="flex items-center gap-2">
                  <span className="text-base md:text-lg 4k:text-xl font-black text-slate-700 dark:text-slate-300 font-mono">{historicalMetrics.avg30.toLocaleString()}</span>
                </div>
              </div>
            </div>
          </div>

          <div className={`mt-auto pt-3 md:pt-4 border-t border-slate-100 dark:border-slate-700/50 text-[10px] md:text-xs flex items-center justify-between font-bold`}>
            <div className={`flex items-center gap-1.5 ${totalProduction >= historicalMetrics.avg7 ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-600 dark:text-amber-400'}`}>
               <TrendingUp size={14} className={`${totalProduction < historicalMetrics.avg7 ? 'rotate-180' : ''} md:w-5 md:h-5`} /> 
               {totalProduction >= historicalMetrics.avg7 ? 'ABOVE 7D AVG' : 'BELOW 7D NORM'}
            </div>
          </div>
        </div>

        {/* Liquid Metrics (Condensate & Water) */}
        <div className="grid grid-rows-2 gap-4 md:gap-6 xl:col-span-1 4k:col-span-1">
          <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl flex flex-col justify-center relative overflow-hidden group">
            <div className="flex items-center gap-2 mb-2">
              <FlaskConical size={16} className="text-blue-500" />
              <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-xs">Condensate</span>
            </div>
            <div className="text-3xl md:text-4xl font-black text-slate-900 dark:text-white tracking-tighter">{totalCondensate.toLocaleString()} <span className="text-[10px] font-bold text-slate-400 uppercase">BBL</span></div>
          </div>
          <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl flex flex-col justify-center relative overflow-hidden group">
            <div className="flex items-center gap-2 mb-2">
              <Droplets size={16} className="text-amber-500" />
              <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-xs">Produced Water</span>
            </div>
            <div className="text-3xl md:text-4xl font-black text-slate-900 dark:text-white tracking-tighter">{totalWater.toLocaleString()} <span className="text-[10px] font-bold text-slate-400 uppercase">BBL</span></div>
          </div>
        </div>

        {/* Workforce Card - Benchmarked against Dynamic Organogram from DB */}
        <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm flex flex-col justify-between relative overflow-hidden xl:col-span-1 4k:col-span-1">
          <div>
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2">
                <Users size={16} className="text-slate-400 md:w-5 md:h-5" />
                <h3 className="text-[10px] md:text-xs font-black text-slate-900 dark:text-white uppercase tracking-widest">Workforce Analysis</h3>
              </div>
              <span className="text-[8px] bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">BGFCL Target</span>
            </div>

            <div className="space-y-3 md:space-y-4">
              {renderWorkforceRow('Officers', <Briefcase size={14} />, stats.officers, stats.targetOfficers, stats.offDiff, 'bg-amber-500/10 text-amber-600 dark:text-amber-400')}
              {renderWorkforceRow('Staff', <Users size={14} />, stats.employees, stats.targetEmployees, stats.empDiff, 'bg-blue-500/10 text-blue-600 dark:text-blue-400')}

              <div className="mt-4 pt-4 border-t border-slate-100 dark:border-slate-700/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 md:p-2 bg-emerald-500/10 rounded-lg text-emerald-600 dark:text-emerald-400"><Target size={14} /></div>
                  <span className="text-slate-800 dark:text-slate-200 font-black text-[10px] md:text-xs uppercase tracking-tighter">Total Strength</span>
                </div>
                <div className="flex flex-col items-end">
                  <div className="text-xl md:text-2xl font-black text-emerald-600 dark:text-emerald-400 tracking-tighter">{stats.total.toLocaleString()}</div>
                  <div className={`text-[8px] font-black uppercase ${stats.totalDiff < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                    Net {stats.totalDiff < 0 ? 'Shortage' : 'Surplus'}: {stats.totalDiff < 0 ? '' : '+'}{stats.totalDiff}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Row 2: Breakdown (Larger) */}
      <div className="grid grid-cols-1 xl:grid-cols-4 4k:grid-cols-6 gap-4 md:gap-6">
        <div className="bg-white dark:bg-slate-900/60 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl backdrop-blur-sm xl:col-span-3 4k:col-span-4">
          <div className="flex items-center gap-3 mb-4">
            <LayoutList size={18} className="text-emerald-500" />
            <h3 className="text-[10px] md:text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest">Field-wise Operational Summary</h3>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-3 4k:grid-cols-6 gap-2 md:gap-4">
            {dayRecords.map((record) => (
              <div key={record.field} className="p-4 bg-slate-50 dark:bg-slate-800/40 rounded-xl border border-slate-100 dark:border-slate-800 hover:border-emerald-500/30 transition-all flex flex-col">
                <div className="text-slate-400 dark:text-slate-500 font-black text-[12px] md:text-[14px] uppercase tracking-widest mb-2 truncate">{record.field}</div>
                <div className="space-y-1">
                  <div className="text-emerald-600 dark:text-emerald-400 font-black text-lg md:text-xl font-mono">{record.amount.toLocaleString()} <span className="text-[8px] text-slate-400 uppercase font-sans">MCF</span></div>
                  <div className="flex justify-between items-center text-[10px] md:text-[11px] font-bold">
                    <span className="text-blue-500 uppercase tracking-tighter">Cond:</span>
                    <span className="text-slate-700 dark:text-slate-300 font-mono">{record.condensate?.toLocaleString() || 0} BBL</span>
                  </div>
                  <div className="flex justify-between items-center text-[10px] md:text-[11px] font-bold">
                    <span className="text-amber-500 uppercase tracking-tighter">Water:</span>
                    <span className="text-slate-700 dark:text-slate-300 font-mono">{record.water?.toLocaleString() || 0} BBL</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
          {dayRecords.length === 0 && <div className="text-slate-400 dark:text-slate-500 text-center py-10 font-bold uppercase tracking-widest border border-dashed border-slate-200 dark:border-slate-800 rounded-2xl">No data found</div>}
        </div>

        <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl xl:col-span-1 4k:col-span-2">
          <FieldDistributionChart data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
      </div>

      {/* Row 3: Trend | Benchmarking | Activity */}
      <div className="grid grid-cols-1 xl:grid-cols-8 gap-4 md:gap-6">
        <div className="bg-white dark:bg-slate-800/50 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg xl:col-span-3">
           <HistoricalTrendChart data={productionData} centerDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
        <div className="bg-white dark:bg-slate-800/50 p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-lg xl:col-span-3">
           <FieldComparisonBar data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
        <div className="bg-white dark:bg-slate-800/80 p-5 md:p-6 rounded-2xl md:rounded-3xl border border-slate-200 dark:border-slate-700 shadow-xl xl:col-span-2">
           <div className="flex items-center gap-2 mb-4">
              <Sparkles size={16} className="text-purple-500" />
