  RefreshCw, Wifi, Moon, Sun, ShieldCheck, Lock, X, Key, ShieldAlert
} from 'lucide-react';

const CompanyLogo = () => (
  <img 
    src="logo.png" 
    alt="BGFCL Official Logo" 
    className="h-10 md:h-12 tv:h-14 w-auto block object-contain"
    style={{ display: 'block' }}
  />
);

const App: React.FC = () => {
  const [productionData, setProductionData] = useState<ProductionRecord[]>([]);
  const [personnelData, setPersonnelData] = useState<PersonnelRecord[]>([]);
  const [view, setView] = useState<ViewType>('dashboard');
  const [isAdminAllowed, setIsAdminAllowed] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [passcode, setPasscode] = useState('');
  const [authError, setAuthError] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'online' | 'offline' | 'mock'>('mock');
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);
  const [isDark, setIsDark] = useState(document.documentElement.classList.contains('dark'));

  const isInitialLoad = useRef(true);
  const prevLatestDate = useRef<string | null>(null);

  const toggleTheme = () => {
    if (isDark) {
      document.documentElement.classList.remove('dark');
      localStorage.theme = 'light';
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.theme = 'dark';
      setIsDark(true);
    }
  };

  const availableDates = useMemo(() => {
    const dates = new Set<string>();
    productionData.forEach(r => dates.add(r.date));
    return Array.from(dates).sort();
  }, [productionData]);

  const latestDateInSystem = useMemo(() => 
    availableDates.length > 0 ? availableDates[availableDates.length - 1] : new Date().toISOString().split('T')[0],
    [availableDates]
  );

  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const fetchData = async () => {
    if (!dbService.isConfigured()) {
      const savedProd = localStorage.getItem('gaspro_production_data');
      const savedPers = localStorage.getItem('gaspro_personnel_data');
      setProductionData(savedProd ? JSON.parse(savedProd) : INITIAL_MOCK_DATA);
      setPersonnelData(savedPers ? JSON.parse(savedPers) : INITIAL_PERSONNEL_DATA);
      setDbStatus('mock');
      return;
    }
    try {
      const [records, personnel] = await Promise.all([
        dbService.getRecords(),
        dbService.getPersonnelRecords()
      ]);
      setProductionData(records);
      setPersonnelData(personnel);
      setDbStatus('online');
      setLastUpdated(new Date());
    } catch (err) {
      console.error("Fetch error:", err);
      setDbStatus('offline');
    }
  };

  useEffect(() => {
    if (dbStatus !== 'online') return;

    const channel = dbService.subscribeToChanges((payload) => {
      setIsSyncing(true);
      const { type, eventType, new: newRecord, old: oldRecord } = payload;

      if (type === 'production') {
        setProductionData(prev => {
          if (eventType === 'INSERT') return [newRecord, ...prev];
          if (eventType === 'UPDATE') return prev.map(r => r.id === newRecord.id ? newRecord : r);
          if (eventType === 'DELETE') return prev.filter(r => r.id !== oldRecord.id);
          return prev;
        });
      } else if (type === 'personnel') {
        setPersonnelData(prev => {
          if (eventType === 'INSERT') return [newRecord, ...prev];
          if (eventType === 'UPDATE') return prev.map(r => r.id === newRecord.id ? newRecord : r);
          if (eventType === 'DELETE') return prev.filter(r => r.id !== oldRecord.id);
          return prev;
        });
      }

      setLastUpdated(new Date());
      setTimeout(() => setIsSyncing(false), 1500);
    });

    return () => {
      if (channel) channel.unsubscribe();
    };
  }, [dbStatus]);

  useEffect(() => {
    const initialize = async () => {
      setIsLoading(true);
      await fetchData();

      // Session storage check
      const savedAuth = sessionStorage.getItem('bgfcl_admin_authorized');
      if (savedAuth === 'true') {
        setIsAdminAllowed(true);
      } else {
        try {
          const response = await fetch('https://api.ipify.org?format=json');
          const result = await response.json();
          const autoAuth = ALLOWED_ADMIN_IPS.includes(result.ip) || window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';
          setIsAdminAllowed(autoAuth);
        } catch {
          setIsAdminAllowed(window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');
        }
      }
      setIsLoading(false);
    };
    initialize();
  }, []);

  useEffect(() => {
    if (!isLoading && availableDates.length > 0) {
      const systemLatest = latestDateInSystem;
      const isNewerDateAvailable = prevLatestDate.current && systemLatest > prevLatestDate.current;
      const isCurrentlySelectedValid = availableDates.includes(selectedDate);

      if (isInitialLoad.current || !isCurrentlySelectedValid || isNewerDateAvailable) {
        setSelectedDate(systemLatest);
        isInitialLoad.current = false;
      }

      prevLatestDate.current = systemLatest;
    }
  }, [availableDates, latestDateInSystem, isLoading, selectedDate]);

  const handleManualAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (passcode === MANAGEMENT_PASSCODE) {
      setIsAdminAllowed(true);
      sessionStorage.setItem('bgfcl_admin_authorized', 'true');
      setShowAuthModal(false);
      setView('admin');
      setAuthError(false);
    } else {
      setAuthError(true);
      setPasscode('');
    }
  };

  const handleAddProduction = async (record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') await dbService.addRecord(record);
    else setProductionData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
  };

  const handleUpdateProduction = async (id: string, record: Omit<ProductionRecord, 'id'>) => {
    if (dbStatus === 'online') await dbService.updateRecord(id, record);
    else setProductionData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
  };

  const handleDeleteProduction = async (id: string) => {
    if (dbStatus === 'online') await dbService.deleteRecord(id);
    else setProductionData(prev => prev.filter(r => r.id !== id));
  };

  const handleAddPersonnel = async (record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') await dbService.addPersonnelRecord(record);
    else setPersonnelData(prev => [{ ...record, id: Math.random().toString(36).substr(2, 9) }, ...prev]);
  };

  const handleUpdatePersonnel = async (id: string, record: Omit<PersonnelRecord, 'id'>) => {
    if (dbStatus === 'online') await dbService.updatePersonnelRecord(id, record);
    else setPersonnelData(prev => prev.map(r => r.id === id ? { ...record, id } : r));
  };

  const handleDeletePersonnel = async (id: string) => {
    if (dbStatus === 'online') await dbService.deletePersonnelRecord(id);
    else setPersonnelData(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-[#020617] text-slate-900 dark:text-slate-100 transition-colors duration-500">
      <header className="sticky top-0 z-50 bg-white/70 dark:bg-slate-900/70 border-b border-slate-200 dark:border-slate-800/80 backdrop-blur-2xl px-8 py-4 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-6">
          <div className="bg-[#004b49] px-2 py-1 rounded-xl shadow-2xl border border-white/10">
            <CompanyLogo />
          </div>
          <div className="hidden tv:block h-8 w-px bg-slate-200 dark:bg-slate-800"></div>
          <div>
            <h1 className="text-xl font-black tracking-[0.1em] uppercase leading-none text-slate-900 dark:text-white">BGFCL <span className="text-emerald-500">Command</span></h1>
            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-[0.2em] mt-1.5 flex items-center gap-2">
              <RefreshCw size={10} className={`${isSyncing ? 'animate-spin' : 'animate-spin-slow'}`} /> Active Sync: {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </p>
          </div>
        </div>

        <nav className="flex items-center bg-slate-100/50 dark:bg-slate-950/50 p-1.5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-inner">
          <button onClick={() => setView('dashboard')} className={`px-6 py-2.5 rounded-xl flex items-center gap-3 font-black text-xs uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-white dark:bg-slate-800 text-slate-900 dark:text-white shadow-xl' : 'text-slate-500 hover:text-slate-900 dark:hover:text-slate-200'}`}>
            <LayoutDashboard size={18} /> Dashboard
          </button>

          {view === 'dashboard' && (
            <div className="mx-2 flex items-center gap-2 bg-white/80 dark:bg-slate-900/80 px-2 py-1.5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
              <button 
                onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx > 0) setSelectedDate(availableDates[idx - 1]); }} 
                disabled={availableDates.indexOf(selectedDate) <= 0} 
                className="p-1 text-slate-400 hover:text-emerald-500 disabled:opacity-20 transition-colors"
              >
                <ChevronLeft size={22} />
              </button>

              <div className="flex items-center px-4 text-slate-900 dark:text-white font-black text-xs border-x border-slate-100 dark:border-slate-800">
                <input 
                  type="date" 
                  value={selectedDate} 
                  onChange={(e) => setSelectedDate(e.target.value)} 
                  className="bg-transparent border-none focus:ring-0 outline-none p-0 w-32 cursor-pointer uppercase" 
                />
              </div>

              <button 
                onClick={() => { const idx = availableDates.indexOf(selectedDate); if (idx < availableDates.length - 1) setSelectedDate(availableDates[idx + 1]); }} 
                disabled={availableDates.indexOf(selectedDate) >= availableDates.length - 1} 
                className="p-1 text-slate-400 hover:text-emerald-500 disabled:opacity-20 transition-colors"
              >
                <ChevronRight size={22} />
              </button>
            </div>
          )}

          <button 
            onClick={() => isAdminAllowed ? setView('admin') : setShowAuthModal(true)} 
            className={`px-6 py-2.5 rounded-xl flex items-center gap-3 font-black text-xs uppercase tracking-widest transition-all ${view === 'admin' ? 'bg-white dark:bg-slate-800 text-slate-900 dark:text-white shadow-xl' : 'text-slate-500 hover:text-slate-900 dark:hover:text-slate-200'}`}
          >
            {isAdminAllowed ? <ShieldCheck className="text-emerald-500" size={18} /> : <Lock size={18} />} 
            {isAdminAllowed ? "Administrator" : "Admin Access"}
          </button>
        </nav>

        <div className="flex items-center gap-4">
           <div className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border ${dbStatus === 'online' ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20' : 'bg-amber-500/10 text-amber-600 border-amber-500/20'}`}>
             <div className={`w-2 h-2 rounded-full ${dbStatus === 'online' ? 'bg-emerald-500 animate-pulse' : 'bg-amber-500'}`}></div>
             {dbStatus === 'online' ? 'Global Cloud' : 'Local Node'}
           </div>

           <button onClick={toggleTheme} className="p-3 bg-slate-100 dark:bg-slate-800 hover:bg-emerald-500/10 rounded-2xl text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700/50 transition-all">
            {isDark ? <Sun size={20} /> : <Moon size={20} />}
           </button>

           <div className="hidden tv:flex items-center gap-2 p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700/50 text-slate-500">
             <Monitor size={20} />
             <span className="text-[10px] font-black uppercase tracking-tighter">43" Optimize</span>
           </div>
        </div>
      </header>

      {/* Auth Modal for Restricted Admin Access */}
      {showAuthModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl border border-slate-200 dark:border-slate-800 shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-8 text-center">
              <div className="mx-auto w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-6">
                <Key className="text-emerald-500" size={32} />
              </div>
              <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight mb-2">Restricted Access</h2>
              <p className="text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-widest mb-8">Management Passcode Required</p>

              <form onSubmit={handleManualAuth} className="space-y-4">
                <div className="relative">
                  <input 
                    type="password" 
                    value={passcode}
                    onChange={(e) => setPasscode(e.target.value)}
                    placeholder="ENTER PASSCODE"
                    className={`w-full bg-slate-50 dark:bg-slate-950 border ${authError ? 'border-rose-500 ring-4 ring-rose-500/10' : 'border-slate-200 dark:border-slate-800'} rounded-2xl p-5 text-center font-mono text-xl tracking-[0.5em] focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 outline-none transition-all placeholder:tracking-normal placeholder:font-sans placeholder:text-xs placeholder:text-slate-300`}
                    autoFocus
                  />
                  {authError && (
                    <div className="absolute left-0 -bottom-8 w-full text-center text-rose-500 text-[10px] font-black uppercase flex items-center justify-center gap-2 animate-bounce">
                      <ShieldAlert size={14} /> Authorization Denied
                    </div>
                  )}
                </div>

                <div className="pt-8 flex gap-3">
                  <button 
                    type="button" 
                    onClick={() => setShowAuthModal(false)}
                    className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-slate-200 dark:hover:bg-slate-700 transition-all"
                  >
                    Cancel
                  </button>
                  <button 
                    type="submit"
                    className="flex-2 flex-[2] py-4 bg-emerald-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-emerald-500 shadow-lg shadow-emerald-500/20 transition-all"
                  >
                    Authorize Access
                  </button>
                </div>
              </form>
            </div>
            <div className="bg-slate-50 dark:bg-slate-950 px-8 py-4 text-center border-t border-slate-100 dark:border-slate-800">
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Global Terminal Security Protocol 4.2.1</span>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 px-8 py-8 w-full">
        {isLoading ? (
          <div className="h-[70vh] flex flex-col items-center justify-center space-y-6 text-slate-400 dark:text-slate-600">
            <div className="relative">
              <div className="w-20 h-20 border-4 border-slate-200 dark:border-slate-800 rounded-full"></div>
              <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin absolute top-0 left-0"></div>
            </div>
            <p className="font-black uppercase tracking-[0.5em] text-sm animate-pulse">Initializing Command Center Data Stream...</p>
          </div>
        ) : view === 'dashboard' ? (
          <Dashboard productionData={productionData} personnelData={personnelData} selectedDate={selectedDate} latestDateInSystem={latestDateInSystem} isDarkMode={isDark} />
        ) : (
          <AdminPanel 
            productionData={productionData} 
            personnelData={personnelData}
            onAddProduction={handleAddProduction} 
            onUpdateProduction={handleUpdateProduction}
            onDeleteProduction={handleDeleteProduction}
            onAddPersonnel={handleAddPersonnel}
            onUpdatePersonnel={handleUpdatePersonnel}
            onDeletePersonnel={handleDeletePersonnel}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { ProductionRecord, PersonnelRecord } from '../types.ts';
import { ORGANOGRAM } from '../constants.ts';
import { FieldDistributionChart, HistoricalTrendChart, FieldComparisonBar } from './Charts.tsx';
import ProductionTable from './ProductionTable.tsx';
import { getAIInsights } from '../services/geminiService.ts';
import { Sparkles, TrendingUp, Activity, Clock, LayoutList, History, Zap, Users, Briefcase, Droplets, FlaskConical, Target, AlertTriangle, CheckCircle2 } from 'lucide-react';

interface Props {
  productionData: ProductionRecord[];
  personnelData: PersonnelRecord[];
  selectedDate: string;
  latestDateInSystem: string;
  isDarkMode: boolean;
}

const Dashboard: React.FC<Props> = ({ productionData, personnelData, selectedDate, latestDateInSystem, isDarkMode }) => {
  const [insights, setInsights] = useState<string>('Analyzing operational metrics...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  const dayRecords = useMemo(() => productionData.filter(d => d.date === selectedDate), [productionData, selectedDate]);

  const latestPersonnel = useMemo(() => {
    if (!personnelData.length) return null;
    return [...personnelData].sort((a, b) => b.date.localeCompare(a.date))[0];
  }, [personnelData]);

  const stats = useMemo(() => {
    const officers = latestPersonnel?.officers || 0;
    const employees = latestPersonnel?.employees || 0;
    const total = officers + employees;

    // Fallback to constants if DB values are missing
    const targetOfficers = latestPersonnel?.approved_officers || ORGANOGRAM.OFFICERS;
    const targetEmployees = latestPersonnel?.approved_employees || ORGANOGRAM.EMPLOYEES;
    const targetTotal = targetOfficers + targetEmployees;

    return {
      officers,
      employees,
      total,
      targetOfficers,
      targetEmployees,
      targetTotal,
      offDiff: officers - targetOfficers,
      empDiff: employees - targetEmployees,
      totalDiff: total - targetTotal,
    };
  }, [latestPersonnel]);

  const totalProduction = useMemo(() => dayRecords.reduce((acc, curr) => acc + curr.amount, 0), [dayRecords]);
  const totalCondensate = useMemo(() => dayRecords.reduce((acc, curr) => acc + (curr.condensate || 0), 0), [dayRecords]);
  const totalWater = useMemo(() => dayRecords.reduce((acc, curr) => acc + (curr.water || 0), 0), [dayRecords]);

  const isLatest = selectedDate === latestDateInSystem;

  const historicalMetrics = useMemo(() => {
    const dailyTotalsMap: Record<string, number> = {};
    productionData.forEach(record => {
      dailyTotalsMap[record.date] = (dailyTotalsMap[record.date] || 0) + record.amount;
    });

    const sortedDates = Object.keys(dailyTotalsMap).sort();
    const latestIdx = sortedDates.indexOf(latestDateInSystem);

    if (latestIdx === -1) return { avg7: 0, avg30: 0 };

    const last7Dates = sortedDates.slice(Math.max(0, latestIdx - 6), latestIdx + 1);
    const last30Dates = sortedDates.slice(Math.max(0, latestIdx - 29), latestIdx + 1);

    const sum7 = last7Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);
    const sum30 = last30Dates.reduce((acc, date) => acc + dailyTotalsMap[date], 0);

    return {
      avg7: last7Dates.length ? Math.round(sum7 / last7Dates.length) : 0,
      avg30: last30Dates.length ? Math.round(sum30 / last30Dates.length) : 0,
    };
  }, [productionData, latestDateInSystem]);

  useEffect(() => {
    const fetchInsights = async () => {
      if (dayRecords.length === 0) {
        setInsights("No data available for AI analysis on this date.");
        setLoadingInsights(false);
        return;
      }
      setLoadingInsights(true);
      try {
        const text = await getAIInsights(productionData, selectedDate);
        setInsights(text);
      } catch (e) {
        setInsights("AI Insights currently unavailable.");
      } finally {
        setLoadingInsights(false);
      }
    };
    fetchInsights();
  }, [selectedDate, productionData]);

  const renderWorkforceRow = (label: string, icon: React.ReactNode, actual: number, target: number, diff: number, color: string) => {
    const isShortage = diff < 0;
    const isSurplus = diff > 0;
    const absDiff = Math.abs(diff);

    return (
      <div className="flex flex-col gap-1.5 p-3 bg-slate-50/50 dark:bg-slate-900/40 rounded-xl border border-slate-200/50 dark:border-slate-800/50 backdrop-blur-md transition-all hover:bg-slate-100/50 dark:hover:bg-slate-800/60">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className={`p-1.5 rounded-lg ${color}`}>{icon}</div>
            <span className="text-slate-600 dark:text-slate-400 font-bold text-xs uppercase tracking-tight">{label}</span>
          </div>
          <div className="flex items-center gap-1.5">
             <span className="text-xl font-black text-slate-900 dark:text-white">{actual.toLocaleString()}</span>
             <span className="text-[10px] font-bold text-slate-400">/ {target}</span>
          </div>
        </div>
        <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest mt-1">
          <div className="text-slate-400">Organogram</div>
          <div className={`flex items-center gap-1 px-1.5 py-0.5 rounded ${isShortage ? 'text-rose-500 bg-rose-500/5' : isSurplus ? 'text-emerald-500 bg-emerald-500/5' : 'text-slate-400'}`}>
            {isShortage ? <AlertTriangle size={10} /> : <CheckCircle2 size={10} />}
            {isShortage ? 'Shortage' : isSurplus ? 'Surplus' : 'Optimal'} ({isShortage ? '-' : '+'}{absDiff})
          </div>
        </div>
        <div className="w-full h-1 bg-slate-200 dark:bg-slate-800 rounded-full mt-1 overflow-hidden">
          <div 
            className={`h-full transition-all duration-1000 ${isShortage ? 'bg-amber-500' : 'bg-emerald-500'}`} 
            style={{ width: `${Math.min(100, (actual/target)*100)}%` }}
          />
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 md:space-y-8 pb-16 max-w-[2500px] mx-auto">
      {/* View Status Bar */}
      <div className={`flex items-center gap-4 px-6 py-3 rounded-2xl border shadow-sm transition-all ${!isLatest ? 'bg-amber-500/5 border-amber-500/20 text-amber-600 dark:text-amber-500' : 'bg-emerald-500/5 border-emerald-500/20 text-emerald-600 dark:text-emerald-500'}`}>
        {!isLatest ? (
          <>
            <History size={18} />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-xs">Historical Archive Data Mode</span>
              <span className="text-[10px] opacity-70 font-bold uppercase">{selectedDate} Records Active</span>
            </div>
          </>
        ) : (
          <>
            <Zap size={18} className="animate-pulse" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-xs">Command Center • Live Operations Monitoring</span>
              <span className="text-[10px] opacity-70 font-bold uppercase">Streaming Real-time Telemetry</span>
            </div>
            <span className="ml-auto flex h-2 w-2 rounded-full bg-emerald-500 animate-ping"></span>
          </>
        )}
      </div>

      {/* Main Grid: Desktop PC Style Desktop-Scale Row */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">

        {/* Main Production Metric - Massive Focus (Col 1-5) */}
        <div className="xl:col-span-5 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-2xl flex flex-col justify-center relative overflow-hidden">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-emerald-500/10 dark:bg-emerald-500/20 rounded-2xl text-emerald-600 dark:text-emerald-400">
              <Activity size={24} />
            </div>
            <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-[0.2em] text-sm">Aggregate Daily Gas Production</span>
          </div>

          <div className="flex items-end gap-8 mb-8">
            <div>
              <div className="text-7xl font-black text-slate-900 dark:text-white tracking-tighter leading-none">{totalProduction.toLocaleString()}</div>
              <div className="text-sm text-slate-400 dark:text-slate-500 font-bold uppercase mt-3 tracking-widest">Million Cubic Feet (MCF)</div>
            </div>
            <div className="flex flex-col pb-2 border-l border-slate-100 dark:border-slate-800 pl-8 space-y-4">
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-600 uppercase tracking-widest">7D Performance Mean</span>
                <span className="text-3xl font-black text-blue-600 dark:text-blue-400 font-mono">{historicalMetrics.avg7.toLocaleString()}</span>
              </div>
              <div className={`flex items-center gap-1.5 text-xs font-black ${totalProduction >= historicalMetrics.avg7 ? 'text-emerald-500' : 'text-rose-500'}`}>
                <TrendingUp size={16} className={totalProduction < historicalMetrics.avg7 ? 'rotate-180' : ''} /> 
                {Math.abs(((totalProduction / historicalMetrics.avg7) * 100) - 100).toFixed(1)}% {totalProduction >= historicalMetrics.avg7 ? 'ABOVE' : 'BELOW'} NORM
              </div>
            </div>
          </div>

          <div className="mt-auto grid grid-cols-2 gap-4 pt-6 border-t border-slate-100 dark:border-slate-800">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase">System Status</span>
              <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-tighter">Operational • Optimal Yield</span>
            </div>
            <div className="flex flex-col items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase text-right">30-Day Peak Output</span>
              <span className="text-xs font-bold text-slate-600 dark:text-slate-400 uppercase text-right font-mono">{historicalMetrics.avg30.toLocaleString()} MCF</span>
            </div>
          </div>
        </div>

        {/* Liquid Metrics and Distribution - High Density (Col 6-9) */}
        <div className="xl:col-span-4 flex flex-col gap-6">
          <div className="grid grid-cols-2 gap-6">
            <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl flex flex-col justify-center">
              <div className="flex items-center gap-3 mb-3">
                <FlaskConical size={20} className="text-blue-500" />
                <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-widest text-[10px]">Condensate Yield</span>
              </div>
              <div className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter font-mono">{totalCondensate.toLocaleString()}</div>
              <div className="text-[10px] font-bold text-slate-400 uppercase mt-1 tracking-tighter">Barrels (BBL) • Recovery Rate</div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl flex flex-col justify-center">
              <div className="flex items-center gap-3 mb-3">
                <Droplets size={20} className="text-amber-500" />
                <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-widest text-[10px]">Produced Water</span>
              </div>
              <div className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter font-mono">{totalWater.toLocaleString()}</div>
              <div className="text-[10px] font-bold text-slate-400 uppercase mt-1 tracking-tighter">Barrels (BBL) • Disposal Metric</div>
            </div>
          </div>

          <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl h-full flex items-center justify-center">
             <FieldDistributionChart data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} />
          </div>
        </div>

        {/* Workforce Side Panel - Benchmarked against Organogram (Col 10-12) */}
        <div className="xl:col-span-3 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-2xl backdrop-blur-md flex flex-col">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-2">
              <Users size={20} className="text-slate-400" />
              <h3 className="text-xs font-black text-slate-900 dark:text-white uppercase tracking-[0.2em]">Workforce Audit</h3>
            </div>
            <span className="text-[10px] bg-slate-100 dark:bg-slate-800 text-slate-500 px-3 py-1 rounded-full font-black uppercase tracking-tighter">BGFCL Org</span>
          </div>

          <div className="space-y-4">
            {renderWorkforceRow('Officers', <Briefcase size={16} />, stats.officers, stats.targetOfficers, stats.offDiff, 'bg-amber-500/10 text-amber-600 dark:text-amber-400')}
            {renderWorkforceRow('Staff Employees', <Users size={16} />, stats.employees, stats.targetEmployees, stats.empDiff, 'bg-blue-500/10 text-blue-600 dark:text-blue-400')}

            <div className="mt-6 pt-6 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="p-3 bg-emerald-500/10 rounded-2xl text-emerald-600 dark:text-emerald-400"><Target size={20} /></div>
                <div className="flex flex-col">
                  <span className="text-slate-800 dark:text-slate-200 font-black text-xs uppercase tracking-tight">Total Personnel</span>
                  <span className="text-[10px] font-bold text-slate-400 uppercase">Across All Fields</span>
                </div>
              </div>
              <div className="text-right">
                <div className="text-3xl font-black text-emerald-600 dark:text-emerald-400 tracking-tighter font-mono">{stats.total.toLocaleString()}</div>
                <div className={`text-[10px] font-black uppercase ${stats.totalDiff < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                  Net {stats.totalDiff < 0 ? 'Shortage' : 'Surplus'}: {stats.totalDiff < 0 ? '' : '+'}{stats.totalDiff}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Row 2: Secondary Visuals Grid */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">

        {/* Field Summaries Grid - Desktop Style Grid (Col 1-8) */}
        <div className="xl:col-span-8 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-3">
              <LayoutList size={22} className="text-emerald-500" />
              <h3 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-[0.2em]">Field-Level Operational Log</h3>
            </div>
            <span className="px-4 py-1.5 bg-slate-100 dark:bg-slate-800 rounded-xl text-[10px] font-black text-slate-400 uppercase tracking-widest">Date: {selectedDate}</span>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
            {dayRecords.length > 0 ? dayRecords.map((record) => (
              <div key={record.field} className="p-5 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-200/50 dark:border-slate-700/50 hover:border-emerald-500/40 transition-all group">
                <div className="text-slate-400 dark:text-slate-500 font-black text-xs uppercase tracking-widest mb-3 truncate group-hover:text-emerald-500 transition-colors">{record.field}</div>
                <div className="space-y-2">
                  <div className="text-emerald-600 dark:text-emerald-400 font-black text-3xl font-mono leading-none">{record.amount.toLocaleString()} <span className="text-xs text-slate-400 uppercase font-sans">MCF</span></div>
                  <div className="flex justify-between items-center text-[11px] font-bold border-t border-slate-200/50 dark:border-slate-700/50 pt-3 mt-3">
                    <span className="text-blue-500/80 uppercase tracking-tighter">Condensate</span>
                    <span className="text-slate-700 dark:text-slate-300 font-mono">{record.condensate?.toLocaleString() || 0} BBL</span>
                  </div>
                  <div className="flex justify-between items-center text-[11px] font-bold">
                    <span className="text-amber-500/80 uppercase tracking-tighter">Prod. Water</span>
                    <span className="text-slate-700 dark:text-slate-300 font-mono">{record.water?.toLocaleString() || 0} BBL</span>
                  </div>
                </div>
              </div>
            )) : (
               <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl text-slate-300 dark:text-slate-600 font-black uppercase tracking-[0.4em]">Historical Log Unavailable</div>
            )}
          </div>
        </div>

        {/* Executive AI Insights Panel (Col 9-12) */}
        <div className="xl:col-span-4 bg-slate-950 text-white p-8 rounded-3xl border border-slate-800 shadow-2xl relative overflow-hidden flex flex-col min-h-[400px]">
          <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/10 blur-[120px] -mr-40 -mt-40"></div>
          <div className="flex items-center gap-4 mb-8 relative z-10">
            <Sparkles size={24} className="text-emerald-400" />
            <h3 className="text-sm font-black uppercase tracking-[0.25em] text-emerald-400">MD's Strategic Insight</h3>
          </div>
          <div className={`flex-1 text-base text-slate-200 leading-relaxed font-medium relative z-10 transition-opacity duration-700 ${loadingInsights ? 'opacity-30 animate-pulse' : 'opacity-100'}`}>
            {insights}
          </div>
          <div className="mt-10 pt-6 border-t border-white/10 flex items-center justify-between text-[10px] font-black text-slate-500 uppercase tracking-widest relative z-10">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
              Engine: Gemini 3 Flash v2
            </div>
            <span>BGFCL Command OS</span>
          </div>
        </div>
      </div>

      {/* Row 3: Trending & Comparison */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">
        <div className="xl:col-span-6 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl">
           <HistoricalTrendChart data={productionData} centerDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
        <div className="xl:col-span-6 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl">
           <FieldComparisonBar data={productionData} targetDate={selectedDate} isDarkMode={isDarkMode} />
        </div>
      </div>

      {/* Activity Table */}
      <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-sm font-black text-slate-900 dark:text-white flex items-center gap-3 uppercase tracking-[0.2em]">
              <Clock size={20} className="text-slate-400" /> Complete Field Log History
            </h3>
            <button className="px-5 py-2.5 bg-slate-100 dark:bg-slate-800 rounded-xl text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] hover:bg-emerald-600 hover:text-white transition-all shadow-sm">
              Export Audit Stream
            </button>
          </div>
          <div className="flex-1 overflow-y-auto max-h-[800px]">
            <ProductionTable data={productionData} />
          </div>
      </div>
    </div>
  );
};

export default Dashboard;

