            </div>
          </>
        ) : (
          <>
            <Zap size={18} className="animate-pulse" />
            <div className="flex flex-col">
              <span className="font-black uppercase tracking-widest text-xs">Command Center • Live Operations Monitoring</span>
              <span className="text-[10px] opacity-70 font-bold uppercase">Streaming Real-time Telemetry ({formatDisplayDate(selectedDate)})</span>
            </div>
            <span className="ml-auto flex h-2 w-2 rounded-full bg-emerald-500 animate-ping"></span>
          </>
        )}
      </div>

      {/* Main Grid: Desktop PC Style Desktop-Scale Row */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">

        {/* Main Production Metric - Massive Focus (Col 1-5) */}
        <div className="xl:col-span-5 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-2xl flex flex-col justify-center relative overflow-hidden">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-emerald-500/10 dark:bg-emerald-500/20 rounded-2xl text-emerald-600 dark:text-emerald-400">
              <Activity size={24} />
            </div>
            <span className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-[0.2em] text-sm">Aggregate Daily Gas Production</span>
          </div>

          <div className="flex items-end gap-8 mb-8">
            <div>
              <div className="text-7xl font-black text-slate-900 dark:text-white tracking-tighter leading-none">{totalProduction.toLocaleString()}</div>
              <div className="text-sm text-slate-400 dark:text-slate-500 font-bold uppercase mt-3 tracking-widest">Million Cubic Feet (MCF)</div>
            </div>
            <div className="flex flex-col pb-2 border-l border-slate-100 dark:border-slate-800 pl-8 space-y-4">
