                <span className="text-3xl font-black text-blue-600 dark:text-blue-400 font-mono">{historicalMetrics.avg7.toLocaleString()}</span>
              </div>
              <div className={`flex items-center gap-1.5 text-xs font-black ${totalProduction >= historicalMetrics.avg7 ? 'text-emerald-500' : 'text-rose-500'}`}>
                <TrendingUp size={16} className={totalProduction < historicalMetrics.avg7 ? 'rotate-180' : ''} /> 
                {Math.abs(((totalProduction / historicalMetrics.avg7) * 100) - 100).toFixed(1)}% {totalProduction >= historicalMetrics.avg7 ? 'ABOVE' : 'BELOW'} NORM
              </div>
            </div>
          </div>

          <div className="mt-auto grid grid-cols-2 gap-4 pt-6 border-t border-slate-100 dark:border-slate-800">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase">System Status</span>
