        {/* Workforce Side Panel - Benchmarked against Organogram (Col 10-12) */}
        <div className="xl:col-span-3 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-2xl backdrop-blur-md flex flex-col">
