                        <div className="text-[8px] md:text-xs font-bold text-slate-400 dark:text-slate-500 uppercase flex items-center gap-1"><Calendar size={10} /> {formatDisplayDate(record.date)}</div>
                        <div className="flex gap-2 mt-1">
